typedef struct {
    uint16_t kind;
    uint8_t barrier_before;
    uint8_t quant_dispatch;
    uint8_t op;
    uint8_t format;
    uint8_t input_dtype;
    uint8_t output_dtype;
    uint32_t source;
    uint32_t region;
    uint32_t scope_index;
    size_t resource_start;
    size_t resource_count;
} termite_metal_runtime_command_op;

typedef struct {
    const uint16_t *ops;
    size_t op_count;
    const uint8_t *barriers;
    size_t barrier_count;
    const uint8_t *quant_dispatches;
    size_t quant_dispatch_count;
    const termite_metal_runtime_command_op *command_ops;
    size_t command_op_count;
    size_t start_index;
} termite_metal_planned_layer_contract;

