static uint64_t termite_metal_clock_monotonic_nanos(void) {
    struct timespec ts;
    if (clock_gettime(CLOCK_MONOTONIC, &ts) != 0) return 0;
    return ((uint64_t)ts.tv_sec * 1000000000ull) + (uint64_t)ts.tv_nsec;
}

static bool termite_metal_debug_q80_block_finite(size_t layer_index) {
    const char *enabled = getenv("TERMITE_METAL_DEBUG_QUANT_BLOCK_FINITE");
    if (enabled == NULL) enabled = getenv("TERMITE_METAL_DEBUG_Q80_BLOCK_FINITE");
    if (enabled == NULL || enabled[0] == '\0' || strcmp(enabled, "0") == 0) return false;
    const char *layer_env = getenv("TERMITE_METAL_DEBUG_QUANT_BLOCK_LAYER");
    if (layer_env == NULL) layer_env = getenv("TERMITE_METAL_DEBUG_Q80_BLOCK_LAYER");
    if (layer_env == NULL || layer_env[0] == '\0') return true;
    char *end = NULL;
    unsigned long long target = strtoull(layer_env, &end, 10);
    if (end == layer_env) return true;
    return (size_t)target == layer_index;
}

static bool termite_metal_trace_q80_block(void) {
    const char *enabled = getenv("TERMITE_METAL_TRACE_QUANT_BLOCK");
    if (enabled == NULL) enabled = getenv("TERMITE_METAL_TRACE_Q80_BLOCK");
    return enabled != NULL && enabled[0] != '\0' && strcmp(enabled, "0") != 0;
}

static bool termite_metal_debug_direct_block_finite(size_t layer_index) {
    const char *enabled = getenv("TERMITE_METAL_DEBUG_DIRECT_BLOCK_FINITE");
    if (enabled == NULL || enabled[0] == '\0' || strcmp(enabled, "0") == 0) return false;
    const char *layer_env = getenv("TERMITE_METAL_DEBUG_DIRECT_BLOCK_LAYER");
    if (layer_env == NULL || layer_env[0] == '\0') return true;
    char *end = NULL;
    unsigned long long target = strtoull(layer_env, &end, 10);
    if (end == layer_env) return true;
    return (size_t)target == layer_index;
}

static void termite_metal_debug_dump_buffer_finite(
    termite_metal_decode_runtime *runtime,
    const char *label,
    size_t layer_index,
    id<MTLBuffer> buffer,
    size_t offset,
    size_t elems
) {
    if (runtime == NULL || buffer == nil || elems == 0) return;
    const size_t bytes = elems * sizeof(float);
    if (offset + bytes > buffer.length) {
        fprintf(stderr, "metal-quant-block-finite label=%s layer=%zu elems=%zu out_of_bounds=1 offset=%zu length=%zu\n", label, layer_index, elems, offset, (size_t)buffer.length);
        return;
    }

    const float *values = NULL;
    id<MTLBuffer> staging = nil;
    if (buffer.storageMode == MTLStorageModeShared) {
        values = (const float *)((const uint8_t *)buffer.contents + offset);
    } else {
        staging = [runtime->device newBufferWithLength:bytes options:MTLResourceStorageModeShared];
        if (staging == nil) {
            fprintf(stderr, "metal-quant-block-finite label=%s layer=%zu elems=%zu staging_failed=1\n", label, layer_index, elems);
            return;
        }
        id<MTLCommandBuffer> cb = termite_metal_new_command_buffer(runtime->queue, "termite_metal_debug_dump_buffer_finite");
        if (cb == nil) {
            fprintf(stderr, "metal-quant-block-finite label=%s layer=%zu elems=%zu command_failed=1\n", label, layer_index, elems);
            return;
        }
        termite_metal_record_active_frame_blit_source(cb, TERMITE_METAL_BLIT_SOURCE_OTHER);
        id<MTLBlitCommandEncoder> blit = termite_metal_tracked_blit_command_encoder(cb);
        if (blit == nil) {
            fprintf(stderr, "metal-quant-block-finite label=%s layer=%zu elems=%zu blit_failed=1\n", label, layer_index, elems);
            return;
        }
        [blit copyFromBuffer:buffer sourceOffset:offset toBuffer:staging destinationOffset:0 size:bytes];
        [blit endEncoding];
        if (termite_metal_commit_and_wait(cb, "termite_metal_debug_dump_buffer_finite", -1) != 0) {
            fprintf(stderr, "metal-quant-block-finite label=%s layer=%zu elems=%zu download_failed=1\n", label, layer_index, elems);
            return;
        }
        values = (const float *)staging.contents;
    }

    size_t nonfinite = 0;
    size_t nan_count = 0;
    size_t inf_count = 0;
    size_t first_bad = SIZE_MAX;
    float first_bad_value = 0.0f;
    float min_value = 0.0f;
    float max_value = 0.0f;
    float max_abs = 0.0f;
    bool have_finite = false;
    for (size_t i = 0; i < elems; ++i) {
        const float v = values[i];
        if (!isfinite(v)) {
            if (first_bad == SIZE_MAX) {
                first_bad = i;
                first_bad_value = v;
            }
            nonfinite += 1;
            if (isnan(v)) nan_count += 1;
            else inf_count += 1;
            continue;
        }
        if (!have_finite) {
            min_value = v;
            max_value = v;
            have_finite = true;
        } else {
            if (v < min_value) min_value = v;
            if (v > max_value) max_value = v;
        }
        const float av = fabsf(v);
        if (av > max_abs) max_abs = av;
    }
    fprintf(
        stderr,
        "metal-quant-block-finite label=%s layer=%zu elems=%zu nonfinite=%zu nan=%zu inf=%zu first_bad=%lld first_bad_value=%e min=%e max=%e max_abs=%e\n",
        label,
        layer_index,
        elems,
        nonfinite,
        nan_count,
        inf_count,
        first_bad == SIZE_MAX ? -1ll : (long long)first_bad,
        first_bad_value,
        have_finite ? min_value : 0.0f,
        have_finite ? max_value : 0.0f,
        max_abs
    );
}

int termite_metal_device_available(void) {
    @autoreleasepool {
        return termite_metal_shared_device() != nil ? 1 : 0;
    }
}

