           "kernel void termite_apply_linear_argmax_1x(device const float *input [[buffer(0)]], device const float *weight [[buffer(1)]], device const float *bias [[buffer(2)]], device uint *output [[buffer(3)]], constant termite_metal_apply_linear_params &p [[buffer(4)]], uint gid [[thread_position_in_grid]]) {\n"
           "    if (gid != 0) return;\n"
           "    float best = -INFINITY;\n"
           "    uint best_idx = 0u;\n"
           "    for (uint o = 0; o < p.out_dim; ++o) {\n"
           "        float acc = bias[o];\n"
           "        uint row_base = o * p.in_dim;\n"
           "        for (uint i = 0; i < p.in_dim; ++i) acc += input[i] * weight[row_base + i];\n"
           "        if (acc > best) { best = acc; best_idx = o; }\n"
           "    }\n"
           "    output[0] = best_idx;\n"
           "}\n"
           "kernel void termite_argmax_logits_1x(device const float *logits [[buffer(0)]], device uint *output [[buffer(1)]], constant uint &out_dim [[buffer(2)]], uint gid [[thread_position_in_grid]]) {\n"
           "    if (gid != 0) return;\n"
           "    if (out_dim == 0u) { output[0] = 0u; return; }\n"
           "    float best = logits[0];\n"
           "    uint best_idx = 0u;\n"
           "    for (uint i = 1u; i < out_dim; ++i) {\n"
           "        float value = logits[i];\n"
           "        if (value > best) { best = value; best_idx = i; }\n"
           "    }\n"
           "    output[0] = best_idx;\n"
           "}\n"
           "kernel void termite_argmax_logits_partials(device const float *logits [[buffer(0)]], device float *partial_values [[buffer(1)]], device uint *partial_ids [[buffer(2)]], constant uint &out_dim [[buffer(3)]], threadgroup float *sh_vals [[threadgroup(0)]], threadgroup uint *sh_ids [[threadgroup(1)]], ushort tid [[thread_index_in_threadgroup]], ushort tg_size [[threads_per_threadgroup]], uint block [[threadgroup_position_in_grid]]) {\n"
           "    const uint block_size = 1024u;\n"
           "    uint start = block * block_size;\n"
           "    uint end = min(start + block_size, out_dim);\n"
           "    float best = -INFINITY;\n"
           "    uint best_idx = 0u;\n"
           "    for (uint i = start + uint(tid); i < end; i += uint(tg_size)) {\n"
           "        float value = logits[i];\n"
           "        if (value > best || (value == best && i < best_idx)) { best = value; best_idx = i; }\n"
           "    }\n"
           "    sh_vals[tid] = best;\n"
           "    sh_ids[tid] = best_idx;\n"
           "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
           "    for (uint stride = uint(tg_size) >> 1u; stride > 0u; stride >>= 1u) {\n"
           "        if (uint(tid) < stride) {\n"
           "            float other = sh_vals[uint(tid) + stride];\n"
           "            uint other_idx = sh_ids[uint(tid) + stride];\n"
           "            if (other > sh_vals[tid] || (other == sh_vals[tid] && other_idx < sh_ids[tid])) { sh_vals[tid] = other; sh_ids[tid] = other_idx; }\n"
           "        }\n"
           "        threadgroup_barrier(mem_flags::mem_threadgroup);\n"
           "    }\n"
           "    if (tid == 0u) { partial_values[block] = sh_vals[0]; partial_ids[block] = sh_ids[0]; }\n"
           "}\n"
           "kernel void termite_argmax_logits_reduce(device const float *partial_values [[buffer(0)]], device const uint *partial_ids [[buffer(1)]], device uint *output [[buffer(2)]], constant uint &partial_count [[buffer(3)]], uint gid [[thread_position_in_grid]]) {\n"
           "    if (gid != 0u) return;\n"
           "    if (partial_count == 0u) { output[0] = 0u; return; }\n"
           "    float best = partial_values[0];\n"
           "    uint best_idx = partial_ids[0];\n"
           "    for (uint i = 1u; i < partial_count; ++i) {\n"
           "        float value = partial_values[i];\n"
           "        uint idx = partial_ids[i];\n"
           "        if (value > best || (value == best && idx < best_idx)) { best = value; best_idx = idx; }\n"
           "    }\n"
           "    output[0] = best_idx;\n"
           "}\n"
           "inline float termite_apply_sampling_penalties(float logit, uint token_id, const device termite_metal_penalty_entry *entries, uint entry_count, constant termite_metal_sample_logits_params &p) {\n"
           "    if (entry_count == 0u) return logit;\n"
           "    for (uint i = 0u; i < entry_count; ++i) {\n"
           "        if (entries[i].token_id != token_id) continue;\n"
           "        float adjusted = logit;\n"
           "        if (p.repetition_penalty != 1.0f) {\n"
           "            adjusted = adjusted > 0.0f ? (adjusted / p.repetition_penalty) : (adjusted * p.repetition_penalty);\n"
           "        }\n"
           "        if (p.frequency_penalty != 0.0f) adjusted -= p.frequency_penalty * float(entries[i].count);\n"
           "        if (p.presence_penalty != 0.0f) adjusted -= p.presence_penalty;\n"
           "        return adjusted;\n"
           "    }\n"
           "    return logit;\n"
           "}\n"
           "kernel void termite_sample_logits_1x(device const float *logits [[buffer(0)]], device float *probs [[buffer(1)]], device uint *output [[buffer(2)]], constant termite_metal_sample_logits_params &p [[buffer(3)]], device const termite_metal_penalty_entry *penalties [[buffer(4)]], uint gid [[thread_position_in_grid]]) {\n"
           "    if (gid != 0) return;\n"
           "    if (p.out_dim == 0u) { output[0] = 0u; return; }\n"
           "    const uint max_top_k = 256u;\n"
           "    thread float top_vals[256];\n"
