static id<MTLBuffer> termite_metal_make_private_buffer_with_bytes(
    id<MTLDevice> device,
    id<MTLCommandQueue> queue,
    const void *bytes,
    size_t length
) {
    if (device == nil || queue == nil || bytes == NULL || length == 0) return nil;
    @autoreleasepool {
        id<MTLBuffer> staging = [device newBufferWithBytes:bytes length:length options:MTLResourceStorageModeShared];
        if (staging == nil) return nil;
        id<MTLBuffer> dst = [device newBufferWithLength:length options:MTLResourceStorageModePrivate];
        if (dst == nil) return nil;
        id<MTLCommandBuffer> command_buffer = termite_metal_new_command_buffer(queue, __func__);
        if (command_buffer == nil) return nil;
        termite_metal_record_active_frame_blit_source(command_buffer, TERMITE_METAL_BLIT_SOURCE_OTHER);
        id<MTLBlitCommandEncoder> blit = termite_metal_tracked_blit_command_encoder(command_buffer);
        if (blit == nil) return nil;
        if ([blit respondsToSelector:@selector(setLabel:)]) {
            blit.label = @"private-buffer-upload";
        }
        [blit copyFromBuffer:staging sourceOffset:0 toBuffer:dst destinationOffset:0 size:length];
        [blit endEncoding];
        return termite_metal_commit_and_wait(command_buffer, __func__, -1) == 0 ? dst : nil;
    }
}

static bool termite_metal_can_make_no_copy_buffer(const void *bytes, size_t length) {
    if (bytes == NULL || length == 0) return false;
    long page_size = sysconf(_SC_PAGESIZE);
    if (page_size <= 0) page_size = 4096;
    const uintptr_t ptr = (uintptr_t)bytes;
    const uintptr_t page = (uintptr_t)page_size;
    return (ptr % page) == 0 && (length % (size_t)page_size) == 0;
}

typedef struct termite_metal_host_staging_slice {
    id<MTLBuffer> buffer;
    size_t offset;
} termite_metal_host_staging_slice;

static size_t termite_metal_align_forward_size(size_t value, size_t alignment) {
    if (alignment <= 1) return value;
    const size_t mask = alignment - 1;
    if ((alignment & mask) != 0) return value;
    if (value > SIZE_MAX - mask) return SIZE_MAX;
    return (value + mask) & ~mask;
}

static int termite_metal_decode_runtime_ensure_host_staging_buffer(
    termite_metal_decode_runtime *runtime,
    bool frame_owned,
    size_t required
) {
    if (runtime == NULL || runtime->device == nil || required == 0) return -1;
    id<MTLBuffer> current_buffer = frame_owned ? runtime->host_staging_buffer : runtime->active_frame_host_staging_buffer;
    size_t current_capacity = frame_owned ? runtime->host_staging_capacity : runtime->active_frame_host_staging_capacity;
    if (current_buffer != nil && current_capacity >= required) return 0;

    size_t new_capacity = current_capacity;
    if (new_capacity < 4096) new_capacity = 4096;
    while (new_capacity < required) {
        if (new_capacity > SIZE_MAX / 2) {
            new_capacity = required;
            break;
        }
        new_capacity *= 2;
    }

    id<MTLBuffer> new_buffer = [runtime->device newBufferWithLength:new_capacity options:MTLResourceStorageModeShared];
    if (new_buffer == nil) return -2;
    if (frame_owned) {
        runtime->host_staging_buffer = new_buffer;
        runtime->host_staging_capacity = new_capacity;
    } else {
        runtime->active_frame_host_staging_buffer = new_buffer;
        runtime->active_frame_host_staging_capacity = new_capacity;
    }
    return 0;
}

static int termite_metal_decode_runtime_stage_host_bytes(
    termite_metal_decode_runtime *runtime,
    const void *bytes,
    size_t length,
    bool frame_owned,
    termite_metal_host_staging_slice *slice
) {
    if (runtime == NULL || bytes == NULL || length == 0 || slice == NULL) return -1;
    const size_t alignment = 256;
    size_t offset = 0;
    if (!frame_owned) {
        offset = termite_metal_align_forward_size(runtime->active_frame_host_staging_offset, alignment);
        if (offset == SIZE_MAX || length > SIZE_MAX - offset) return -2;
    }
    const size_t required = offset + length;
    if (termite_metal_decode_runtime_ensure_host_staging_buffer(runtime, frame_owned, required) != 0) return -3;

    id<MTLBuffer> buffer = frame_owned ? runtime->host_staging_buffer : runtime->active_frame_host_staging_buffer;
    if (buffer == nil || buffer.contents == NULL || offset + length > buffer.length) return -4;
    memcpy((uint8_t *)buffer.contents + offset, bytes, length);
    if (buffer.storageMode == MTLStorageModeManaged) {
        [buffer didModifyRange:NSMakeRange(offset, length)];
    }

    if (!frame_owned) {
        runtime->active_frame_host_staging_offset = termite_metal_align_forward_size(required, alignment);
        if (runtime->active_frame_host_staging_offset == SIZE_MAX) return -5;
        if (runtime->active_frame_host_staging_retained_buffer != buffer) {
            if (termite_metal_decode_runtime_retain_frame_resource(runtime, buffer) != 0) return -6;
            runtime->active_frame_host_staging_retained_buffer = buffer;
        }
    }

    slice->buffer = buffer;
    slice->offset = offset;
    return 0;
}

static int termite_metal_upload_private_buffer(
    id<MTLDevice> device,
    id<MTLCommandQueue> queue,
    id<MTLBuffer> dst,
    const void *bytes,
    size_t length
) {
    if (device == nil || queue == nil || dst == nil || bytes == NULL || length == 0) return -1;
    @autoreleasepool {
        if (dst.length < length) return -2;
        id<MTLBuffer> staging = [device newBufferWithBytes:bytes length:length options:MTLResourceStorageModeShared];
        if (staging == nil) return -3;
        id<MTLCommandBuffer> command_buffer = termite_metal_new_command_buffer(queue, __func__);
        if (command_buffer == nil) return -4;
        termite_metal_record_active_frame_blit_source(command_buffer, TERMITE_METAL_BLIT_SOURCE_OTHER);
        id<MTLBlitCommandEncoder> blit = termite_metal_tracked_blit_command_encoder(command_buffer);
        if (blit == nil) return -5;
        if ([blit respondsToSelector:@selector(setLabel:)]) {
            blit.label = @"private-buffer-upload";
        }
        [blit copyFromBuffer:staging sourceOffset:0 toBuffer:dst destinationOffset:0 size:length];
        [blit endEncoding];
        return termite_metal_commit_and_wait(command_buffer, __func__, -6);
    }
}

static void termite_metal_decode_runtime_memory_add_buffer(
    termite_metal_decode_runtime_memory_stats *snapshot,
    id<MTLBuffer> buffer,
    uint64_t *category
) {
    if (snapshot == NULL || buffer == nil) return;
    const uint64_t bytes = (uint64_t)buffer.length;
    snapshot->buffer_count += 1;
    snapshot->total_bytes += bytes;
    if (category != NULL) {
        *category += bytes;
    }
}

static void termite_metal_decode_runtime_memory_add_resources(
    termite_metal_decode_runtime_memory_stats *snapshot,
    CFMutableArrayRef resources,
    uint64_t *category
) {
    if (snapshot == NULL || resources == NULL) return;
    const CFIndex count = CFArrayGetCount(resources);
    for (CFIndex i = 0; i < count; ++i) {
        id resource = (__bridge id)CFArrayGetValueAtIndex(resources, i);
        if ([resource conformsToProtocol:@protocol(MTLBuffer)]) {
            termite_metal_decode_runtime_memory_add_buffer(snapshot, (id<MTLBuffer>)resource, category);
        }
    }
}

static termite_metal_decode_runtime *termite_metal_active_encoder_runtime = NULL;

static bool termite_metal_trace_unscoped_compute_enabled(void) {
    const char *enabled = getenv("TERMITE_METAL_TRACE_UNSCOPED_COMPUTE");
    return enabled != NULL && enabled[0] != '\0' && strcmp(enabled, "0") != 0;
}

static bool termite_metal_trace_frame_blits_enabled(void) {
    const char *enabled = getenv("TERMITE_METAL_TRACE_FRAME_BLITS");
    return enabled != NULL && enabled[0] != '\0' && strcmp(enabled, "0") != 0;
}

static bool termite_metal_trace_frame_lifecycle_enabled(void) {
    const char *enabled = getenv("TERMITE_METAL_TRACE_FRAME_LIFECYCLE");
    return enabled != NULL && enabled[0] != '\0' && strcmp(enabled, "0") != 0;
}

static bool termite_metal_coalesce_planned_compute_encoders_enabled(void) {
    const char *disabled = getenv("TERMITE_METAL_DISABLE_PLANNED_ENCODER_COALESCING");
    return disabled == NULL || disabled[0] == '\0' || strcmp(disabled, "0") == 0;
}

static bool termite_metal_planned_compute_barriers_enabled(void) {
    const char *disabled = getenv("TERMITE_METAL_DISABLE_PLANNED_COMPUTE_BARRIERS");
    if (disabled != NULL && disabled[0] != '\0' && strcmp(disabled, "0") != 0) return false;
    return true;
}

static void termite_metal_decode_runtime_reset_planned_compute_ranges(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return;
    runtime->active_planned_compute_range_count = 0;
}

static bool termite_metal_size_mul(size_t a, size_t b, size_t *out) {
    if (out == NULL) return false;
    if (a != 0 && b > SIZE_MAX / a) return false;
    *out = a * b;
    return true;
}

static bool termite_metal_size_mul3(size_t a, size_t b, size_t c, size_t *out) {
    size_t ab = 0;
    return termite_metal_size_mul(a, b, &ab) && termite_metal_size_mul(ab, c, out);
}

static bool termite_metal_buffer_range_valid(id<MTLBuffer> buffer, size_t offset, size_t byte_count) {
    if (buffer == nil) return false;
    return offset <= buffer.length && byte_count <= buffer.length - offset;
}

static int termite_metal_planned_range_make(
    id<MTLBuffer> buffer,
    size_t offset,
    size_t byte_count,
    termite_metal_planned_range_type type,
    termite_metal_planned_encoder_range *out,
    int failure_code
) {
    if (out == NULL) return failure_code;
    out->buffer = nil;
    out->begin = 0;
    out->end = 0;
    out->type = type;
    if (buffer == nil || byte_count == 0) return 0;
    if (offset > buffer.length || byte_count > buffer.length - offset) return failure_code;
    out->buffer = buffer;
    out->begin = offset;
    out->end = offset + byte_count;
    return 0;
}

static bool termite_metal_planned_ranges_overlap(
    const termite_metal_planned_encoder_range *a,
    const termite_metal_planned_encoder_range *b
) {
    if (a == NULL || b == NULL || a->buffer == nil || b->buffer == nil) return false;
    if (a->buffer != b->buffer) return false;
    if (a->type == TERMITE_METAL_PLANNED_RANGE_READ && b->type == TERMITE_METAL_PLANNED_RANGE_READ) return false;
    return a->begin < b->end && b->begin < a->end;
}

static int termite_metal_decode_runtime_prepare_planned_compute_accesses(
    termite_metal_decode_runtime *runtime,
    const termite_metal_planned_encoder_range *accesses,
    size_t access_count,
    int failure_code
) {
    if (runtime == NULL || accesses == NULL || access_count == 0) return 0;
    if (runtime->active_frame_cb == nil || runtime->active_planned_compute_encoder == nil) return 0;

    bool conflict = false;
    for (size_t i = 0; !conflict && i < access_count; ++i) {
        const termite_metal_planned_encoder_range *access = &accesses[i];
        if (access->buffer == nil) continue;
        for (size_t j = 0; j < runtime->active_planned_compute_range_count; ++j) {
            if (termite_metal_planned_ranges_overlap(access, &runtime->active_planned_compute_ranges[j])) {
                conflict = true;
                break;
            }
        }
    }

    if (conflict || runtime->active_planned_compute_range_count + access_count > TERMITE_METAL_PLANNED_RANGE_CAPACITY) {
        id<MTLComputeCommandEncoder> encoder = runtime->active_planned_compute_encoder;
        if (encoder == nil) return failure_code;
        if (termite_metal_planned_compute_barriers_enabled()) {
            [encoder memoryBarrierWithScope:MTLBarrierScopeBuffers];
            runtime->active_frame_planned_barrier_count += 1;
        }
        termite_metal_decode_runtime_reset_planned_compute_ranges(runtime);
    }

    for (size_t i = 0; i < access_count; ++i) {
        const termite_metal_planned_encoder_range access = accesses[i];
        if (access.buffer == nil) continue;
        if (runtime->active_planned_compute_range_count >= TERMITE_METAL_PLANNED_RANGE_CAPACITY) return failure_code;
        runtime->active_planned_compute_ranges[runtime->active_planned_compute_range_count] = access;
        runtime->active_planned_compute_range_count += 1;
    }
    return 0;
}

static int termite_metal_decode_runtime_prepare_planned_compute_unary_accesses(
    termite_metal_decode_runtime *runtime,
    id<MTLBuffer> input_buffer,
    size_t input_offset,
    size_t input_bytes,
    id<MTLBuffer> output_buffer,
    size_t output_offset,
    size_t output_bytes,
    int failure_code
) {
    termite_metal_planned_encoder_range accesses[2];
    if (termite_metal_planned_range_make(input_buffer, input_offset, input_bytes, TERMITE_METAL_PLANNED_RANGE_READ, &accesses[0], failure_code) != 0 ||
        termite_metal_planned_range_make(output_buffer, output_offset, output_bytes, TERMITE_METAL_PLANNED_RANGE_WRITE, &accesses[1], failure_code) != 0 ||
        termite_metal_decode_runtime_prepare_planned_compute_accesses(runtime, accesses, 2, failure_code) != 0)
    {
        return failure_code;
    }
    return 0;
}

static int termite_metal_decode_runtime_prepare_planned_compute_binary_accesses(
    termite_metal_decode_runtime *runtime,
