        termite_metal_planned_range_make(rhs_buffer, rhs_offset, rhs_bytes, TERMITE_METAL_PLANNED_RANGE_READ, &accesses[1], failure_code) != 0 ||
        termite_metal_planned_range_make(output_buffer, output_offset, output_bytes, TERMITE_METAL_PLANNED_RANGE_WRITE, &accesses[2], failure_code) != 0 ||
        termite_metal_decode_runtime_prepare_planned_compute_accesses(runtime, accesses, 3, failure_code) != 0)
