static bool termite_metal_should_coalesce_planned_compute_encoder(termite_metal_decode_runtime *runtime) {
    return runtime != NULL &&
        runtime->active_frame_cb != nil &&
        termite_metal_coalesce_planned_compute_encoders_enabled();
}

static id<MTLComputeCommandEncoder> termite_metal_tracked_compute_command_encoder_at(id<MTLCommandBuffer> command_buffer, const char *func, int line) {
    termite_metal_decode_runtime *runtime = termite_metal_active_encoder_runtime;
    if (runtime != NULL && runtime->active_frame_cb == command_buffer && runtime->active_compute_region == TERMITE_METAL_COMPUTE_REGION_OTHER && termite_metal_trace_unscoped_compute_enabled()) {
        fprintf(stderr, "metal_unscoped_compute: func=%s line=%d\n", func != NULL ? func : "(unknown)", line);
    }
    return termite_metal_tracked_compute_command_encoder_for(command_buffer, TERMITE_METAL_COMPUTE_SOURCE_OTHER);
}

static size_t termite_metal_enter_compute_region(termite_metal_decode_runtime *runtime, size_t region) {
    if (runtime == NULL) return TERMITE_METAL_COMPUTE_REGION_OTHER;
    if (region >= TERMITE_METAL_COMPUTE_REGION_COUNTER_COUNT) region = TERMITE_METAL_COMPUTE_REGION_OTHER;
    const size_t previous = runtime->active_compute_region;
    runtime->active_compute_region = region;
    return previous;
}

static void termite_metal_restore_compute_region(termite_metal_decode_runtime *runtime, size_t previous) {
    if (runtime == NULL) return;
    if (previous >= TERMITE_METAL_COMPUTE_REGION_COUNTER_COUNT) previous = TERMITE_METAL_COMPUTE_REGION_OTHER;
    runtime->active_compute_region = previous;
}

static size_t termite_metal_default_compute_region_for_source(size_t source) {
    switch (source) {
        case TERMITE_METAL_COMPUTE_SOURCE_QUANT_QKV:
        case TERMITE_METAL_COMPUTE_SOURCE_ATTENTION:
        case TERMITE_METAL_COMPUTE_SOURCE_HEAD_ROPE:
            return TERMITE_METAL_COMPUTE_REGION_ATTENTION;
        case TERMITE_METAL_COMPUTE_SOURCE_QUANT_PAIR_ACT:
        case TERMITE_METAL_COMPUTE_SOURCE_FFN:
            return TERMITE_METAL_COMPUTE_REGION_FFN;
        case TERMITE_METAL_COMPUTE_SOURCE_PLE:
            return TERMITE_METAL_COMPUTE_REGION_PLE;
        case TERMITE_METAL_COMPUTE_SOURCE_TAIL:
            return TERMITE_METAL_COMPUTE_REGION_TAIL;
        case TERMITE_METAL_COMPUTE_SOURCE_EMBEDDING:
            return TERMITE_METAL_COMPUTE_REGION_EMBEDDING;
        case TERMITE_METAL_COMPUTE_SOURCE_LAYER:
            return TERMITE_METAL_COMPUTE_REGION_LAYER;
        case TERMITE_METAL_COMPUTE_SOURCE_DENSE_LINEAR:
            return TERMITE_METAL_COMPUTE_REGION_OTHER;
        default:
            return TERMITE_METAL_COMPUTE_REGION_OTHER;
    }
}

