        case TERMITE_METAL_PLAN_OP_ATTENTION_FLASH: return "attention_flash";
        case TERMITE_METAL_PLAN_OP_ATTENTION_PAGED: return "attention_paged";
        case TERMITE_METAL_PLAN_OP_ATTENTION_QUANTIZED_KV: return "attention_quantized_kv";
        default: return "unknown";
    }
}

static const char *termite_metal_operator_name(size_t op) {
    switch (op) {
        case TERMITE_METAL_OPERATOR_FALLBACK: return "fallback";
        case TERMITE_METAL_OPERATOR_MUL_MV: return "mul_mv";
        case TERMITE_METAL_OPERATOR_MUL_MV_EXT: return "mul_mv_ext";
        case TERMITE_METAL_OPERATOR_MUL_MM: return "mul_mm";
        case TERMITE_METAL_OPERATOR_GET_ROWS: return "get_rows";
        case TERMITE_METAL_OPERATOR_SET_ROWS: return "set_rows";
        case TERMITE_METAL_OPERATOR_CPY_Q_TO_F32: return "cpy_q_to_f32";
        case TERMITE_METAL_OPERATOR_CPY_F32_TO_Q: return "cpy_f32_to_q";
        case TERMITE_METAL_OPERATOR_ATTENTION_FLASH: return "attention_flash";
        case TERMITE_METAL_OPERATOR_ATTENTION_PAGED: return "attention_paged";
        case TERMITE_METAL_OPERATOR_ATTENTION_QUANTIZED_KV: return "attention_quantized_kv";
        default: return "unknown";
    }
}

static void termite_metal_decode_runtime_record_planned_command_op(
    termite_metal_decode_runtime *runtime,
    termite_metal_runtime_command_op op
) {
    if (runtime == NULL || runtime->active_frame_cb == nil) return;
    runtime->active_frame_planned_command_op_count += 1;
    const size_t kind = op.kind < TERMITE_METAL_PLAN_OP_COUNTER_COUNT ? op.kind : TERMITE_METAL_PLAN_OP_UNKNOWN;
    runtime->active_frame_planned_command_op_kind_counts[kind] += 1;
    if (op.op < TERMITE_METAL_OPERATOR_COUNTER_COUNT) {
        runtime->active_frame_planned_command_operator_counts[op.op] += 1;
    }
    if (op.quant_dispatch < TERMITE_METAL_QUANT_DISPATCH_COUNTER_COUNT) {
        runtime->active_frame_planned_command_quant_dispatch_counts[op.quant_dispatch] += 1;
    }
}

static void termite_metal_decode_runtime_record_logical_command_op(
    termite_metal_decode_runtime *runtime,
    uint16_t kind,
    uint8_t op,
    uint8_t quant_dispatch
) {
    termite_metal_runtime_command_op command_op = {
        .kind = kind,
        .barrier_before = 0,
        .quant_dispatch = quant_dispatch,
        .op = op,
        .format = TERMITE_METAL_GRAPH_FORMAT_UNKNOWN,
        .input_dtype = 0u,
        .output_dtype = 0u,
        .source = 0,
        .region = 0,
        .scope_index = 0,
        .resource_start = 0,
        .resource_count = 0,
    };
    termite_metal_decode_runtime_record_planned_command_op(runtime, command_op);
}

static bool termite_metal_planned_layer_contract_find_command_op(
    termite_metal_planned_layer_contract contract,
    uint16_t kind,
    termite_metal_runtime_command_op *out_op
) {
    if (contract.command_ops == NULL || out_op == NULL) return false;
    if (contract.start_index >= contract.command_op_count) return false;
    for (size_t index = contract.start_index; index < contract.command_op_count; index += 1) {
        const termite_metal_runtime_command_op op = contract.command_ops[index];
        if (op.kind == kind) {
            *out_op = op;
            return true;
        }
    }
    return false;
}

static void termite_metal_decode_runtime_record_contract_or_logical_command_op(
    termite_metal_decode_runtime *runtime,
    termite_metal_planned_layer_contract contract,
    uint16_t kind,
    uint8_t op,
    uint8_t quant_dispatch
) {
    termite_metal_runtime_command_op command_op;
    if (termite_metal_planned_layer_contract_find_command_op(contract, kind, &command_op)) {
        termite_metal_decode_runtime_record_planned_command_op(runtime, command_op);
        return;
    }
    termite_metal_decode_runtime_record_logical_command_op(runtime, kind, op, quant_dispatch);
}

static void termite_metal_maybe_trace_last_frame(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return;
    const char *enabled = getenv("TERMITE_METAL_TRACE_FRAME");
    if (enabled == NULL || enabled[0] == '\0' || strcmp(enabled, "0") == 0) return;
    const bool trace_all = strcmp(enabled, "all") == 0;
    if (!trace_all && runtime->last_frame_compute_encoder_count < 100 && runtime->last_frame_blit_encoder_count < 100) return;

    fprintf(
        stderr,
        "metal_frame_trace: compute=%llu blit=%llu planned_scopes=%llu planned_barriers=%llu gpu_ms=%.3f\n",
        (unsigned long long)runtime->last_frame_compute_encoder_count,
        (unsigned long long)runtime->last_frame_blit_encoder_count,
        (unsigned long long)runtime->last_frame_planned_compute_scope_count,
        (unsigned long long)runtime->last_frame_planned_barrier_count,
        (double)runtime->last_frame_gpu_nanos / 1000000.0
    );
    for (size_t region = 0; region < TERMITE_METAL_COMPUTE_REGION_COUNTER_COUNT; ++region) {
        const uint64_t region_total = runtime->last_frame_compute_region_counts[region];
        if (region_total == 0) continue;
        fprintf(
            stderr,
            "metal_frame_trace_region: %s total=%llu",
            termite_metal_compute_region_name(region),
            (unsigned long long)region_total
        );
        for (size_t source = 0; source < TERMITE_METAL_COMPUTE_COUNTER_COUNT; ++source) {
            const uint64_t count = runtime->last_frame_compute_region_source_counts[region][source];
            if (count == 0) continue;
            fprintf(
                stderr,
                " %s=%llu",
                termite_metal_compute_source_name(source),
                (unsigned long long)count
            );
        }
        fprintf(stderr, "\n");
    }
    if (runtime->last_frame_planned_command_op_count != 0) {
        fprintf(
            stderr,
            "metal_frame_trace_command_ops: total=%llu",
            (unsigned long long)runtime->last_frame_planned_command_op_count
        );
        for (size_t kind = 0; kind < TERMITE_METAL_PLAN_OP_COUNTER_COUNT; ++kind) {
            const uint64_t count = runtime->last_frame_planned_command_op_kind_counts[kind];
            if (count == 0) continue;
            fprintf(stderr, " %s=%llu", termite_metal_plan_op_name(kind), (unsigned long long)count);
        }
        fprintf(stderr, "\n");
        fprintf(stderr, "metal_frame_trace_command_operators:");
        for (size_t op = 0; op < TERMITE_METAL_OPERATOR_COUNTER_COUNT; ++op) {
            const uint64_t count = runtime->last_frame_planned_command_operator_counts[op];
            if (count == 0) continue;
            fprintf(stderr, " %s=%llu", termite_metal_operator_name(op), (unsigned long long)count);
        }
        fprintf(stderr, "\n");
        fprintf(
            stderr,
            "metal_frame_trace_quant_dispatch: scalar=%llu mmv=%llu small_batch=%llu mm=%llu\n",
            (unsigned long long)runtime->last_frame_planned_command_quant_dispatch_counts[0],
            (unsigned long long)runtime->last_frame_planned_command_quant_dispatch_counts[1],
            (unsigned long long)runtime->last_frame_planned_command_quant_dispatch_counts[2],
            (unsigned long long)runtime->last_frame_planned_command_quant_dispatch_counts[3]
        );
    }
}

static id<MTLComputeCommandEncoder> termite_metal_tracked_compute_command_encoder_for(id<MTLCommandBuffer> command_buffer, size_t source) {
    termite_metal_decode_runtime *runtime = termite_metal_active_encoder_runtime;
    if (runtime != NULL && runtime->active_frame_cb == command_buffer) {
        termite_metal_decode_runtime_close_planned_compute_encoder_for_transition(runtime);
        if (source >= TERMITE_METAL_COMPUTE_COUNTER_COUNT) source = TERMITE_METAL_COMPUTE_SOURCE_OTHER;
        size_t region = runtime->active_compute_region;
        if (region >= TERMITE_METAL_COMPUTE_REGION_COUNTER_COUNT) region = TERMITE_METAL_COMPUTE_REGION_OTHER;
        if (region == TERMITE_METAL_COMPUTE_REGION_OTHER) region = termite_metal_default_compute_region_for_source(source);
        runtime->compute_encoder_count += 1;
        runtime->active_frame_compute_encoder_count += 1;
        runtime->active_frame_compute_source_counts[source] += 1;
        runtime->active_frame_compute_region_counts[region] += 1;
        runtime->active_frame_compute_region_source_counts[region][source] += 1;
    }
    return [command_buffer computeCommandEncoder];
}

static id<MTLComputeCommandEncoder> termite_metal_scoped_compute_encoder_for(
    termite_metal_decode_runtime *runtime,
    id<MTLCommandBuffer> command_buffer,
    size_t source,
    BOOL *owned
) {
    if (owned != NULL) *owned = YES;
    if (runtime != NULL &&
        runtime->active_frame_cb == command_buffer &&
        runtime->active_planned_compute_encoder != nil &&
        termite_metal_coalesce_planned_compute_encoders_enabled())
    {
        if (owned != NULL) *owned = NO;
        return runtime->active_planned_compute_encoder;
    }
    return termite_metal_tracked_compute_command_encoder_for(command_buffer, source);
}

static void termite_metal_end_scoped_compute_encoder(id<MTLComputeCommandEncoder> encoder, BOOL owned) {
    if (owned && encoder != nil) [encoder endEncoding];
}

int termite_metal_decode_runtime_begin_planned_compute_scope(termite_metal_decode_runtime *runtime, size_t source, size_t region) {
    if (runtime == NULL) return -1;
    if (runtime->active_frame_cb == nil) return -2;
    if (source >= TERMITE_METAL_COMPUTE_COUNTER_COUNT) source = TERMITE_METAL_COMPUTE_SOURCE_OTHER;
    if (region >= TERMITE_METAL_COMPUTE_REGION_COUNTER_COUNT) region = TERMITE_METAL_COMPUTE_REGION_OTHER;
    if (region == TERMITE_METAL_COMPUTE_REGION_OTHER) region = termite_metal_default_compute_region_for_source(source);

    if (runtime->active_planned_compute_encoder != nil) {
        if (!termite_metal_should_coalesce_planned_compute_encoder(runtime)) return -3;
        runtime->active_planned_compute_scope_closed_for_encoder_transition = false;
        runtime->active_planned_compute_source = source;
        runtime->active_planned_compute_region = region;
        runtime->active_frame_planned_compute_scope_count += 1;
        runtime->active_frame_compute_source_counts[source] += 1;
        runtime->active_frame_compute_region_counts[region] += 1;
        runtime->active_frame_compute_region_source_counts[region][source] += 1;
        return 0;
    }

    id<MTLComputeCommandEncoder> encoder = [runtime->active_frame_cb computeCommandEncoder];
    if (encoder == nil) return -4;
    runtime->active_planned_compute_encoder = encoder;
    runtime->active_planned_compute_scope_closed_for_encoder_transition = false;
    runtime->active_planned_compute_source = source;
    runtime->active_planned_compute_region = region;
    termite_metal_decode_runtime_reset_planned_compute_ranges(runtime);
    runtime->compute_encoder_count += 1;
    runtime->active_frame_compute_encoder_count += 1;
    runtime->active_frame_planned_compute_scope_count += 1;
    runtime->active_frame_compute_source_counts[source] += 1;
    runtime->active_frame_compute_region_counts[region] += 1;
    runtime->active_frame_compute_region_source_counts[region][source] += 1;
    return 0;
}

int termite_metal_decode_runtime_planned_compute_barrier(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return -1;
    if (runtime->active_frame_cb == nil) return -2;
    id<MTLComputeCommandEncoder> encoder = runtime->active_planned_compute_encoder;
    if (encoder == nil) {
        if (runtime->active_planned_compute_scope_closed_for_encoder_transition) return 0;
        return -3;
    }
    if (termite_metal_planned_compute_barriers_enabled()) {
        [encoder memoryBarrierWithScope:MTLBarrierScopeBuffers];
        runtime->active_frame_planned_barrier_count += 1;
    }
    termite_metal_decode_runtime_reset_planned_compute_ranges(runtime);
    return 0;
}

static termite_metal_planned_layer_cursor termite_metal_planned_layer_cursor_make(
    termite_metal_decode_runtime *runtime,
    termite_metal_planned_layer_contract contract,
    int failure_code
) {
    return (termite_metal_planned_layer_cursor){
        .runtime = runtime,
        .contract = contract,
        .index = contract.start_index,
        .use_ops = contract.ops != NULL && contract.start_index < contract.op_count,
        .use_barriers = contract.barriers != NULL && contract.start_index < contract.barrier_count,
        .use_quant_dispatches = contract.quant_dispatches != NULL && contract.start_index < contract.quant_dispatch_count,
        .use_command_ops = contract.command_ops != NULL && contract.start_index < contract.command_op_count,
        .last_quant_dispatch = TERMITE_METAL_QUANT_MATMUL_DISPATCH_UNKNOWN,
        .last_operator = TERMITE_METAL_OPERATOR_UNKNOWN,
        .last_format = UINT8_MAX,
        .last_input_dtype = TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32,
        .last_output_dtype = TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32,
        .failure_code = failure_code,
    };
}

static int termite_metal_planned_layer_cursor_before_op(
    termite_metal_planned_layer_cursor *cursor,
    uint16_t expected_kind
) {
    if (cursor == NULL) return -1;
    if (cursor->use_command_ops) {
        if (cursor->index >= cursor->contract.command_op_count) return cursor->failure_code;
        const termite_metal_runtime_command_op op = cursor->contract.command_ops[cursor->index];
        cursor->last_quant_dispatch = op.quant_dispatch;
        cursor->last_operator = op.op;
        cursor->last_format = op.format;
        cursor->last_input_dtype = op.input_dtype;
        cursor->last_output_dtype = op.output_dtype;
        if (op.kind != expected_kind) return cursor->failure_code;
        termite_metal_decode_runtime_record_planned_command_op(cursor->runtime, op);
        cursor->index += 1;
        return 0;
    }
    cursor->last_quant_dispatch = (cursor->use_quant_dispatches && cursor->index < cursor->contract.quant_dispatch_count)
        ? cursor->contract.quant_dispatches[cursor->index]
        : TERMITE_METAL_QUANT_MATMUL_DISPATCH_UNKNOWN;
    cursor->last_operator = TERMITE_METAL_OPERATOR_UNKNOWN;
    cursor->last_format = UINT8_MAX;
    cursor->last_input_dtype = TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32;
    cursor->last_output_dtype = TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32;
    if (cursor->use_ops) {
        if (cursor->index >= cursor->contract.op_count || cursor->contract.ops[cursor->index] != expected_kind) return cursor->failure_code;
    }
    if (cursor->use_barriers || cursor->use_ops) {
        cursor->index += 1;
    }
    return 0;
}

static int termite_metal_planned_layer_cursor_before_step(
    termite_metal_planned_layer_cursor *cursor,
    const uint16_t *step_kinds,
    size_t step_count,
    size_t step_index
) {
    if (cursor == NULL || step_kinds == NULL || step_index >= step_count) return -1;
    return termite_metal_planned_layer_cursor_before_op(cursor, step_kinds[step_index]);
}

static uint8_t termite_metal_planned_layer_cursor_quant_dispatch(
    const termite_metal_planned_layer_cursor *cursor
) {
    return cursor != NULL ? cursor->last_quant_dispatch : TERMITE_METAL_QUANT_MATMUL_DISPATCH_UNKNOWN;
}

static uint8_t termite_metal_planned_layer_cursor_operator(
    const termite_metal_planned_layer_cursor *cursor
) {
    return cursor != NULL ? cursor->last_operator : TERMITE_METAL_OPERATOR_UNKNOWN;
}

static uint8_t termite_metal_planned_layer_cursor_input_dtype(
    const termite_metal_planned_layer_cursor *cursor
) {
    return cursor != NULL ? cursor->last_input_dtype : TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32;
}

static uint8_t termite_metal_planned_layer_cursor_output_dtype(
    const termite_metal_planned_layer_cursor *cursor
) {
    return cursor != NULL ? cursor->last_output_dtype : TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32;
}

static bool termite_metal_runtime_operator_is_quant_matmul(uint8_t op) {
    return op == TERMITE_METAL_OPERATOR_UNKNOWN ||
        op == TERMITE_METAL_OPERATOR_MUL_MV ||
        op == TERMITE_METAL_OPERATOR_MUL_MV_EXT ||
        op == TERMITE_METAL_OPERATOR_MUL_MM;
}

static uint8_t termite_metal_graph_quant_format_for_runtime_format(uint32_t format) {
    switch (format) {
        case TERMITE_METAL_QUANT_FORMAT_Q1_0: return TERMITE_METAL_GRAPH_QUANT_FORMAT_Q1_0;
        case TERMITE_METAL_QUANT_FORMAT_I2_S: return TERMITE_METAL_GRAPH_QUANT_FORMAT_I2_S;
        case TERMITE_METAL_QUANT_FORMAT_I8_S: return TERMITE_METAL_GRAPH_QUANT_FORMAT_I8_S;
        case TERMITE_METAL_QUANT_FORMAT_Q2_K: return TERMITE_METAL_GRAPH_QUANT_FORMAT_Q2_K;
        case TERMITE_METAL_QUANT_FORMAT_Q3_K: return TERMITE_METAL_GRAPH_QUANT_FORMAT_Q3_K;
        case TERMITE_METAL_QUANT_FORMAT_Q4_0: return TERMITE_METAL_GRAPH_QUANT_FORMAT_Q4_0;
        case TERMITE_METAL_QUANT_FORMAT_Q4_1: return TERMITE_METAL_GRAPH_QUANT_FORMAT_Q4_1;
        case TERMITE_METAL_QUANT_FORMAT_Q4_K: return TERMITE_METAL_GRAPH_QUANT_FORMAT_Q4_K;
        case TERMITE_METAL_QUANT_FORMAT_Q5_0: return TERMITE_METAL_GRAPH_QUANT_FORMAT_Q5_0;
        case TERMITE_METAL_QUANT_FORMAT_Q5_1: return TERMITE_METAL_GRAPH_QUANT_FORMAT_Q5_1;
        case TERMITE_METAL_QUANT_FORMAT_Q5_K: return TERMITE_METAL_GRAPH_QUANT_FORMAT_Q5_K;
        case TERMITE_METAL_QUANT_FORMAT_Q6_K: return TERMITE_METAL_GRAPH_QUANT_FORMAT_Q6_K;
        case TERMITE_METAL_QUANT_FORMAT_Q8_0: return TERMITE_METAL_GRAPH_QUANT_FORMAT_Q8_0;
        case TERMITE_METAL_QUANT_FORMAT_Q8_1: return TERMITE_METAL_GRAPH_QUANT_FORMAT_Q8_1;
        case TERMITE_METAL_QUANT_FORMAT_Q8_K: return TERMITE_METAL_GRAPH_QUANT_FORMAT_Q8_K;
        case TERMITE_METAL_QUANT_FORMAT_IQ2_XS: return TERMITE_METAL_GRAPH_QUANT_FORMAT_IQ2_XS;
        case TERMITE_METAL_QUANT_FORMAT_IQ4_NL: return TERMITE_METAL_GRAPH_QUANT_FORMAT_IQ4_NL;
        case TERMITE_METAL_QUANT_FORMAT_IQ4_XS: return TERMITE_METAL_GRAPH_QUANT_FORMAT_IQ4_XS;
        case TERMITE_METAL_QUANT_FORMAT_MXFP4: return TERMITE_METAL_GRAPH_QUANT_FORMAT_MXFP4;
        case TERMITE_METAL_QUANT_FORMAT_NVFP4: return TERMITE_METAL_GRAPH_QUANT_FORMAT_NVFP4;
        case TERMITE_METAL_QUANT_FORMAT_TL1: return TERMITE_METAL_GRAPH_QUANT_FORMAT_TL1;
        case TERMITE_METAL_QUANT_FORMAT_TL2: return TERMITE_METAL_GRAPH_QUANT_FORMAT_TL2;
        default: return TERMITE_METAL_GRAPH_FORMAT_UNKNOWN;
    }
}

static bool termite_metal_runtime_command_format_matches_quant(uint8_t command_format, uint32_t quant_format) {
    const uint8_t graph_format = termite_metal_graph_quant_format_for_runtime_format(quant_format);
    return command_format == TERMITE_METAL_GRAPH_FORMAT_UNKNOWN ||
        (graph_format != TERMITE_METAL_GRAPH_FORMAT_UNKNOWN && command_format == graph_format);
}

static bool termite_metal_runtime_command_format_is_f32_attention(uint8_t format) {
    return format == TERMITE_METAL_GRAPH_FORMAT_UNKNOWN ||
        format == TERMITE_METAL_GRAPH_ATTENTION_KV_FORMAT_F32;
}

static int termite_metal_planned_layer_cursor_fallback_barrier_after_op(
    termite_metal_planned_layer_cursor *cursor
) {
    if (cursor == NULL) return -1;
    (void)cursor;
    return 0;
}

static void termite_metal_decode_runtime_close_planned_compute_encoder_for_transition(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return;
    id<MTLComputeCommandEncoder> encoder = runtime->active_planned_compute_encoder;
    if (encoder == nil) return;
    [encoder endEncoding];
    runtime->active_planned_compute_encoder = nil;
    termite_metal_decode_runtime_reset_planned_compute_ranges(runtime);
    runtime->active_planned_compute_scope_closed_for_encoder_transition = true;
}

int termite_metal_decode_runtime_end_planned_compute_scope(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return -1;
    id<MTLComputeCommandEncoder> encoder = runtime->active_planned_compute_encoder;
    if (encoder == nil) {
        if (runtime->active_planned_compute_scope_closed_for_encoder_transition) {
            runtime->active_planned_compute_scope_closed_for_encoder_transition = false;
            runtime->active_planned_compute_source = TERMITE_METAL_COMPUTE_SOURCE_OTHER;
            runtime->active_planned_compute_region = TERMITE_METAL_COMPUTE_REGION_OTHER;
            return 0;
        }
        return -2;
    }
    if (termite_metal_should_coalesce_planned_compute_encoder(runtime)) {
        runtime->active_planned_compute_scope_closed_for_encoder_transition = false;
        runtime->active_planned_compute_source = TERMITE_METAL_COMPUTE_SOURCE_OTHER;
        runtime->active_planned_compute_region = TERMITE_METAL_COMPUTE_REGION_OTHER;
        return 0;
    }
    [encoder endEncoding];
    runtime->active_planned_compute_encoder = nil;
    termite_metal_decode_runtime_reset_planned_compute_ranges(runtime);
    runtime->active_planned_compute_scope_closed_for_encoder_transition = false;
    runtime->active_planned_compute_source = TERMITE_METAL_COMPUTE_SOURCE_OTHER;
    runtime->active_planned_compute_region = TERMITE_METAL_COMPUTE_REGION_OTHER;
    return 0;
}

static id<MTLBlitCommandEncoder> termite_metal_tracked_blit_command_encoder(id<MTLCommandBuffer> command_buffer) {
    termite_metal_decode_runtime *runtime = termite_metal_active_encoder_runtime;
    if (runtime != NULL && runtime->active_frame_cb == command_buffer) {
        termite_metal_decode_runtime_close_planned_compute_encoder_for_transition(runtime);
        runtime->blit_encoder_count += 1;
        runtime->active_frame_blit_encoder_count += 1;
    }
    return [command_buffer blitCommandEncoder];
}

static void termite_metal_record_active_frame_blit_source(id<MTLCommandBuffer> command_buffer, size_t source) {
    termite_metal_decode_runtime *runtime = termite_metal_active_encoder_runtime;
    if (runtime == NULL || runtime->active_frame_cb != command_buffer) return;
    if (source >= TERMITE_METAL_BLIT_COUNTER_COUNT) source = TERMITE_METAL_BLIT_SOURCE_OTHER;
    runtime->active_frame_blit_source_counts[source] += 1;
}

static id<MTLComputePipelineState> termite_metal_make_pipeline(id<MTLDevice> device, id<MTLLibrary> library, NSString *name) {
    NSError *error = nil;
    id<MTLFunction> function = [library newFunctionWithName:name];
    if (function == nil) {
        fprintf(stderr, "metal-make-pipeline missing-function name=%s\n", name.UTF8String);
        return nil;
    }
    id<MTLComputePipelineState> pipeline = [device newComputePipelineStateWithFunction:function error:&error];
    if (pipeline == nil && error != nil) {
        fprintf(stderr, "metal-make-pipeline name=%s error=%s\n", name.UTF8String, error.localizedDescription.UTF8String);
    }
    return pipeline;
}

static MPSMatrixMultiplication *termite_metal_decode_runtime_cached_mps_mm(
    termite_metal_decode_runtime *runtime,
    size_t slot,
    size_t rows,
    size_t in_dim,
    size_t out_dim
) {
    if (runtime == NULL || slot >= TERMITE_METAL_LINEAR_SLOT_CAPACITY || rows == 0 || in_dim == 0 || out_dim == 0) return nil;
    MPSMatrixMultiplication *cached = runtime->linear_mps_mm[slot];
    if (cached != nil &&
        runtime->linear_mps_mm_rows[slot] == rows &&
        runtime->linear_in_dims[slot] == in_dim &&
        runtime->linear_out_dims[slot] == out_dim)
    {
        return cached;
    }
    MPSMatrixMultiplication *mm = [[MPSMatrixMultiplication alloc] initWithDevice:runtime->device
                                                                    transposeLeft:NO
                                                                   transposeRight:YES
                                                                       resultRows:rows
                                                                    resultColumns:out_dim
                                                                  interiorColumns:in_dim
                                                                            alpha:1.0
                                                                             beta:0.0];
    if (mm == nil) return nil;
    runtime->linear_mps_mm[slot] = mm;
    runtime->linear_mps_mm_rows[slot] = rows;
    return mm;
}

static void termite_metal_decode_runtime_invalidate_dense_qkv_pack_slot(
    termite_metal_decode_runtime *runtime,
    size_t slot
) {
    if (runtime == NULL) return;
    for (size_t i = 0; i < TERMITE_METAL_DENSE_QKV_PACK_CACHE_CAPACITY; ++i) {
        if (i == slot ||
            runtime->dense_qkv_packed_k_slots[i] == slot ||
            runtime->dense_qkv_packed_v_slots[i] == slot)
        {
            runtime->dense_qkv_packed_weight_buffers[i] = nil;
            runtime->dense_qkv_packed_bias_buffers[i] = nil;
            runtime->dense_qkv_packed_mps_mm[i] = nil;
            runtime->dense_qkv_packed_k_slots[i] = SIZE_MAX;
            runtime->dense_qkv_packed_v_slots[i] = SIZE_MAX;
            runtime->dense_qkv_packed_in_dims[i] = 0;
            runtime->dense_qkv_packed_q_out_dims[i] = 0;
            runtime->dense_qkv_packed_kv_out_dims[i] = 0;
            runtime->dense_qkv_packed_mps_rows[i] = 0;
        }
    }
}

static void termite_metal_decode_runtime_invalidate_dense_pair_pack_slot(
    termite_metal_decode_runtime *runtime,
    size_t slot
) {
    if (runtime == NULL) return;
    for (size_t i = 0; i < TERMITE_METAL_LINEAR_SLOT_CAPACITY; ++i) {
        if (i == slot || runtime->dense_pair_packed_b_slots[i] == slot) {
            runtime->dense_pair_packed_weight_buffers[i] = nil;
            runtime->dense_pair_packed_bias_buffers[i] = nil;
            runtime->dense_pair_packed_mps_mm[i] = nil;
            runtime->dense_pair_packed_b_slots[i] = SIZE_MAX;
            runtime->dense_pair_packed_in_dims[i] = 0;
            runtime->dense_pair_packed_out_dims[i] = 0;
            runtime->dense_pair_packed_mps_rows[i] = 0;
        }
    }
}

static MPSMatrixMultiplication *termite_metal_decode_runtime_cached_dense_qkv_mps_mm(
    termite_metal_decode_runtime *runtime,
    size_t q_slot,
    size_t rows,
    size_t in_dim,
    size_t total_out_dim
) {
    if (runtime == NULL || q_slot >= TERMITE_METAL_DENSE_QKV_PACK_CACHE_CAPACITY || rows == 0 || in_dim == 0 || total_out_dim == 0) return nil;
    MPSMatrixMultiplication *cached = runtime->dense_qkv_packed_mps_mm[q_slot];
    if (cached != nil &&
        runtime->dense_qkv_packed_mps_rows[q_slot] == rows &&
        runtime->dense_qkv_packed_in_dims[q_slot] == in_dim)
    {
        return cached;
    }
    MPSMatrixMultiplication *mm = [[MPSMatrixMultiplication alloc] initWithDevice:runtime->device
                                                                    transposeLeft:NO
                                                                   transposeRight:YES
                                                                       resultRows:rows
                                                                    resultColumns:total_out_dim
                                                                  interiorColumns:in_dim
                                                                            alpha:1.0
                                                                             beta:0.0];
    if (mm == nil) return nil;
    runtime->dense_qkv_packed_mps_mm[q_slot] = mm;
    runtime->dense_qkv_packed_mps_rows[q_slot] = rows;
    return mm;
}

static int termite_metal_decode_runtime_ensure_dense_qkv_packed_weight(
    termite_metal_decode_runtime *runtime,
    id<MTLCommandBuffer> command_buffer,
    size_t q_slot,
    size_t k_slot,
    size_t v_slot,
    size_t in_dim,
    size_t q_out_dim,
    size_t kv_out_dim
) {
    if (runtime == NULL || command_buffer == nil || q_slot >= TERMITE_METAL_DENSE_QKV_PACK_CACHE_CAPACITY) return -1;
    const size_t q_bytes = q_out_dim * in_dim * sizeof(float);
    const size_t kv_bytes = kv_out_dim * in_dim * sizeof(float);
    const size_t packed_bytes = q_bytes + kv_bytes + kv_bytes;
    const size_t q_bias_bytes = q_out_dim * sizeof(float);
    const size_t kv_bias_bytes = kv_out_dim * sizeof(float);
    const size_t packed_bias_bytes = q_bias_bytes + kv_bias_bytes + kv_bias_bytes;
    if (runtime->dense_qkv_packed_weight_buffers[q_slot] != nil &&
        runtime->dense_qkv_packed_weight_buffers[q_slot].length >= packed_bytes &&
        runtime->dense_qkv_packed_bias_buffers[q_slot] != nil &&
        runtime->dense_qkv_packed_bias_buffers[q_slot].length >= packed_bias_bytes &&
        runtime->dense_qkv_packed_k_slots[q_slot] == k_slot &&
        runtime->dense_qkv_packed_v_slots[q_slot] == v_slot &&
        runtime->dense_qkv_packed_in_dims[q_slot] == in_dim &&
        runtime->dense_qkv_packed_q_out_dims[q_slot] == q_out_dim &&
        runtime->dense_qkv_packed_kv_out_dims[q_slot] == kv_out_dim)
    {
        return 0;
    }
    id<MTLBuffer> packed = [runtime->device newBufferWithLength:packed_bytes options:MTLResourceStorageModePrivate];
    id<MTLBuffer> packed_bias = [runtime->device newBufferWithLength:packed_bias_bytes options:MTLResourceStorageModePrivate];
    if (packed == nil || packed_bias == nil) return -2;
    id<MTLBlitCommandEncoder> blit = termite_metal_tracked_blit_command_encoder(command_buffer);
    if (blit == nil) return -3;
    [blit copyFromBuffer:runtime->linear_weight_buffers[q_slot] sourceOffset:0 toBuffer:packed destinationOffset:0 size:q_bytes];
    [blit copyFromBuffer:runtime->linear_weight_buffers[k_slot] sourceOffset:0 toBuffer:packed destinationOffset:q_bytes size:kv_bytes];
    [blit copyFromBuffer:runtime->linear_weight_buffers[v_slot] sourceOffset:0 toBuffer:packed destinationOffset:q_bytes + kv_bytes size:kv_bytes];
    [blit copyFromBuffer:runtime->linear_bias_buffers[q_slot] sourceOffset:0 toBuffer:packed_bias destinationOffset:0 size:q_bias_bytes];
    [blit copyFromBuffer:runtime->linear_bias_buffers[k_slot] sourceOffset:0 toBuffer:packed_bias destinationOffset:q_bias_bytes size:kv_bias_bytes];
    [blit copyFromBuffer:runtime->linear_bias_buffers[v_slot] sourceOffset:0 toBuffer:packed_bias destinationOffset:q_bias_bytes + kv_bias_bytes size:kv_bias_bytes];
    [blit endEncoding];

    runtime->dense_qkv_packed_weight_buffers[q_slot] = packed;
    runtime->dense_qkv_packed_bias_buffers[q_slot] = packed_bias;
    runtime->dense_qkv_packed_mps_mm[q_slot] = nil;
    runtime->dense_qkv_packed_k_slots[q_slot] = k_slot;
    runtime->dense_qkv_packed_v_slots[q_slot] = v_slot;
    runtime->dense_qkv_packed_in_dims[q_slot] = in_dim;
    runtime->dense_qkv_packed_q_out_dims[q_slot] = q_out_dim;
    runtime->dense_qkv_packed_kv_out_dims[q_slot] = kv_out_dim;
    runtime->dense_qkv_packed_mps_rows[q_slot] = 0;
    return 0;
}

static MPSMatrixMultiplication *termite_metal_decode_runtime_cached_dense_pair_mps_mm(
    termite_metal_decode_runtime *runtime,
    size_t a_slot,
    size_t rows,
    size_t in_dim,
    size_t total_out_dim
) {
    if (runtime == NULL || a_slot >= TERMITE_METAL_LINEAR_SLOT_CAPACITY || rows == 0 || in_dim == 0 || total_out_dim == 0) return nil;
    MPSMatrixMultiplication *cached = runtime->dense_pair_packed_mps_mm[a_slot];
    if (cached != nil &&
        runtime->dense_pair_packed_mps_rows[a_slot] == rows &&
        runtime->dense_pair_packed_in_dims[a_slot] == in_dim)
    {
        return cached;
    }
    MPSMatrixMultiplication *mm = [[MPSMatrixMultiplication alloc] initWithDevice:runtime->device
                                                                    transposeLeft:NO
                                                                   transposeRight:YES
                                                                       resultRows:rows
                                                                    resultColumns:total_out_dim
                                                                  interiorColumns:in_dim
                                                                            alpha:1.0
                                                                             beta:0.0];
    if (mm == nil) return nil;
    runtime->dense_pair_packed_mps_mm[a_slot] = mm;
    runtime->dense_pair_packed_mps_rows[a_slot] = rows;
    return mm;
}

static int termite_metal_decode_runtime_ensure_dense_pair_packed_weight(
    termite_metal_decode_runtime *runtime,
    id<MTLCommandBuffer> command_buffer,
    size_t a_slot,
    size_t b_slot,
    size_t in_dim,
    size_t out_dim
) {
    if (runtime == NULL || command_buffer == nil || a_slot >= TERMITE_METAL_LINEAR_SLOT_CAPACITY) return -1;
    const size_t projection_bytes = out_dim * in_dim * sizeof(float);
    const size_t packed_bytes = projection_bytes * 2;
    const size_t bias_bytes = out_dim * sizeof(float);
    const size_t packed_bias_bytes = bias_bytes * 2;
    if (runtime->dense_pair_packed_weight_buffers[a_slot] != nil &&
        runtime->dense_pair_packed_weight_buffers[a_slot].length >= packed_bytes &&
        runtime->dense_pair_packed_bias_buffers[a_slot] != nil &&
        runtime->dense_pair_packed_bias_buffers[a_slot].length >= packed_bias_bytes &&
        runtime->dense_pair_packed_b_slots[a_slot] == b_slot &&
        runtime->dense_pair_packed_in_dims[a_slot] == in_dim &&
        runtime->dense_pair_packed_out_dims[a_slot] == out_dim)
    {
        return 0;
    }
    id<MTLBuffer> packed = [runtime->device newBufferWithLength:packed_bytes options:MTLResourceStorageModePrivate];
    id<MTLBuffer> packed_bias = [runtime->device newBufferWithLength:packed_bias_bytes options:MTLResourceStorageModePrivate];
    if (packed == nil || packed_bias == nil) return -2;
    id<MTLBlitCommandEncoder> blit = termite_metal_tracked_blit_command_encoder(command_buffer);
    if (blit == nil) return -3;
    [blit copyFromBuffer:runtime->linear_weight_buffers[a_slot] sourceOffset:0 toBuffer:packed destinationOffset:0 size:projection_bytes];
    [blit copyFromBuffer:runtime->linear_weight_buffers[b_slot] sourceOffset:0 toBuffer:packed destinationOffset:projection_bytes size:projection_bytes];
    [blit copyFromBuffer:runtime->linear_bias_buffers[a_slot] sourceOffset:0 toBuffer:packed_bias destinationOffset:0 size:bias_bytes];
    [blit copyFromBuffer:runtime->linear_bias_buffers[b_slot] sourceOffset:0 toBuffer:packed_bias destinationOffset:bias_bytes size:bias_bytes];
    [blit endEncoding];

    runtime->dense_pair_packed_weight_buffers[a_slot] = packed;
    runtime->dense_pair_packed_bias_buffers[a_slot] = packed_bias;
    runtime->dense_pair_packed_mps_mm[a_slot] = nil;
    runtime->dense_pair_packed_b_slots[a_slot] = b_slot;
    runtime->dense_pair_packed_in_dims[a_slot] = in_dim;
    runtime->dense_pair_packed_out_dims[a_slot] = out_dim;
    runtime->dense_pair_packed_mps_rows[a_slot] = 0;
    return 0;
}

static id<MTLLibrary> termite_metal_make_library(id<MTLDevice> device, BOOL precise_math) {
    NSError *error = nil;
    MTLCompileOptions *options = [MTLCompileOptions new];
    if (precise_math) {
        if (options != nil) {
            options.mathMode = MTLMathModeSafe;
        }
    }
    id<MTLLibrary> library = [device newLibraryWithSource:termite_metal_shader_source() options:options error:&error];
    if (library == nil && error != nil) {
        fprintf(stderr, "metal-make-library precise=%d error=%s\n", precise_math ? 1 : 0, error.localizedDescription.UTF8String);
    }
    return library;
}

static id<MTLDevice> termite_metal_shared_device(void) {
    static id<MTLDevice> shared_device = nil;
    if (shared_device == nil) {
        shared_device = MTLCreateSystemDefaultDevice();
    }
    return shared_device;
}

static id<MTLCommandBuffer> termite_metal_new_command_buffer(id<MTLCommandQueue> queue, const char *label_cstr) {
    if (queue == nil) return nil;
    @autoreleasepool {
        id<MTLCommandBuffer> command_buffer = nil;
        if ([queue respondsToSelector:@selector(commandBufferWithDescriptor:)]) {
            MTLCommandBufferDescriptor *descriptor = [MTLCommandBufferDescriptor new];
            if (descriptor != nil && [descriptor respondsToSelector:@selector(setErrorOptions:)]) {
                descriptor.errorOptions = MTLCommandBufferErrorOptionEncoderExecutionStatus;
            }
            command_buffer = [queue commandBufferWithDescriptor:descriptor];
        }
        if (command_buffer == nil) {
            command_buffer = [queue commandBuffer];
        }
        if (command_buffer != nil && label_cstr != NULL) {
            NSString *label = [NSString stringWithUTF8String:label_cstr];
            if (label != nil) {
                command_buffer.label = label;
            }
        }
        if (command_buffer != nil) {
            const char *context = label_cstr;
            [command_buffer addCompletedHandler:^(id<MTLCommandBuffer> cb) {
                if (cb.status != MTLCommandBufferStatusCompleted) {
                    termite_metal_log_command_buffer_failure(cb, context);
                }
            }];
        }
        return command_buffer;
    }
}

static void termite_metal_log_command_buffer_failure(id<MTLCommandBuffer> command_buffer, const char *context) {
    if (command_buffer == nil) return;
    NSError *error = command_buffer.error;
    if (command_buffer.status != MTLCommandBufferStatusError && error == nil) return;
    const char *label = command_buffer.label != nil ? command_buffer.label.UTF8String : "(unlabeled)";
    const char *domain = (error != nil && error.domain != nil) ? error.domain.UTF8String : "(none)";
    const char *desc = (error != nil && error.localizedDescription != nil) ? error.localizedDescription.UTF8String : "(none)";
    long code = error != nil ? (long)error.code : 0;
    fprintf(stderr,
        "metal-command-buffer-failed context=%s label=%s status=%ld error_domain=%s error_code=%ld description=%s\n",
        context != NULL ? context : "(unknown)",
        label,
        (long)command_buffer.status,
        domain,
        code,
        desc);
}

static int termite_metal_commit_and_wait(id<MTLCommandBuffer> command_buffer, const char *context, int failure_code) {
    (void)context;
    if (command_buffer == nil) return failure_code;
    [command_buffer commit];
    [command_buffer waitUntilCompleted];
    if (command_buffer.status == MTLCommandBufferStatusCompleted) return 0;
    return failure_code;
}

static uint64_t termite_metal_command_buffer_gpu_elapsed_nanos(id<MTLCommandBuffer> command_buffer) {
    if (command_buffer == nil) return 0;
    if (![command_buffer respondsToSelector:@selector(GPUStartTime)] || ![command_buffer respondsToSelector:@selector(GPUEndTime)]) return 0;
    const CFTimeInterval start = command_buffer.GPUStartTime;
    const CFTimeInterval end = command_buffer.GPUEndTime;
    if (!(end > start) || !isfinite(start) || !isfinite(end)) return 0;
    return (uint64_t)((end - start) * 1000000000.0);
}

static id<MTLCommandBuffer> termite_metal_decode_runtime_command_buffer(termite_metal_decode_runtime *runtime, const char *label_cstr, bool *frame_owned) {
    if (runtime == NULL || frame_owned == NULL) return nil;
    *frame_owned = (runtime->active_frame_cb == nil);
    return *frame_owned ? termite_metal_new_command_buffer(runtime->queue, label_cstr) : runtime->active_frame_cb;
}

static bool termite_metal_mpsgraph_ffn_enabled(void) {
    const char *enabled = getenv("TERMITE_METAL_GLINER_DEBERTA_MPSGRAPH_BLOCK_EXPERIMENT");
    return enabled != NULL && enabled[0] != '\0' && strcmp(enabled, "0") != 0;
}

static bool termite_metal_dense_mps_linear_enabled(void) {
    const char *enabled = getenv("TERMITE_METAL_ENABLE_DENSE_MPS_LINEAR");
    if (enabled == NULL || enabled[0] == '\0' || strcmp(enabled, "0") == 0) return false;
    const char *disabled = getenv("TERMITE_METAL_DISABLE_DENSE_MPS_LINEAR");
    return disabled == NULL || disabled[0] == '\0' || strcmp(disabled, "0") == 0;
}

static bool termite_metal_direct_packed_dense_enabled(void) {
    const char *enabled = getenv("TERMITE_METAL_GLINER_DIRECT_PACKED_DENSE_EXPERIMENT");
    if (enabled != NULL && enabled[0] != '\0' && strcmp(enabled, "0") != 0) return true;
    return !termite_metal_dense_mps_linear_enabled();
}

static bool termite_metal_direct_deberta_ffn_enabled(void) {
    const char *disabled = getenv("TERMITE_METAL_DISABLE_GLINER_DEBERTA_DIRECT_FFN");
    return disabled == NULL || disabled[0] == '\0' || strcmp(disabled, "0") == 0;
}

static void termite_metal_mpsgraph_ffn_cache_clear(termite_metal_mpsgraph_ffn_cache *cache) {
    if (cache == NULL) return;
    cache->graph = nil;
    cache->input_tensor = nil;
    cache->residual_tensor = nil;
    cache->w1_tensor = nil;
    cache->b1_tensor = nil;
    cache->w2_tensor = nil;
    cache->b2_tensor = nil;
    cache->ln_w_tensor = nil;
    cache->ln_b_tensor = nil;
    cache->output_tensor = nil;
    cache->rows = 0;
    cache->hidden_size = 0;
    cache->intermediate_size = 0;
    cache->activation_kind = UINT32_MAX;
}

static MPSGraphTensor *termite_metal_mpsgraph_gelu_tanh(MPSGraph *graph, MPSGraphTensor *x) {
    MPSGraphTensor *half = [graph constantWithScalar:0.5 dataType:MPSDataTypeFloat32];
    MPSGraphTensor *one = [graph constantWithScalar:1.0 dataType:MPSDataTypeFloat32];
    MPSGraphTensor *coef = [graph constantWithScalar:0.7978845608028654 dataType:MPSDataTypeFloat32];
    MPSGraphTensor *cubic_coef = [graph constantWithScalar:0.044715 dataType:MPSDataTypeFloat32];
    MPSGraphTensor *x2 = [graph multiplicationWithPrimaryTensor:x secondaryTensor:x name:@"gelu_x2"];
    MPSGraphTensor *x3 = [graph multiplicationWithPrimaryTensor:x2 secondaryTensor:x name:@"gelu_x3"];
    MPSGraphTensor *x3_scaled = [graph multiplicationWithPrimaryTensor:x3 secondaryTensor:cubic_coef name:@"gelu_x3_scaled"];
    MPSGraphTensor *inner_sum = [graph additionWithPrimaryTensor:x secondaryTensor:x3_scaled name:@"gelu_inner_sum"];
    MPSGraphTensor *inner = [graph multiplicationWithPrimaryTensor:inner_sum secondaryTensor:coef name:@"gelu_inner"];
    MPSGraphTensor *tanh_inner = [graph tanhWithTensor:inner name:@"gelu_tanh"];
    MPSGraphTensor *cdf = [graph additionWithPrimaryTensor:one secondaryTensor:tanh_inner name:@"gelu_cdf"];
    MPSGraphTensor *xh = [graph multiplicationWithPrimaryTensor:x secondaryTensor:half name:@"gelu_xh"];
    return [graph multiplicationWithPrimaryTensor:xh secondaryTensor:cdf name:@"gelu_out"];
}

static int termite_metal_mpsgraph_ffn_cache_prepare(
    termite_metal_decode_runtime *runtime,
    size_t rows,
    size_t hidden_size,
    size_t intermediate_size,
    uint32_t activation_kind,
    float eps
) {
    if (runtime == NULL) return -1;
    if (activation_kind != 0u && activation_kind != 1u) return -2;
    termite_metal_mpsgraph_ffn_cache *cache = &runtime->mpsgraph_ffn_cache;
    if (cache->graph != nil &&
        cache->rows == rows &&
        cache->hidden_size == hidden_size &&
        cache->intermediate_size == intermediate_size &&
        cache->activation_kind == activation_kind) {
        runtime->mpsgraph_ffn_cache_hits += 1;
        return 0;
    }

    termite_metal_mpsgraph_ffn_cache_clear(cache);
    @autoreleasepool {
        MPSGraph *graph = [MPSGraph new];
        if (graph == nil) return -3;
        MPSShape *hidden_shape = @[ @(rows), @(hidden_size) ];
        MPSShape *intermediate_shape = @[ @(rows), @(intermediate_size) ];
        MPSShape *w1_shape = @[ @(intermediate_size), @(hidden_size) ];
        MPSShape *b1_shape = @[ @(intermediate_size) ];
        MPSShape *w2_shape = @[ @(hidden_size), @(intermediate_size) ];
        MPSShape *b2_shape = @[ @(hidden_size) ];
        MPSGraphTensor *input = [graph placeholderWithShape:hidden_shape dataType:MPSDataTypeFloat32 name:@"input"];
        MPSGraphTensor *residual = [graph placeholderWithShape:hidden_shape dataType:MPSDataTypeFloat32 name:@"residual"];
        MPSGraphTensor *w1 = [graph placeholderWithShape:w1_shape dataType:MPSDataTypeFloat32 name:@"w1"];
        MPSGraphTensor *b1 = [graph placeholderWithShape:b1_shape dataType:MPSDataTypeFloat32 name:@"b1"];
        MPSGraphTensor *w2 = [graph placeholderWithShape:w2_shape dataType:MPSDataTypeFloat32 name:@"w2"];
        MPSGraphTensor *b2 = [graph placeholderWithShape:b2_shape dataType:MPSDataTypeFloat32 name:@"b2"];
        MPSGraphTensor *ln_w = [graph placeholderWithShape:b2_shape dataType:MPSDataTypeFloat32 name:@"ln_w"];
        MPSGraphTensor *ln_b = [graph placeholderWithShape:b2_shape dataType:MPSDataTypeFloat32 name:@"ln_b"];
        if (input == nil || residual == nil || w1 == nil || b1 == nil || w2 == nil || b2 == nil || ln_w == nil || ln_b == nil) return -4;

        MPSGraphTensor *w1_t = [graph transposeTensor:w1 dimension:0 withDimension:1 name:@"w1_t"];
        MPSGraphTensor *h1 = [graph matrixMultiplicationWithPrimaryTensor:input secondaryTensor:w1_t name:@"ffn_up"];
        MPSGraphTensor *h1_bias = [graph additionWithPrimaryTensor:h1 secondaryTensor:b1 name:@"ffn_up_bias"];
        MPSGraphTensor *h1_act = termite_metal_mpsgraph_gelu_tanh(graph, h1_bias);
        MPSGraphTensor *w2_t = [graph transposeTensor:w2 dimension:0 withDimension:1 name:@"w2_t"];
        MPSGraphTensor *h2 = [graph matrixMultiplicationWithPrimaryTensor:h1_act secondaryTensor:w2_t name:@"ffn_down"];
        MPSGraphTensor *h2_bias = [graph additionWithPrimaryTensor:h2 secondaryTensor:b2 name:@"ffn_down_bias"];
        MPSGraphTensor *residual_sum = [graph additionWithPrimaryTensor:h2_bias secondaryTensor:residual name:@"ffn_residual"];
        NSArray<NSNumber *> *axes = @[ @1 ];
        MPSGraphTensor *mean = [graph meanOfTensor:residual_sum axes:axes name:@"ln_mean"];
        MPSGraphTensor *variance = [graph varianceOfTensor:residual_sum meanTensor:mean axes:axes name:@"ln_variance"];
        MPSGraphTensor *output = [graph normalizationWithTensor:residual_sum
                                                     meanTensor:mean
                                                 varianceTensor:variance
                                                    gammaTensor:ln_w
                                                     betaTensor:ln_b
                                                        epsilon:eps
                                                           name:@"ln_out"];
        if (output == nil) return -5;

        cache->graph = graph;
        cache->input_tensor = input;
        cache->residual_tensor = residual;
        cache->w1_tensor = w1;
        cache->b1_tensor = b1;
        cache->w2_tensor = w2;
        cache->b2_tensor = b2;
        cache->ln_w_tensor = ln_w;
        cache->ln_b_tensor = ln_b;
        cache->output_tensor = output;
        cache->rows = rows;
        cache->hidden_size = hidden_size;
        cache->intermediate_size = intermediate_size;
        cache->activation_kind = activation_kind;
        runtime->mpsgraph_ffn_compiles += 1;
        return 0;
    }
}

static int termite_metal_decode_runtime_apply_mpsgraph_ffn_layer_norm_device(
    termite_metal_decode_runtime *runtime,
    size_t first_linear_slot,
    size_t second_linear_slot,
    size_t layer_norm_slot,
    id<MTLBuffer> input_buffer,
    id<MTLBuffer> residual_buffer,
    id<MTLBuffer> output_buffer,
    size_t rows,
    size_t hidden_size,
    size_t intermediate_size,
    uint32_t activation_kind,
    float eps
) {
    if (runtime == NULL || input_buffer == nil || residual_buffer == nil || output_buffer == nil) return -1;
    int cache_rc = termite_metal_mpsgraph_ffn_cache_prepare(runtime, rows, hidden_size, intermediate_size, activation_kind, eps);
    if (cache_rc != 0) return -2;
    termite_metal_mpsgraph_ffn_cache *cache = &runtime->mpsgraph_ffn_cache;
    if (cache->graph == nil || cache->output_tensor == nil) return -3;

    const bool frame_owned = (runtime->active_frame_cb == nil);
    if (!frame_owned && runtime->active_planned_compute_encoder != nil) {
        termite_metal_decode_runtime_close_planned_compute_encoder_for_transition(runtime);
    }
    id<MTLCommandBuffer> command_buffer = frame_owned
        ? termite_metal_new_command_buffer(runtime->queue, __func__)
        : runtime->active_frame_cb;
    if (command_buffer == nil) return -4;
    MPSCommandBuffer *mps_command_buffer = [MPSCommandBuffer commandBufferWithCommandBuffer:command_buffer];
    if (mps_command_buffer == nil) return -5;

    MPSShape *hidden_shape = @[ @(rows), @(hidden_size) ];
    MPSShape *intermediate_shape = @[ @(rows), @(intermediate_size) ];
    MPSShape *w1_shape = @[ @(intermediate_size), @(hidden_size) ];
    MPSShape *b1_shape = @[ @(intermediate_size) ];
    MPSShape *w2_shape = @[ @(hidden_size), @(intermediate_size) ];
    MPSShape *b2_shape = @[ @(hidden_size) ];
    MPSGraphTensorData *input_data = [[MPSGraphTensorData alloc] initWithMTLBuffer:input_buffer shape:hidden_shape dataType:MPSDataTypeFloat32];
    MPSGraphTensorData *residual_data = [[MPSGraphTensorData alloc] initWithMTLBuffer:residual_buffer shape:hidden_shape dataType:MPSDataTypeFloat32];
    MPSGraphTensorData *w1_data = [[MPSGraphTensorData alloc] initWithMTLBuffer:runtime->linear_weight_buffers[first_linear_slot] shape:w1_shape dataType:MPSDataTypeFloat32];
    MPSGraphTensorData *b1_data = [[MPSGraphTensorData alloc] initWithMTLBuffer:runtime->linear_bias_buffers[first_linear_slot] shape:b1_shape dataType:MPSDataTypeFloat32];
    MPSGraphTensorData *w2_data = [[MPSGraphTensorData alloc] initWithMTLBuffer:runtime->linear_weight_buffers[second_linear_slot] shape:w2_shape dataType:MPSDataTypeFloat32];
    MPSGraphTensorData *b2_data = [[MPSGraphTensorData alloc] initWithMTLBuffer:runtime->linear_bias_buffers[second_linear_slot] shape:b2_shape dataType:MPSDataTypeFloat32];
    MPSGraphTensorData *ln_w_data = [[MPSGraphTensorData alloc] initWithMTLBuffer:runtime->layer_norm_weight_buffers[layer_norm_slot] shape:b2_shape dataType:MPSDataTypeFloat32];
    MPSGraphTensorData *ln_b_data = [[MPSGraphTensorData alloc] initWithMTLBuffer:runtime->layer_norm_bias_buffers[layer_norm_slot] shape:b2_shape dataType:MPSDataTypeFloat32];
    MPSGraphTensorData *output_data = [[MPSGraphTensorData alloc] initWithMTLBuffer:output_buffer shape:hidden_shape dataType:MPSDataTypeFloat32];
    if (input_data == nil || residual_data == nil || w1_data == nil || b1_data == nil || w2_data == nil || b2_data == nil || ln_w_data == nil || ln_b_data == nil || output_data == nil) return -6;

    MPSGraphTensorDataDictionary *feeds = @{
        cache->input_tensor: input_data,
        cache->residual_tensor: residual_data,
        cache->w1_tensor: w1_data,
        cache->b1_tensor: b1_data,
        cache->w2_tensor: w2_data,
        cache->b2_tensor: b2_data,
        cache->ln_w_tensor: ln_w_data,
        cache->ln_b_tensor: ln_b_data,
    };
    MPSGraphTensorDataDictionary *results = @{
        cache->output_tensor: output_data,
    };
    if (feeds == nil || results == nil) return -7;
    [cache->graph encodeToCommandBuffer:mps_command_buffer
                                  feeds:feeds
                       targetOperations:nil
                      resultsDictionary:results
                    executionDescriptor:nil];
    if (!frame_owned) {
        runtime->active_frame_cb = mps_command_buffer.rootCommandBuffer;
        if (termite_metal_decode_runtime_retain_frame_resource(runtime, mps_command_buffer) != 0 ||
            termite_metal_decode_runtime_retain_frame_resource(runtime, feeds) != 0 ||
            termite_metal_decode_runtime_retain_frame_resource(runtime, results) != 0) {
            return -8;
        }
        runtime->mpsgraph_ffn_calls += 1;
        return 0;
    }
    const uint64_t wait_start = termite_metal_clock_monotonic_nanos();
    [mps_command_buffer commit];
    [mps_command_buffer waitUntilCompleted];
    const uint64_t wait_end = termite_metal_clock_monotonic_nanos();
    if (wait_end > wait_start) runtime->mps_dense_linear_standalone_wait_nanos += wait_end - wait_start;
    if (mps_command_buffer.status == MTLCommandBufferStatusCompleted) {
        runtime->mps_dense_linear_standalone_gpu_nanos += termite_metal_command_buffer_gpu_elapsed_nanos(mps_command_buffer);
        runtime->mpsgraph_ffn_calls += 1;
        return 0;
    }
    return -9;
}

static int termite_metal_decode_runtime_finish_command_buffer(id<MTLCommandBuffer> command_buffer, bool frame_owned, int failure_code) {
    if (!frame_owned) return 0;
    [command_buffer commit];
    [command_buffer waitUntilCompleted];
    return command_buffer.status == MTLCommandBufferStatusCompleted ? 0 : failure_code;
}

static void termite_metal_decode_runtime_set_quant_linear_descriptor(
    termite_metal_decode_runtime *runtime,
    size_t slot,
    uint32_t format,
    size_t values_per_block,
    size_t bytes_per_block,
    size_t in_dim
) {
    if (runtime == NULL || slot >= TERMITE_METAL_LINEAR_SLOT_CAPACITY || values_per_block == 0) return;
    runtime->quant_linear_formats[slot] = format;
    runtime->quant_linear_values_per_block[slot] = values_per_block;
    runtime->quant_linear_bytes_per_block[slot] = bytes_per_block;
    runtime->quant_linear_row_blocks[slot] = in_dim / values_per_block;
    runtime->quant_linear_row_stride_bytes[slot] = (in_dim / values_per_block) * bytes_per_block;
}

static void termite_metal_decode_runtime_clear_quant_linear_descriptor(termite_metal_decode_runtime *runtime, size_t slot) {
    termite_metal_decode_runtime_set_quant_linear_descriptor(runtime, slot, TERMITE_METAL_QUANT_FORMAT_UNSUPPORTED, 1u, 0u, 0u);
    if (runtime == NULL || slot >= TERMITE_METAL_LINEAR_SLOT_CAPACITY) return;
    runtime->quant_linear_weight_buffers[slot] = nil;
    runtime->quant_linear_in_dims[slot] = 0;
    runtime->quant_linear_out_dims[slot] = 0;
    runtime->quant_linear_slot_prepared[slot] = 0;
    runtime->quant_linear_tl1_packed_len[slot] = 0;
    runtime->quant_linear_tl1_bm[slot] = 0;
    runtime->quant_linear_tl1_cfg_by[slot] = 0;
    runtime->quant_linear_tl1_bmm[slot] = 0;
    runtime->quant_linear_tl2_scale_off[slot] = 0;
    runtime->quant_linear_tl2_three_value_len[slot] = 0;
    runtime->quant_linear_tl2_three_sign_len[slot] = 0;
    runtime->quant_linear_tl2_bm[slot] = 0;
    runtime->quant_linear_tl2_cfg_by[slot] = 0;
    runtime->quant_linear_tl2_bmm[slot] = 0;
    runtime->quant_linear_tl2_three_cols[slot] = 0;
    runtime->quant_linear_tl2_two_cols[slot] = 0;
}

static int termite_metal_decode_runtime_check_quant_linear_descriptor(
    termite_metal_decode_runtime *runtime,
    size_t slot,
    uint32_t format,
    size_t values_per_block,
    size_t bytes_per_block,
    size_t in_dim
) {
    if (runtime == NULL) return -1;
    if (slot >= TERMITE_METAL_LINEAR_SLOT_CAPACITY) return -2;
    if (values_per_block == 0 || in_dim % values_per_block != 0) return -3;
    if (runtime->quant_linear_formats[slot] != format) return -4;
    if (runtime->quant_linear_values_per_block[slot] != values_per_block) return -5;
    if (runtime->quant_linear_bytes_per_block[slot] != bytes_per_block) return -6;
    if (runtime->quant_linear_row_blocks[slot] != in_dim / values_per_block) return -7;
    if (runtime->quant_linear_row_stride_bytes[slot] != (in_dim / values_per_block) * bytes_per_block) return -8;
    return 0;
}

typedef struct termite_metal_quant_linear_slot_view {
    id<MTLComputePipelineState> pipeline;
    id<MTLBuffer> weight_buffer;
    uint8_t prepared;
    size_t in_dim;
    size_t out_dim;
    uint32_t format;
    size_t values_per_block;
    size_t bytes_per_block;
} termite_metal_quant_linear_slot_view;

static bool termite_metal_quant_format_block_layout(
    uint32_t format,
    size_t *values_per_block,
    size_t *bytes_per_block
) {
    if (values_per_block == NULL || bytes_per_block == NULL) return false;
    switch (format) {
        case TERMITE_METAL_QUANT_FORMAT_Q1_0: *values_per_block = 128u; *bytes_per_block = 18u; return true;
        case TERMITE_METAL_QUANT_FORMAT_I2_S: *values_per_block = 128u; *bytes_per_block = 32u; return true;
        case TERMITE_METAL_QUANT_FORMAT_I8_S: *values_per_block = 1u; *bytes_per_block = 1u; return true;
        case TERMITE_METAL_QUANT_FORMAT_Q2_K: *values_per_block = 256u; *bytes_per_block = 84u; return true;
        case TERMITE_METAL_QUANT_FORMAT_Q3_K: *values_per_block = 256u; *bytes_per_block = 110u; return true;
        case TERMITE_METAL_QUANT_FORMAT_Q4_0: *values_per_block = 32u; *bytes_per_block = 18u; return true;
        case TERMITE_METAL_QUANT_FORMAT_Q4_1: *values_per_block = 32u; *bytes_per_block = 20u; return true;
        case TERMITE_METAL_QUANT_FORMAT_Q4_K: *values_per_block = 256u; *bytes_per_block = 144u; return true;
        case TERMITE_METAL_QUANT_FORMAT_Q5_0: *values_per_block = 32u; *bytes_per_block = 22u; return true;
        case TERMITE_METAL_QUANT_FORMAT_Q5_1: *values_per_block = 32u; *bytes_per_block = 24u; return true;
        case TERMITE_METAL_QUANT_FORMAT_Q5_K: *values_per_block = 256u; *bytes_per_block = 176u; return true;
        case TERMITE_METAL_QUANT_FORMAT_Q6_K: *values_per_block = 256u; *bytes_per_block = 210u; return true;
        case TERMITE_METAL_QUANT_FORMAT_Q8_0: *values_per_block = 32u; *bytes_per_block = 34u; return true;
        case TERMITE_METAL_QUANT_FORMAT_Q8_1: *values_per_block = 32u; *bytes_per_block = 36u; return true;
        case TERMITE_METAL_QUANT_FORMAT_Q8_K: *values_per_block = 256u; *bytes_per_block = 292u; return true;
        case TERMITE_METAL_QUANT_FORMAT_IQ2_XS: *values_per_block = 256u; *bytes_per_block = 74u; return true;
        case TERMITE_METAL_QUANT_FORMAT_IQ4_NL: *values_per_block = 32u; *bytes_per_block = 18u; return true;
        case TERMITE_METAL_QUANT_FORMAT_IQ4_XS: *values_per_block = 256u; *bytes_per_block = 136u; return true;
        case TERMITE_METAL_QUANT_FORMAT_MXFP4: *values_per_block = 32u; *bytes_per_block = 17u; return true;
        case TERMITE_METAL_QUANT_FORMAT_NVFP4: *values_per_block = 64u; *bytes_per_block = 36u; return true;
        case TERMITE_METAL_QUANT_FORMAT_TL1:
        case TERMITE_METAL_QUANT_FORMAT_TL2: *values_per_block = 1u; *bytes_per_block = 1u; return true;
        default: return false;
    }
}

typedef enum termite_metal_quant_matmul_epilogue {
    TERMITE_METAL_QUANT_MATMUL_EPILOGUE_NONE = 0,
    TERMITE_METAL_QUANT_MATMUL_EPILOGUE_PAIR_ACTIVATION_MUL = 1,
    TERMITE_METAL_QUANT_MATMUL_EPILOGUE_QKV = 2,
    TERMITE_METAL_QUANT_MATMUL_EPILOGUE_PAIR = 3,
    TERMITE_METAL_QUANT_MATMUL_EPILOGUE_ACTIVATION_RHS_MUL = 4,
    TERMITE_METAL_QUANT_MATMUL_EPILOGUE_PAIR_ACTIVATION_RMS_SCALE_1X = 5,
} termite_metal_quant_matmul_epilogue;

typedef struct termite_metal_quant_matmul_descriptor {
    size_t slot;
    uint32_t format;
    termite_metal_quant_matmul_activation_dtype activation_dtype;
    termite_metal_quant_matmul_activation_dtype input_dtype;
    termite_metal_quant_matmul_activation_dtype output_dtype;
    termite_metal_quant_matmul_epilogue epilogue;
    id<MTLComputePipelineState> fallback_pipeline;
    id<MTLBuffer> input_buffer;
    size_t input_offset;
    id<MTLBuffer> weight_buffer;
    id<MTLBuffer> second_weight_buffer;
    id<MTLBuffer> third_weight_buffer;
    id<MTLBuffer> output_buffer;
    size_t output_offset;
    id<MTLBuffer> second_output_buffer;
    size_t second_output_offset;
    id<MTLBuffer> third_output_buffer;
    size_t third_output_offset;
    id<MTLBuffer> rhs_buffer;
    size_t rhs_offset;
    id<MTLBuffer> inv_scale_buffer;
    size_t inv_scale_offset;
    size_t norm_slot;
    size_t rows;
    size_t in_dim;
    size_t out_dim;
    size_t second_out_dim;
    size_t values_per_block;
    size_t bytes_per_block;
    uint32_t activation_kind;
    termite_metal_q8_0_linear_family_kind q8_family;
    bool use_planned_dispatch;
    uint8_t planned_dispatch;
    int failure_code;
} termite_metal_quant_matmul_descriptor;

static uint8_t termite_metal_quant_matmul_descriptor_planned_dispatch(const termite_metal_quant_matmul_descriptor *descriptor);

static size_t termite_metal_quant_matmul_dtype_size(termite_metal_quant_matmul_activation_dtype dtype) {
    switch (dtype) {
        case TERMITE_METAL_QUANT_MATMUL_ACTIVATION_BF16:
        case TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F16:
            return sizeof(uint16_t);
        case TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32:
        default:
            return sizeof(float);
    }
}

static termite_metal_quant_matmul_activation_dtype termite_metal_quant_matmul_dtype_from_command(uint8_t dtype) {
    switch (dtype) {
        case TERMITE_METAL_QUANT_MATMUL_ACTIVATION_BF16:
            return TERMITE_METAL_QUANT_MATMUL_ACTIVATION_BF16;
        case TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F16:
            return TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F16;
        case TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32:
        default:
            return TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32;
    }
}

static bool termite_metal_quant_matmul_descriptor_dtype_supported(
    termite_metal_decode_runtime *runtime,
    const termite_metal_quant_matmul_descriptor *descriptor
) {
    if (runtime == NULL || descriptor == NULL) return false;
    if (descriptor->activation_dtype != TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32) return false;
    if (descriptor->input_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32 &&
        descriptor->output_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32) return true;
    if (descriptor->format != TERMITE_METAL_QUANT_FORMAT_Q8_0 ||
        descriptor->values_per_block != 32u ||
        descriptor->bytes_per_block != 34u) return false;
    const uint8_t planned_dispatch = termite_metal_quant_matmul_descriptor_planned_dispatch(descriptor);
    const termite_metal_q8_0_linear_dispatch_kind dispatch_kind = termite_metal_q8_0_dispatch_from_quant_dispatch(
        termite_metal_select_quant_matmul_dispatch_preferred(
            descriptor->format,
            descriptor->rows,
            descriptor->in_dim,
            descriptor->out_dim,
            descriptor->values_per_block,
            planned_dispatch));
    if (descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_PAIR_ACTIVATION_MUL &&
        descriptor->input_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32 &&
        descriptor->output_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F16) {
        return dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM &&
            runtime->q8_0_pair_activation_mm_f16_output_pipeline != nil;
    }
    if (descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_PAIR_ACTIVATION_RMS_SCALE_1X &&
        descriptor->rows == 1u &&
        descriptor->input_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32 &&
        descriptor->output_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F16) {
        return (dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MMV ||
                dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SCALAR) &&
            runtime->q8_0_pair_activation_rms_scale_mmv_f16_output_pipeline != nil;
    }
    if (descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_NONE &&
        descriptor->input_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F16 &&
        descriptor->output_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32) {
        return (dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM &&
                runtime->q8_0_mm_f16_input_pipeline != nil) ||
            ((dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MMV ||
                dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SCALAR) &&
                runtime->q8_0_mmv_f16_input_pipeline != nil);
    }
    return false;
}

