static void termite_metal_decode_runtime_set_quant_linear_slot_view(
    termite_metal_quant_linear_slot_view *view,
    id<MTLComputePipelineState> pipeline,
    id<MTLBuffer> weight_buffer,
    uint8_t prepared,
    size_t in_dim,
    size_t out_dim,
    uint32_t format,
    size_t values_per_block,
    size_t bytes_per_block
) {
    view->pipeline = pipeline;
    view->weight_buffer = weight_buffer;
    view->prepared = prepared;
    view->in_dim = in_dim;
    view->out_dim = out_dim;
    view->format = format;
    view->values_per_block = values_per_block;
    view->bytes_per_block = bytes_per_block;
}

static int termite_metal_decode_runtime_quant_linear_slot_view(
    termite_metal_decode_runtime *runtime,
    uint32_t format,
    size_t slot,
    termite_metal_quant_linear_slot_view *view
) {
    if (runtime == NULL || view == NULL) return -1;
    if (slot >= TERMITE_METAL_LINEAR_SLOT_CAPACITY) return -2;
    if (runtime->quant_linear_formats[slot] != format) return -4;
    id<MTLComputePipelineState> pipeline = nil;
    switch (format) {
        case TERMITE_METAL_QUANT_FORMAT_Q1_0:
            pipeline = runtime->q1_0_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_I2_S:
            pipeline = runtime->i2_s_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_I8_S:
            pipeline = runtime->i8_s_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_Q2_K:
            pipeline = runtime->q2_k_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_Q3_K:
            pipeline = runtime->q3_k_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_Q4_0:
            pipeline = runtime->q4_0_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_Q4_1:
            pipeline = runtime->q4_1_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_Q5_0:
            pipeline = runtime->q5_0_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_Q5_1:
            pipeline = runtime->q5_1_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_Q4_K:
            pipeline = runtime->q4_k_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_Q5_K:
            pipeline = runtime->q5_k_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_Q6_K:
            pipeline = runtime->q6_k_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_Q8_0:
            pipeline = runtime->q8_0_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_Q8_1:
            pipeline = runtime->q8_1_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_Q8_K:
            pipeline = runtime->q8_k_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_IQ4_NL:
            pipeline = runtime->iq4_nl_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_IQ4_XS:
            pipeline = runtime->iq4_xs_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_MXFP4:
            pipeline = runtime->mxfp4_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_NVFP4:
            pipeline = runtime->nvfp4_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_IQ2_XS:
            pipeline = runtime->iq2_xs_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_TL1:
            pipeline = runtime->tl1_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_TL2:
            pipeline = runtime->tl2_pipeline;
            break;
        default:
            return -3;
    }
    termite_metal_decode_runtime_set_quant_linear_slot_view(view, pipeline, runtime->quant_linear_weight_buffers[slot], runtime->quant_linear_slot_prepared[slot], runtime->quant_linear_in_dims[slot], runtime->quant_linear_out_dims[slot], format, runtime->quant_linear_values_per_block[slot], runtime->quant_linear_bytes_per_block[slot]);
    return 0;
}

static int termite_metal_decode_runtime_require_quant_linear_slot(
    termite_metal_decode_runtime *runtime,
    uint32_t format,
    size_t slot,
    size_t in_dim,
    size_t out_dim,
    termite_metal_quant_linear_slot_view *view
) {
    int rc = termite_metal_decode_runtime_quant_linear_slot_view(runtime, format, slot, view);
    if (rc != 0) return rc;
    if (view->pipeline == nil || view->weight_buffer == nil) return -20;
    if (view->prepared == 0) return -21;
    if (view->in_dim != in_dim || view->out_dim != out_dim) return -22;
    if (termite_metal_decode_runtime_check_quant_linear_descriptor(runtime, slot, format, view->values_per_block, view->bytes_per_block, in_dim) != 0) return -23;
    return 0;
}

static uint8_t termite_metal_quant_matmul_descriptor_planned_dispatch(
    const termite_metal_quant_matmul_descriptor *descriptor
) {
    return (descriptor != NULL && descriptor->use_planned_dispatch)
        ? descriptor->planned_dispatch
        : TERMITE_METAL_QUANT_MATMUL_DISPATCH_UNKNOWN;
}

static int termite_metal_prepare_quant_matmul_accesses(
    termite_metal_decode_runtime *runtime,
    const termite_metal_quant_matmul_descriptor *descriptor,
    int failure_code
);

static int termite_metal_encode_quant_matmul_generic_pair_on_encoder(
    termite_metal_decode_runtime *runtime,
    id<MTLComputeCommandEncoder> encoder,
    const termite_metal_quant_matmul_descriptor *descriptor
) {
    if (runtime == NULL || encoder == nil || descriptor == NULL) return -1;
    const int failure_code = descriptor->failure_code;
    if (descriptor->activation_dtype != TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32 ||
        descriptor->epilogue != TERMITE_METAL_QUANT_MATMUL_EPILOGUE_PAIR ||
        descriptor->input_buffer == nil ||
        descriptor->weight_buffer == nil ||
        descriptor->second_weight_buffer == nil ||
        descriptor->output_buffer == nil ||
        descriptor->second_output_buffer == nil) return failure_code;
    if (descriptor->rows == 0 ||
        descriptor->in_dim == 0 ||
        descriptor->out_dim == 0 ||
        descriptor->values_per_block == 0 ||
        descriptor->in_dim % descriptor->values_per_block != 0) return failure_code;
    size_t expected_values_per_block = 0;
    size_t expected_bytes_per_block = 0;
    if (!termite_metal_quant_format_block_layout(descriptor->format, &expected_values_per_block, &expected_bytes_per_block) ||
        descriptor->values_per_block != expected_values_per_block ||
        descriptor->bytes_per_block != expected_bytes_per_block) return failure_code;
    if (termite_metal_prepare_quant_matmul_accesses(runtime, descriptor, failure_code) != 0) return failure_code;

    id<MTLComputePipelineState> pipeline = descriptor->fallback_pipeline;
    BOOL two_dimensional_grid = NO;
    switch (descriptor->format) {
        case TERMITE_METAL_QUANT_FORMAT_I2_S:
            pipeline = pipeline != nil ? pipeline : runtime->i2_s_pair_pipeline;
            break;
        case TERMITE_METAL_QUANT_FORMAT_Q4_0:
            pipeline = pipeline != nil ? pipeline : runtime->q4_0_pair_pipeline;
            two_dimensional_grid = YES;
            break;
        case TERMITE_METAL_QUANT_FORMAT_Q4_K:
            pipeline = pipeline != nil ? pipeline : runtime->q4_k_pair_pipeline;
            two_dimensional_grid = YES;
            break;
        case TERMITE_METAL_QUANT_FORMAT_Q6_K:
            pipeline = pipeline != nil ? pipeline : runtime->q6_k_pair_pipeline;
            two_dimensional_grid = YES;
            break;
        default:
            return failure_code;
    }
    if (pipeline == nil) return failure_code;

    termite_metal_linear_params params = {
        .rows = (uint32_t)descriptor->rows,
        .in_dim = (uint32_t)descriptor->in_dim,
        .out_dim = (uint32_t)descriptor->out_dim,
        .row_blocks = (uint32_t)(descriptor->in_dim / descriptor->values_per_block),
    };
    [encoder setComputePipelineState:pipeline];
    [encoder setBuffer:descriptor->input_buffer offset:descriptor->input_offset atIndex:0];
    [encoder setBuffer:descriptor->weight_buffer offset:0 atIndex:1];
    [encoder setBuffer:descriptor->second_weight_buffer offset:0 atIndex:2];
    [encoder setBuffer:descriptor->output_buffer offset:descriptor->output_offset atIndex:3];
    [encoder setBuffer:descriptor->second_output_buffer offset:descriptor->second_output_offset atIndex:4];
    [encoder setBytes:&params length:sizeof(params) atIndex:5];
    if (two_dimensional_grid) {
        NSUInteger thread_width = pipeline.maxTotalThreadsPerThreadgroup;
        if (thread_width == 0) thread_width = 32;
        if (thread_width > descriptor->out_dim && descriptor->out_dim > 0) thread_width = descriptor->out_dim;
        [encoder dispatchThreads:MTLSizeMake(descriptor->out_dim, descriptor->rows, 1) threadsPerThreadgroup:MTLSizeMake(thread_width, 1, 1)];
    } else {
        const size_t total = descriptor->rows * descriptor->out_dim;
        [encoder dispatchThreads:MTLSizeMake(total, 1, 1) threadsPerThreadgroup:MTLSizeMake(termite_metal_thread_width(pipeline, total), 1, 1)];
    }
    return 0;
}

static int termite_metal_prepare_quant_matmul_accesses(
    termite_metal_decode_runtime *runtime,
    const termite_metal_quant_matmul_descriptor *descriptor,
    int failure_code
) {
    if (runtime == NULL || descriptor == NULL || runtime->active_planned_compute_encoder == nil) return 0;

    size_t input_bytes = 0;
    size_t output_bytes = 0;
    if (!termite_metal_size_mul3(descriptor->rows, descriptor->in_dim, termite_metal_quant_matmul_dtype_size(descriptor->input_dtype), &input_bytes)) return failure_code;
    if (!termite_metal_size_mul3(descriptor->rows, descriptor->out_dim, termite_metal_quant_matmul_dtype_size(descriptor->output_dtype), &output_bytes)) return failure_code;

    termite_metal_planned_encoder_range accesses[12];
    size_t count = 0;
#define TERMITE_PLAN_ACCESS(access_buffer, offset, bytes, kind) do { \
        if (termite_metal_planned_range_make((access_buffer), (offset), (bytes), (kind), &accesses[count], failure_code) != 0) return failure_code; \
        if (accesses[count].buffer != nil) count += 1; \
    } while (0)

    TERMITE_PLAN_ACCESS(descriptor->input_buffer, descriptor->input_offset, input_bytes, TERMITE_METAL_PLANNED_RANGE_READ);
    TERMITE_PLAN_ACCESS(descriptor->weight_buffer, 0, descriptor->weight_buffer.length, TERMITE_METAL_PLANNED_RANGE_READ);
    TERMITE_PLAN_ACCESS(descriptor->output_buffer, descriptor->output_offset, output_bytes, TERMITE_METAL_PLANNED_RANGE_WRITE);

    if (descriptor->second_weight_buffer != nil) {
        TERMITE_PLAN_ACCESS(descriptor->second_weight_buffer, 0, descriptor->second_weight_buffer.length, TERMITE_METAL_PLANNED_RANGE_READ);
    }
    if (descriptor->third_weight_buffer != nil) {
        TERMITE_PLAN_ACCESS(descriptor->third_weight_buffer, 0, descriptor->third_weight_buffer.length, TERMITE_METAL_PLANNED_RANGE_READ);
    }
    if (descriptor->second_output_buffer != nil) {
        const size_t second_out_dim = descriptor->second_out_dim != 0 ? descriptor->second_out_dim : descriptor->out_dim;
        size_t second_output_bytes = 0;
        if (!termite_metal_size_mul3(descriptor->rows, second_out_dim, termite_metal_quant_matmul_dtype_size(descriptor->output_dtype), &second_output_bytes)) return failure_code;
        TERMITE_PLAN_ACCESS(descriptor->second_output_buffer, descriptor->second_output_offset, second_output_bytes, TERMITE_METAL_PLANNED_RANGE_WRITE);
    }
    if (descriptor->third_output_buffer != nil) {
        const size_t third_out_dim = descriptor->second_out_dim != 0 ? descriptor->second_out_dim : descriptor->out_dim;
        size_t third_output_bytes = 0;
        if (!termite_metal_size_mul3(descriptor->rows, third_out_dim, termite_metal_quant_matmul_dtype_size(descriptor->output_dtype), &third_output_bytes)) return failure_code;
        TERMITE_PLAN_ACCESS(descriptor->third_output_buffer, descriptor->third_output_offset, third_output_bytes, TERMITE_METAL_PLANNED_RANGE_WRITE);
    }
    if (descriptor->rhs_buffer != nil) {
        TERMITE_PLAN_ACCESS(descriptor->rhs_buffer, descriptor->rhs_offset, output_bytes, TERMITE_METAL_PLANNED_RANGE_READ);
    }
    if (descriptor->inv_scale_buffer != nil) {
        TERMITE_PLAN_ACCESS(descriptor->inv_scale_buffer, descriptor->inv_scale_offset, sizeof(float), TERMITE_METAL_PLANNED_RANGE_READ);
    }

#undef TERMITE_PLAN_ACCESS
    return termite_metal_decode_runtime_prepare_planned_compute_accesses(runtime, accesses, count, failure_code);
}

static int termite_metal_encode_quant_matmul_descriptor_on_encoder(
    termite_metal_decode_runtime *runtime,
    id<MTLComputeCommandEncoder> encoder,
    const termite_metal_quant_matmul_descriptor *descriptor
) {
    if (runtime == NULL || encoder == nil || descriptor == NULL) return -1;
    const int failure_code = descriptor->failure_code;
    if (!termite_metal_quant_matmul_descriptor_dtype_supported(runtime, descriptor)) return failure_code;
    if (descriptor->input_buffer == nil || descriptor->weight_buffer == nil || descriptor->output_buffer == nil) return failure_code;
    if (descriptor->rows == 0 || descriptor->in_dim == 0 || descriptor->out_dim == 0) return failure_code;
    if (descriptor->values_per_block == 0 || descriptor->in_dim % descriptor->values_per_block != 0) return failure_code;
    const uint8_t planned_dispatch = termite_metal_quant_matmul_descriptor_planned_dispatch(descriptor);
    if (descriptor->format == TERMITE_METAL_QUANT_FORMAT_Q8_0 &&
        descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_NONE)
    {
        return termite_metal_encode_quant_matmul_none_on_encoder(runtime, encoder, descriptor);
    }
    if (descriptor->format == TERMITE_METAL_QUANT_FORMAT_Q8_0 &&
        descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_PAIR_ACTIVATION_MUL)
    {
        if (descriptor->second_weight_buffer == nil) return failure_code;
        return termite_metal_encode_quant_matmul_pair_activation_mul_on_encoder(runtime, encoder, descriptor);
    }
    if (descriptor->format == TERMITE_METAL_QUANT_FORMAT_Q8_0 &&
        descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_PAIR_ACTIVATION_RMS_SCALE_1X)
    {
        if (descriptor->rows != 1 || descriptor->second_weight_buffer == nil || descriptor->inv_scale_buffer == nil) return failure_code;
        return termite_metal_encode_quant_matmul_pair_activation_rms_scale_1x_on_encoder(runtime, encoder, descriptor);
    }
    if (descriptor->format == TERMITE_METAL_QUANT_FORMAT_Q8_0 &&
        descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_ACTIVATION_RHS_MUL)
    {
        if (descriptor->rhs_buffer == nil) return failure_code;
        (void)planned_dispatch;
        return termite_metal_encode_quant_matmul_activation_rhs_mul_on_encoder(runtime, encoder, descriptor);
    }
    if (descriptor->format == TERMITE_METAL_QUANT_FORMAT_Q8_0 &&
        descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_PAIR)
    {
        if (descriptor->second_weight_buffer == nil || descriptor->second_output_buffer == nil) return failure_code;
        return termite_metal_encode_quant_matmul_pair_on_encoder(runtime, encoder, descriptor);
    }
    if (descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_PAIR) {
        if (descriptor->second_weight_buffer == nil || descriptor->second_output_buffer == nil) return failure_code;
        return termite_metal_encode_quant_matmul_generic_pair_on_encoder(runtime, encoder, descriptor);
    }
    if (descriptor->format == TERMITE_METAL_QUANT_FORMAT_Q8_0 &&
        descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_QKV)
    {
        if (descriptor->second_weight_buffer == nil ||
            descriptor->third_weight_buffer == nil ||
            descriptor->second_output_buffer == nil ||
            descriptor->third_output_buffer == nil ||
            descriptor->second_out_dim == 0) return failure_code;
        return termite_metal_encode_quant_matmul_qkv_on_encoder(runtime, encoder, descriptor);
    }
    if (descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_NONE) {
        return termite_metal_encode_quant_matmul_generic_none_on_encoder(runtime, encoder, descriptor);
    }
    return failure_code;
}

static int termite_metal_encode_quant_matmul_descriptor(
    termite_metal_decode_runtime *runtime,
    id<MTLCommandBuffer> command_buffer,
    const termite_metal_quant_matmul_descriptor *descriptor
) {
    if (runtime == NULL || command_buffer == nil || descriptor == NULL) return -1;
    const int failure_code = descriptor->failure_code;
    if (!termite_metal_quant_matmul_descriptor_dtype_supported(runtime, descriptor)) return failure_code;
    if (descriptor->input_buffer == nil || descriptor->weight_buffer == nil || descriptor->output_buffer == nil) return failure_code;
    if (descriptor->rows == 0 || descriptor->in_dim == 0 || descriptor->out_dim == 0) return failure_code;
    if (descriptor->values_per_block == 0 || descriptor->in_dim % descriptor->values_per_block != 0) return failure_code;
    if (descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_PAIR_ACTIVATION_MUL) {
        if (descriptor->format != TERMITE_METAL_QUANT_FORMAT_Q8_0 || descriptor->second_weight_buffer == nil) return failure_code;
        if (runtime->active_planned_compute_encoder != nil) {
            return termite_metal_encode_quant_matmul_descriptor_on_encoder(runtime, runtime->active_planned_compute_encoder, descriptor);
        }
        id<MTLComputeCommandEncoder> encoder = termite_metal_tracked_compute_command_encoder_for(command_buffer, TERMITE_METAL_COMPUTE_SOURCE_QUANT_PAIR_ACT);
        if (encoder == nil) return failure_code;
        const int rc = termite_metal_encode_quant_matmul_descriptor_on_encoder(runtime, encoder, descriptor);
        [encoder endEncoding];
        return rc;
    }
    if (descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_ACTIVATION_RHS_MUL) {
        if (descriptor->format != TERMITE_METAL_QUANT_FORMAT_Q8_0 || descriptor->rhs_buffer == nil) return failure_code;
        if (runtime->active_planned_compute_encoder != nil) {
            return termite_metal_encode_quant_matmul_descriptor_on_encoder(runtime, runtime->active_planned_compute_encoder, descriptor);
        }
        id<MTLComputeCommandEncoder> encoder = termite_metal_tracked_compute_command_encoder_for(command_buffer, TERMITE_METAL_COMPUTE_SOURCE_QUANT_PAIR_ACT);
        if (encoder == nil) return failure_code;
        const int rc = termite_metal_encode_quant_matmul_descriptor_on_encoder(runtime, encoder, descriptor);
        [encoder endEncoding];
        return rc;
    }
    if (descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_PAIR_ACTIVATION_RMS_SCALE_1X) {
        if (descriptor->format != TERMITE_METAL_QUANT_FORMAT_Q8_0 ||
            descriptor->rows != 1 ||
            descriptor->second_weight_buffer == nil ||
            descriptor->inv_scale_buffer == nil) return failure_code;
        if (runtime->active_planned_compute_encoder != nil) {
            return termite_metal_encode_quant_matmul_descriptor_on_encoder(runtime, runtime->active_planned_compute_encoder, descriptor);
        }
        id<MTLComputeCommandEncoder> encoder = termite_metal_tracked_compute_command_encoder_for(command_buffer, TERMITE_METAL_COMPUTE_SOURCE_QUANT_PAIR_ACT);
        if (encoder == nil) return failure_code;
        const int rc = termite_metal_encode_quant_matmul_descriptor_on_encoder(runtime, encoder, descriptor);
        [encoder endEncoding];
        return rc;
    }
    if (descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_PAIR) {
        if (descriptor->second_weight_buffer == nil ||
            descriptor->second_output_buffer == nil) return failure_code;
        if (runtime->active_planned_compute_encoder != nil) {
            return termite_metal_encode_quant_matmul_descriptor_on_encoder(runtime, runtime->active_planned_compute_encoder, descriptor);
        }
        id<MTLComputeCommandEncoder> encoder = termite_metal_tracked_compute_command_encoder_for(command_buffer, TERMITE_METAL_COMPUTE_SOURCE_QUANT_PAIR_ACT);
        if (encoder == nil) return failure_code;
        const int rc = termite_metal_encode_quant_matmul_descriptor_on_encoder(runtime, encoder, descriptor);
        [encoder endEncoding];
        return rc;
    }
    if (descriptor->epilogue == TERMITE_METAL_QUANT_MATMUL_EPILOGUE_QKV) {
        if (descriptor->format != TERMITE_METAL_QUANT_FORMAT_Q8_0 ||
            descriptor->second_weight_buffer == nil ||
            descriptor->third_weight_buffer == nil ||
            descriptor->second_output_buffer == nil ||
            descriptor->third_output_buffer == nil ||
            descriptor->second_out_dim == 0) return failure_code;
        if (runtime->active_planned_compute_encoder != nil) {
            return termite_metal_encode_quant_matmul_descriptor_on_encoder(runtime, runtime->active_planned_compute_encoder, descriptor);
        }
        id<MTLComputeCommandEncoder> encoder = termite_metal_tracked_compute_command_encoder_for(command_buffer, TERMITE_METAL_COMPUTE_SOURCE_QUANT_QKV);
        if (encoder == nil) return failure_code;
        const int rc = termite_metal_encode_quant_matmul_descriptor_on_encoder(runtime, encoder, descriptor);
        [encoder endEncoding];
        return rc;
    }
    if (descriptor->epilogue != TERMITE_METAL_QUANT_MATMUL_EPILOGUE_NONE) return failure_code;
    id<MTLComputeCommandEncoder> encoder = runtime->active_planned_compute_encoder;
    const BOOL planned_encoder = (encoder != nil);
    if (!planned_encoder) {
        encoder = termite_metal_tracked_compute_command_encoder_for(command_buffer, TERMITE_METAL_COMPUTE_SOURCE_QUANT_LINEAR);
        if (encoder == nil) return failure_code;
    }
    const int rc = termite_metal_encode_quant_matmul_descriptor_on_encoder(runtime, encoder, descriptor);
    if (!planned_encoder) [encoder endEncoding];
    return rc;
}

static int termite_metal_decode_runtime_apply_quantized_linear_slot_device_direct(
    termite_metal_decode_runtime *runtime,
    size_t slot,
    void *input_handle,
    size_t input_offset,
    size_t rows,
    size_t in_dim,
    size_t out_dim,
    void *output_handle,
    size_t output_offset,
    id<MTLComputePipelineState> pipeline,
    id<MTLBuffer> weight_buffer,
    uint8_t slot_prepared,
    size_t slot_in_dim,
    size_t slot_out_dim,
    uint32_t format,
    size_t values_per_block,
    size_t bytes_per_block
) {
    if (runtime == NULL || input_handle == NULL || output_handle == NULL) return -1;
    if (pipeline == nil || weight_buffer == nil) return -2;
    if (slot_prepared == 0) return -3;
    if (slot_in_dim != in_dim || slot_out_dim != out_dim) return -4;
    if (rows == 0 || in_dim == 0 || out_dim == 0) return -5;
    if (rows > UINT32_MAX || in_dim > UINT32_MAX || out_dim > UINT32_MAX) return -6;
    if (termite_metal_decode_runtime_check_quant_linear_descriptor(runtime, slot, format, values_per_block, bytes_per_block, in_dim) != 0) return -7;
    @autoreleasepool {
        id<MTLBuffer> input_buffer = (__bridge id<MTLBuffer>)input_handle;
        id<MTLBuffer> output_buffer = (__bridge id<MTLBuffer>)output_handle;
        const size_t input_bytes = rows * in_dim * sizeof(float);
        const size_t output_bytes = rows * out_dim * sizeof(float);
        if (input_offset + input_bytes > input_buffer.length) return -8;
        if (output_offset + output_bytes > output_buffer.length) return -9;
        bool frame_owned = true;
        id<MTLCommandBuffer> command_buffer = termite_metal_decode_runtime_command_buffer(runtime, __func__, &frame_owned);
        if (command_buffer == nil) return -10;
        termite_metal_quant_matmul_descriptor descriptor = {
            .slot = slot,
            .format = format,
            .activation_dtype = TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32,
            .epilogue = TERMITE_METAL_QUANT_MATMUL_EPILOGUE_NONE,
            .fallback_pipeline = pipeline,
            .input_buffer = input_buffer,
            .input_offset = input_offset,
            .weight_buffer = weight_buffer,
            .output_buffer = output_buffer,
            .output_offset = output_offset,
            .rows = rows,
            .in_dim = in_dim,
            .out_dim = out_dim,
            .values_per_block = values_per_block,
            .bytes_per_block = bytes_per_block,
            .failure_code = -11,
        };
        if (termite_metal_encode_quant_matmul_descriptor(runtime, command_buffer, &descriptor) != 0) return -11;
        return termite_metal_decode_runtime_finish_command_buffer(command_buffer, frame_owned, -12);
    }
}

int termite_metal_decode_runtime_apply_quantized_linear_slot_device(
    termite_metal_decode_runtime *runtime,
    uint32_t format,
    size_t slot,
    void *input_handle,
    size_t input_offset,
    size_t rows,
    size_t in_dim,
    size_t out_dim,
    void *output_handle,
    size_t output_offset
);

int termite_metal_decode_runtime_apply_quantized_linear_slot_host(
    termite_metal_decode_runtime *runtime,
    uint32_t format,
    size_t slot,
    const float *input,
    size_t rows,
    size_t in_dim,
    size_t out_dim,
    float *output
) {
    if (runtime == NULL || input == NULL || output == NULL) return -1;
    if (slot >= TERMITE_METAL_LINEAR_SLOT_CAPACITY || rows == 0 || in_dim == 0 || out_dim == 0) return -3;
    termite_metal_quant_linear_slot_view view;
    if (termite_metal_decode_runtime_require_quant_linear_slot(runtime, format, slot, in_dim, out_dim, &view) != 0) return -4;
    if (rows > UINT32_MAX || in_dim > UINT32_MAX || out_dim > UINT32_MAX) return -6;
    @autoreleasepool {
        const size_t input_bytes = rows * in_dim * sizeof(float);
        const size_t output_bytes = rows * out_dim * sizeof(float);
        id<MTLBuffer> input_buffer = [runtime->device newBufferWithBytesNoCopy:(void *)input length:input_bytes options:MTLResourceStorageModeShared deallocator:nil];
        if (input_buffer == nil) input_buffer = [runtime->device newBufferWithBytes:input length:input_bytes options:MTLResourceStorageModeShared];
        id<MTLBuffer> output_buffer = [runtime->device newBufferWithBytesNoCopy:output length:output_bytes options:MTLResourceStorageModeShared deallocator:nil];
        if (output_buffer == nil) output_buffer = [runtime->device newBufferWithBytes:output length:output_bytes options:MTLResourceStorageModeShared];
        if (input_buffer == nil || output_buffer == nil) return -7;
        if (format == TERMITE_METAL_QUANT_FORMAT_TL1 || format == TERMITE_METAL_QUANT_FORMAT_TL2) {
            return termite_metal_decode_runtime_apply_quantized_linear_slot_device(
                runtime,
                format,
                slot,
                (__bridge void *)input_buffer,
                0,
                rows,
                in_dim,
                out_dim,
                (__bridge void *)output_buffer,
                0
            );
        }
        bool frame_owned = true;
        id<MTLCommandBuffer> command_buffer = termite_metal_decode_runtime_command_buffer(runtime, __func__, &frame_owned);
        if (command_buffer == nil) return -8;
        termite_metal_quant_matmul_descriptor descriptor = {
            .slot = slot,
            .format = format,
            .activation_dtype = TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32,
            .epilogue = TERMITE_METAL_QUANT_MATMUL_EPILOGUE_NONE,
            .fallback_pipeline = view.pipeline,
            .input_buffer = input_buffer,
            .input_offset = 0,
            .weight_buffer = view.weight_buffer,
            .output_buffer = output_buffer,
            .output_offset = 0,
            .rows = rows,
            .in_dim = in_dim,
            .out_dim = out_dim,
            .values_per_block = view.values_per_block,
            .bytes_per_block = view.bytes_per_block,
            .failure_code = -9,
        };
        if (termite_metal_encode_quant_matmul_descriptor(runtime, command_buffer, &descriptor) != 0) return -9;
        return termite_metal_decode_runtime_finish_command_buffer(command_buffer, frame_owned, -10);
    }
}

static termite_metal_quant_matmul_dispatch_kind termite_metal_select_quant_matmul_dispatch(
    uint32_t format,
    size_t rows,
    size_t in_dim,
    size_t out_dim,
    size_t values_per_block
) {
    if (format == TERMITE_METAL_QUANT_FORMAT_UNSUPPORTED ||
        rows == 0 ||
        in_dim == 0 ||
        out_dim == 0 ||
        values_per_block == 0 ||
        in_dim % values_per_block != 0) {
        return TERMITE_METAL_QUANT_MATMUL_DISPATCH_SCALAR;
    }
    if (rows >= 2 && rows <= 8) return TERMITE_METAL_QUANT_MATMUL_DISPATCH_SMALL_BATCH;
    if (rows >= 9u) return TERMITE_METAL_QUANT_MATMUL_DISPATCH_MM;
    return TERMITE_METAL_QUANT_MATMUL_DISPATCH_MMV;
}

static bool termite_metal_quant_matmul_dispatch_valid_for_shape(
    termite_metal_quant_matmul_dispatch_kind dispatch_kind,
    uint32_t format,
    size_t rows,
    size_t in_dim,
    size_t out_dim,
    size_t values_per_block
) {
    if (format == TERMITE_METAL_QUANT_FORMAT_UNSUPPORTED ||
        rows == 0 ||
        in_dim == 0 ||
        out_dim == 0 ||
        values_per_block == 0 ||
        in_dim % values_per_block != 0) {
        return dispatch_kind == TERMITE_METAL_QUANT_MATMUL_DISPATCH_SCALAR;
    }
    switch (dispatch_kind) {
        case TERMITE_METAL_QUANT_MATMUL_DISPATCH_SCALAR:
            return true;
        case TERMITE_METAL_QUANT_MATMUL_DISPATCH_MMV:
            return rows == 1;
        case TERMITE_METAL_QUANT_MATMUL_DISPATCH_SMALL_BATCH:
            return rows >= 2 && rows <= 8;
        case TERMITE_METAL_QUANT_MATMUL_DISPATCH_MM:
            return rows >= 9;
    }
    return false;
}

static termite_metal_quant_matmul_dispatch_kind termite_metal_select_quant_matmul_dispatch_preferred(
    uint32_t format,
    size_t rows,
    size_t in_dim,
    size_t out_dim,
    size_t values_per_block,
    uint8_t preferred_dispatch
) {
    if (preferred_dispatch <= (uint8_t)TERMITE_METAL_QUANT_MATMUL_DISPATCH_MM) {
        const termite_metal_quant_matmul_dispatch_kind preferred = (termite_metal_quant_matmul_dispatch_kind)preferred_dispatch;
        if (termite_metal_quant_matmul_dispatch_valid_for_shape(preferred, format, rows, in_dim, out_dim, values_per_block)) {
            return preferred;
        }
    }
    return termite_metal_select_quant_matmul_dispatch(format, rows, in_dim, out_dim, values_per_block);
}

static termite_metal_quant_matmul_primitive_kind termite_metal_quant_matmul_primitive_for_dispatch(
    termite_metal_quant_matmul_dispatch_kind dispatch_kind
) {
    switch (dispatch_kind) {
        case TERMITE_METAL_QUANT_MATMUL_DISPATCH_MMV:
            return TERMITE_METAL_QUANT_MATMUL_PRIMITIVE_QGEMV;
        case TERMITE_METAL_QUANT_MATMUL_DISPATCH_SMALL_BATCH:
            return TERMITE_METAL_QUANT_MATMUL_PRIMITIVE_QGEMV_BATCH;
        case TERMITE_METAL_QUANT_MATMUL_DISPATCH_MM:
            return TERMITE_METAL_QUANT_MATMUL_PRIMITIVE_QMATMUL;
        case TERMITE_METAL_QUANT_MATMUL_DISPATCH_SCALAR:
            return TERMITE_METAL_QUANT_MATMUL_PRIMITIVE_SCALAR;
    }
    return TERMITE_METAL_QUANT_MATMUL_PRIMITIVE_SCALAR;
}

static termite_metal_q8_0_linear_dispatch_kind termite_metal_q8_0_dispatch_from_quant_dispatch(
    termite_metal_quant_matmul_dispatch_kind dispatch_kind
) {
    switch (dispatch_kind) {
        case TERMITE_METAL_QUANT_MATMUL_DISPATCH_MMV:
            return TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MMV;
        case TERMITE_METAL_QUANT_MATMUL_DISPATCH_SMALL_BATCH:
            return TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SMALL_BATCH;
        case TERMITE_METAL_QUANT_MATMUL_DISPATCH_MM:
            return TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM;
        case TERMITE_METAL_QUANT_MATMUL_DISPATCH_SCALAR:
            return TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SCALAR;
    }
    return TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SCALAR;
}

static void termite_metal_record_q8_0_linear_dispatch(
    termite_metal_decode_runtime *runtime,
    termite_metal_q8_0_linear_dispatch_kind dispatch_kind,
    size_t rows,
    termite_metal_q8_0_linear_family_kind family
) {
    if (runtime == NULL) return;
    switch (dispatch_kind) {
        case TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SCALAR:
            runtime->q8_0_linear_dispatch_scalar += 1;
            break;
        case TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MMV:
            runtime->q8_0_linear_dispatch_mmv += 1;
            break;
        case TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SMALL_BATCH:
            runtime->q8_0_linear_dispatch_small_batch += 1;
            break;
        case TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM:
            runtime->q8_0_linear_dispatch_mm += 1;
            break;
    }
    if (rows == 1) {
        runtime->q8_0_linear_rows_1 += 1;
    } else if (rows <= 8) {
        runtime->q8_0_linear_rows_2_8 += 1;
    } else if (rows <= 64) {
        runtime->q8_0_linear_rows_9_64 += 1;
    } else {
        runtime->q8_0_linear_rows_65_plus += 1;
    }
    const size_t family_index = (size_t)family;
    const size_t dispatch_index = (size_t)dispatch_kind;
    if (family_index < TERMITE_METAL_Q8_0_LINEAR_FAMILY_COUNT &&
        dispatch_index < TERMITE_METAL_Q8_0_LINEAR_DISPATCH_COUNT) {
        runtime->q8_0_linear_family_dispatch_counts[family_index][dispatch_index] += 1;
    }
}

static int termite_metal_encode_quant_matmul_none_on_encoder_family(
    termite_metal_decode_runtime *runtime,
    id<MTLComputeCommandEncoder> encoder,
    const termite_metal_quant_matmul_descriptor *descriptor,
    termite_metal_q8_0_linear_family_kind family
) {
    if (runtime == NULL || encoder == nil || descriptor == NULL) return -1;
    const int failure_code = descriptor->failure_code;
    if (descriptor->activation_dtype != TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32 ||
        descriptor->epilogue != TERMITE_METAL_QUANT_MATMUL_EPILOGUE_NONE ||
        descriptor->input_buffer == nil ||
        descriptor->weight_buffer == nil ||
        descriptor->output_buffer == nil) return failure_code;
    if (descriptor->rows == 0 ||
        descriptor->in_dim == 0 ||
        descriptor->out_dim == 0 ||
        descriptor->values_per_block == 0 ||
        descriptor->in_dim % descriptor->values_per_block != 0) return failure_code;
    const BOOL q8_0_format =
        descriptor->format == TERMITE_METAL_QUANT_FORMAT_Q8_0 &&
        descriptor->values_per_block == 32u &&
        descriptor->bytes_per_block == 34u;
    if (!q8_0_format && descriptor->fallback_pipeline == nil) return failure_code;

    termite_metal_linear_params params = {
        .rows = (uint32_t)descriptor->rows,
        .in_dim = (uint32_t)descriptor->in_dim,
        .out_dim = (uint32_t)descriptor->out_dim,
        .row_blocks = (uint32_t)(descriptor->in_dim / descriptor->values_per_block),
    };
    const uint8_t planned_dispatch = termite_metal_quant_matmul_descriptor_planned_dispatch(descriptor);
    const termite_metal_quant_matmul_dispatch_kind quant_dispatch_kind = termite_metal_select_quant_matmul_dispatch_preferred(
        descriptor->format,
        descriptor->rows,
        descriptor->in_dim,
        descriptor->out_dim,
        descriptor->values_per_block,
        planned_dispatch);
    const termite_metal_q8_0_linear_dispatch_kind dispatch_kind =
        termite_metal_q8_0_dispatch_from_quant_dispatch(quant_dispatch_kind);
    (void)termite_metal_quant_matmul_primitive_for_dispatch(quant_dispatch_kind);
    const BOOL f32_activation_buffers =
        descriptor->input_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32 &&
        descriptor->output_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32;
    const BOOL use_mm_f16_input = (q8_0_format &&
        descriptor->input_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F16 &&
        descriptor->output_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32 &&
        runtime->q8_0_mm_f16_input_pipeline != nil &&
        dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM);
    const BOOL use_mmv_f16_input = (!use_mm_f16_input &&
        q8_0_format &&
        descriptor->input_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F16 &&
        descriptor->output_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32 &&
        runtime->q8_0_mmv_f16_input_pipeline != nil &&
        (dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MMV ||
            dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SCALAR));
    if (!f32_activation_buffers && !use_mm_f16_input && !use_mmv_f16_input) return failure_code;
    const BOOL use_mm_sg = (q8_0_format &&
        f32_activation_buffers &&
        descriptor->rows >= 65u &&
        runtime->q8_0_mm_sg_pipeline != nil &&
        dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM);
    const BOOL use_mm = (!use_mm_sg && !use_mm_f16_input && q8_0_format && f32_activation_buffers && runtime->q8_0_mm_pipeline != nil && dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM);
    id<MTLComputePipelineState> small_batch_pipeline = runtime->q8_0_small_batch_pipeline;
    size_t small_batch_rows_per_tg = 5u;
    if (descriptor->rows <= 2u && runtime->q8_0_small_batch_r2_pipeline != nil) {
        small_batch_pipeline = runtime->q8_0_small_batch_r2_pipeline;
        small_batch_rows_per_tg = 2u;
    } else if (descriptor->rows == 3u && runtime->q8_0_small_batch_r3_pipeline != nil) {
        small_batch_pipeline = runtime->q8_0_small_batch_r3_pipeline;
        small_batch_rows_per_tg = 3u;
    } else if (descriptor->rows == 4u && runtime->q8_0_small_batch_r4_pipeline != nil) {
        small_batch_pipeline = runtime->q8_0_small_batch_r4_pipeline;
        small_batch_rows_per_tg = 4u;
    }
    const BOOL use_small_batch = (q8_0_format &&
        f32_activation_buffers &&
        !use_mm_sg &&
        !use_mm &&
        !use_mm_f16_input &&
        small_batch_pipeline != nil &&
        descriptor->rows > 1 &&
        (dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SMALL_BATCH ||
            dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM));
    const BOOL use_mmv = (!use_mm_sg &&
        !use_mm &&
        !use_mm_f16_input &&
        q8_0_format &&
        f32_activation_buffers &&
        !use_small_batch &&
        runtime->q8_0_mmv_pipeline != nil &&
        (dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MMV ||
            dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM));
    const termite_metal_q8_0_linear_dispatch_kind actual_kind = (use_mm_sg || use_mm || use_mm_f16_input)
        ? TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM
        : (use_small_batch
            ? TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SMALL_BATCH
            : ((use_mmv || use_mmv_f16_input)
                ? TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MMV
                : TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SCALAR));
    if (q8_0_format) {
        if (use_mm_f16_input) runtime->q8_0_linear_mm_f16_input += 1;
        if (use_mmv_f16_input) runtime->q8_0_linear_mmv_f16_input += 1;
        termite_metal_record_q8_0_linear_dispatch(runtime, actual_kind, descriptor->rows, family);
    }
    id<MTLComputePipelineState> scalar_pipeline = descriptor->fallback_pipeline != nil
        ? descriptor->fallback_pipeline
        : runtime->q8_0_pipeline;
    id<MTLComputePipelineState> pipeline = use_mm_sg
        ? runtime->q8_0_mm_sg_pipeline
        : (use_mm_f16_input
            ? runtime->q8_0_mm_f16_input_pipeline
        : (use_mm
            ? runtime->q8_0_mm_pipeline
        : (use_mmv_f16_input
            ? runtime->q8_0_mmv_f16_input_pipeline
        : (use_mmv
            ? runtime->q8_0_mmv_pipeline
            : (use_small_batch
                ? small_batch_pipeline
                : scalar_pipeline)))));
    if (pipeline == nil) return failure_code;
    [encoder setComputePipelineState:pipeline];
    [encoder setBuffer:descriptor->input_buffer offset:descriptor->input_offset atIndex:0];
    [encoder setBuffer:descriptor->weight_buffer offset:0 atIndex:1];
    [encoder setBuffer:descriptor->output_buffer offset:descriptor->output_offset atIndex:2];
    [encoder setBytes:&params length:sizeof(params) atIndex:3];
    if (use_mm_sg) {
        [encoder setThreadgroupMemoryLength:8192u atIndex:0];
        [encoder dispatchThreadgroups:MTLSizeMake((descriptor->out_dim + 63u) / 64u, (descriptor->rows + 31u) / 32u, 1) threadsPerThreadgroup:MTLSizeMake(128, 1, 1)];
    } else if (use_mm || use_mm_f16_input) {
        [encoder dispatchThreadgroups:MTLSizeMake((descriptor->out_dim + 31u) / 32u, (descriptor->rows + 7u) / 8u, 1) threadsPerThreadgroup:MTLSizeMake(128, 1, 1)];
    } else if (use_mmv || use_mmv_f16_input) {
        [encoder setThreadgroupMemoryLength:64u * sizeof(float) atIndex:0];
        [encoder dispatchThreadgroups:MTLSizeMake((descriptor->out_dim + 1u) / 2u, descriptor->rows, 1) threadsPerThreadgroup:MTLSizeMake(128, 1, 1)];
    } else if (use_small_batch) {
        [encoder dispatchThreadgroups:MTLSizeMake((descriptor->out_dim + 15u) / 16u, (descriptor->rows + small_batch_rows_per_tg - 1u) / small_batch_rows_per_tg, 1) threadsPerThreadgroup:MTLSizeMake(128, 1, 1)];
    } else {
        const size_t total = descriptor->rows * descriptor->out_dim;
        [encoder dispatchThreads:MTLSizeMake(total, 1, 1) threadsPerThreadgroup:MTLSizeMake(termite_metal_thread_width(pipeline, total), 1, 1)];
    }
    return 0;
}

static int termite_metal_encode_quant_matmul_none_on_encoder(
    termite_metal_decode_runtime *runtime,
    id<MTLComputeCommandEncoder> encoder,
    const termite_metal_quant_matmul_descriptor *descriptor
) {
    if (runtime == NULL || encoder == nil || descriptor == NULL) return -1;
    const int failure_code = descriptor->failure_code;
    if (termite_metal_prepare_quant_matmul_accesses(runtime, descriptor, failure_code) != 0) return failure_code;
    const termite_metal_q8_0_linear_family_kind family =
        descriptor->q8_family;
    return termite_metal_encode_quant_matmul_none_on_encoder_family(
        runtime,
        encoder,
        descriptor,
        family);
}

static int termite_metal_encode_quant_matmul_pair_activation_mul_on_encoder(
    termite_metal_decode_runtime *runtime,
    id<MTLComputeCommandEncoder> encoder,
    const termite_metal_quant_matmul_descriptor *descriptor
) {
    if (runtime == NULL || encoder == nil || descriptor == NULL) return -1;
    const int failure_code = descriptor->failure_code;
    if (descriptor->activation_dtype != TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32 ||
        descriptor->epilogue != TERMITE_METAL_QUANT_MATMUL_EPILOGUE_PAIR_ACTIVATION_MUL ||
        descriptor->input_buffer == nil ||
        descriptor->weight_buffer == nil ||
        descriptor->second_weight_buffer == nil ||
        descriptor->output_buffer == nil) return failure_code;
    if (descriptor->rows == 0 ||
        descriptor->in_dim == 0 ||
        descriptor->out_dim == 0 ||
        descriptor->values_per_block == 0 ||
        descriptor->in_dim % descriptor->values_per_block != 0) return failure_code;
    if (descriptor->format != TERMITE_METAL_QUANT_FORMAT_Q8_0 ||
        descriptor->values_per_block != 32u ||
        descriptor->bytes_per_block != 34u) return failure_code;
    if (termite_metal_prepare_quant_matmul_accesses(runtime, descriptor, failure_code) != 0) return failure_code;

    const uint8_t planned_dispatch = termite_metal_quant_matmul_descriptor_planned_dispatch(descriptor);
    const termite_metal_q8_0_linear_dispatch_kind dispatch_kind = termite_metal_q8_0_dispatch_from_quant_dispatch(
        termite_metal_select_quant_matmul_dispatch_preferred(
            descriptor->format,
            descriptor->rows,
            descriptor->in_dim,
            descriptor->out_dim,
            descriptor->values_per_block,
            planned_dispatch));
    const BOOL f32_activation_buffers =
        descriptor->input_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32 &&
        descriptor->output_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32;
    const BOOL use_mm_f16_output = (descriptor->input_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32 &&
        descriptor->output_dtype == TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F16 &&
        runtime->q8_0_pair_activation_mm_f16_output_pipeline != nil &&
        dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM);
    if (!f32_activation_buffers && !use_mm_f16_output) return failure_code;
    const BOOL use_mm_sg = (descriptor->rows >= TERMITE_METAL_Q8_0_PAIR_ACTIVATION_SPLIT_MM_SG_MIN_ROWS &&
        f32_activation_buffers &&
        runtime->q8_0_pair_activation_mm_pipeline == nil &&
        runtime->q8_0_mm_sg_pipeline != nil &&
        runtime->activation_multiply_pipeline != nil &&
        dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM);
    if (use_mm_sg) {
        if (descriptor->rows > UINT32_MAX || descriptor->in_dim > UINT32_MAX || descriptor->out_dim > UINT32_MAX) return failure_code;
        if (descriptor->rows > SIZE_MAX / descriptor->out_dim) return failure_code;
        const size_t total = descriptor->rows * descriptor->out_dim;
        if (total > UINT32_MAX || total > SIZE_MAX / sizeof(float)) return failure_code;
        const size_t intermediate_bytes = total * sizeof(float);
        if (descriptor->output_offset > descriptor->output_buffer.length ||
            intermediate_bytes > descriptor->output_buffer.length - descriptor->output_offset) return failure_code;
        if (termite_metal_decode_runtime_ensure_hot_buffers(runtime, 0, intermediate_bytes) != 0) return failure_code;
        id<MTLBuffer> gate_output_buffer = runtime->hot_intermediate_buffers[0];
        id<MTLBuffer> up_output_buffer = runtime->hot_intermediate_buffers[1];
        if (gate_output_buffer == nil || up_output_buffer == nil) return failure_code;
        if (intermediate_bytes > gate_output_buffer.length || intermediate_bytes > up_output_buffer.length) return failure_code;

        termite_metal_linear_params params = {
            .rows = (uint32_t)descriptor->rows,
            .in_dim = (uint32_t)descriptor->in_dim,
            .out_dim = (uint32_t)descriptor->out_dim,
            .row_blocks = (uint32_t)(descriptor->in_dim / descriptor->values_per_block),
        };
        termite_metal_apply_activation_params activation_params = {
            .activation_kind = descriptor->activation_kind,
            .rows = (uint32_t)descriptor->rows,
            .dim = (uint32_t)descriptor->out_dim,
        };
        termite_metal_record_q8_0_linear_dispatch(
            runtime,
            TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM,
            descriptor->rows,
            TERMITE_METAL_Q8_0_LINEAR_FAMILY_PAIR_ACTIVATION);
        termite_metal_record_q8_0_linear_dispatch(
            runtime,
            TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM,
            descriptor->rows,
            TERMITE_METAL_Q8_0_LINEAR_FAMILY_PAIR_ACTIVATION);

        [encoder setComputePipelineState:runtime->q8_0_mm_sg_pipeline];
        [encoder setBuffer:descriptor->input_buffer offset:descriptor->input_offset atIndex:0];
        [encoder setBuffer:descriptor->weight_buffer offset:0 atIndex:1];
        [encoder setBuffer:gate_output_buffer offset:0 atIndex:2];
        [encoder setBytes:&params length:sizeof(params) atIndex:3];
        [encoder setThreadgroupMemoryLength:8192u atIndex:0];
        [encoder dispatchThreadgroups:MTLSizeMake((descriptor->out_dim + 63u) / 64u, (descriptor->rows + 31u) / 32u, 1) threadsPerThreadgroup:MTLSizeMake(128, 1, 1)];

        [encoder setComputePipelineState:runtime->q8_0_mm_sg_pipeline];
        [encoder setBuffer:descriptor->input_buffer offset:descriptor->input_offset atIndex:0];
        [encoder setBuffer:descriptor->second_weight_buffer offset:0 atIndex:1];
        [encoder setBuffer:up_output_buffer offset:0 atIndex:2];
        [encoder setBytes:&params length:sizeof(params) atIndex:3];
        [encoder setThreadgroupMemoryLength:8192u atIndex:0];
        [encoder dispatchThreadgroups:MTLSizeMake((descriptor->out_dim + 63u) / 64u, (descriptor->rows + 31u) / 32u, 1) threadsPerThreadgroup:MTLSizeMake(128, 1, 1)];

        [encoder memoryBarrierWithScope:MTLBarrierScopeBuffers];
        [encoder setComputePipelineState:runtime->activation_multiply_pipeline];
        [encoder setBuffer:gate_output_buffer offset:0 atIndex:0];
        [encoder setBuffer:up_output_buffer offset:0 atIndex:1];
        [encoder setBuffer:descriptor->output_buffer offset:descriptor->output_offset atIndex:2];
        [encoder setBytes:&activation_params length:sizeof(activation_params) atIndex:3];
        [encoder dispatchThreads:MTLSizeMake(total, 1, 1)
           threadsPerThreadgroup:MTLSizeMake(termite_metal_thread_width(runtime->activation_multiply_pipeline, total), 1, 1)];
        return 0;
    }

    const BOOL use_mm = (!use_mm_f16_output && f32_activation_buffers && runtime->q8_0_pair_activation_mm_pipeline != nil && dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM);
    const BOOL use_mmv = (!use_mm &&
        !use_mm_f16_output &&
        f32_activation_buffers &&
        runtime->q8_0_pair_activation_mmv_pipeline != nil &&
        dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MMV);
    id<MTLComputePipelineState> small_batch_pipeline = runtime->q8_0_pair_activation_small_batch_pipeline;
    size_t small_batch_rows_per_tg = 5u;
    if (descriptor->rows <= 2u && runtime->q8_0_pair_activation_small_batch_r2_pipeline != nil) {
        small_batch_pipeline = runtime->q8_0_pair_activation_small_batch_r2_pipeline;
        small_batch_rows_per_tg = 2u;
    } else if (descriptor->rows == 3u && runtime->q8_0_pair_activation_small_batch_r3_pipeline != nil) {
        small_batch_pipeline = runtime->q8_0_pair_activation_small_batch_r3_pipeline;
        small_batch_rows_per_tg = 3u;
    } else if (descriptor->rows == 4u && runtime->q8_0_pair_activation_small_batch_r4_pipeline != nil) {
        small_batch_pipeline = runtime->q8_0_pair_activation_small_batch_r4_pipeline;
        small_batch_rows_per_tg = 4u;
    }
    const BOOL use_small_batch = (!use_mm &&
        !use_mm_f16_output &&
        f32_activation_buffers &&
        !use_mmv &&
        small_batch_pipeline != nil &&
        descriptor->rows > 1 &&
        (dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SMALL_BATCH ||
            dispatch_kind == TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM));
    id<MTLComputePipelineState> scalar_pipeline = descriptor->fallback_pipeline != nil
        ? descriptor->fallback_pipeline
        : runtime->q8_0_pair_activation_reduce_pipeline;
    id<MTLComputePipelineState> pipeline = use_mm
        ? runtime->q8_0_pair_activation_mm_pipeline
        : (use_mm_f16_output
            ? runtime->q8_0_pair_activation_mm_f16_output_pipeline
        : (use_mmv
            ? runtime->q8_0_pair_activation_mmv_pipeline
            : (use_small_batch
                ? small_batch_pipeline
                : scalar_pipeline)));
    if (pipeline == nil) return failure_code;
    const termite_metal_q8_0_linear_dispatch_kind actual_kind = (use_mm || use_mm_f16_output)
        ? TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MM
        : (use_small_batch
            ? TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SMALL_BATCH
            : (use_mmv
                ? TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MMV
                : TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SCALAR));
    termite_metal_record_q8_0_linear_dispatch(
        runtime,
        actual_kind,
        descriptor->rows,
        TERMITE_METAL_Q8_0_LINEAR_FAMILY_PAIR_ACTIVATION);
    if (use_mm_f16_output) runtime->q8_0_pair_activation_mm_f16_output += 1;
    termite_metal_linear_params params = {
        .rows = (uint32_t)descriptor->rows,
        .in_dim = (uint32_t)descriptor->in_dim,
        .out_dim = (uint32_t)descriptor->out_dim,
        .row_blocks = (uint32_t)(descriptor->in_dim / descriptor->values_per_block),
    };
    termite_metal_apply_activation_params activation_params = {
