    } else {
        [encoder setThreadgroupMemoryLength:256u * sizeof(float) atIndex:0];
        [encoder dispatchThreadgroups:MTLSizeMake((descriptor->out_dim + 3u) / 4u, descriptor->rows, 1) threadsPerThreadgroup:MTLSizeMake(128, 1, 1)];
