        descriptor->bytes_per_block != 34u) return failure_code;
    if (termite_metal_prepare_quant_matmul_accesses(runtime, descriptor, failure_code) != 0) return failure_code;
    if (descriptor->rows >= 9u && runtime->q8_0_mm_pipeline != nil) {
        termite_metal_quant_matmul_descriptor first = *descriptor;
        first.epilogue = TERMITE_METAL_QUANT_MATMUL_EPILOGUE_NONE;
        first.second_weight_buffer = nil;
        first.third_weight_buffer = nil;
        first.second_output_buffer = nil;
        first.third_output_buffer = nil;
        first.second_out_dim = 0;
        int rc = termite_metal_encode_quant_matmul_none_on_encoder_family(
            runtime,
            encoder,
            &first,
            TERMITE_METAL_Q8_0_LINEAR_FAMILY_PAIR);
        if (rc != 0) return rc;
        termite_metal_quant_matmul_descriptor second = first;
        second.weight_buffer = descriptor->second_weight_buffer;
        second.output_buffer = descriptor->second_output_buffer;
        second.output_offset = descriptor->second_output_offset;
        return termite_metal_encode_quant_matmul_none_on_encoder_family(
            runtime,
            encoder,
            &second,
            TERMITE_METAL_Q8_0_LINEAR_FAMILY_PAIR);
    }
    termite_metal_linear_params params = {
        .rows = (uint32_t)descriptor->rows,
        .in_dim = (uint32_t)descriptor->in_dim,
        .out_dim = (uint32_t)descriptor->out_dim,
        .row_blocks = (uint32_t)(descriptor->in_dim / descriptor->values_per_block),
    };
    const uint8_t planned_dispatch = termite_metal_quant_matmul_descriptor_planned_dispatch(descriptor);
    const termite_metal_q8_0_linear_dispatch_kind dispatch_kind = termite_metal_q8_0_dispatch_from_quant_dispatch(
        termite_metal_select_quant_matmul_dispatch_preferred(
            descriptor->format,
            descriptor->rows,
            descriptor->in_dim,
            descriptor->out_dim,
            descriptor->values_per_block,
            planned_dispatch));
    id<MTLComputePipelineState> small_batch_pipeline = runtime->q8_0_pair_small_batch_pipeline;
    size_t small_batch_rows_per_tg = 5u;
    if (descriptor->rows <= 2u && runtime->q8_0_pair_small_batch_r2_pipeline != nil) {
        small_batch_pipeline = runtime->q8_0_pair_small_batch_r2_pipeline;
        small_batch_rows_per_tg = 2u;
    } else if (descriptor->rows == 3u && runtime->q8_0_pair_small_batch_r3_pipeline != nil) {
        small_batch_pipeline = runtime->q8_0_pair_small_batch_r3_pipeline;
        small_batch_rows_per_tg = 3u;
    } else if (descriptor->rows == 4u && runtime->q8_0_pair_small_batch_r4_pipeline != nil) {
        small_batch_pipeline = runtime->q8_0_pair_small_batch_r4_pipeline;
        small_batch_rows_per_tg = 4u;
    }
    const BOOL use_small_batch = (small_batch_pipeline != nil &&
        descriptor->rows > 1 &&
        dispatch_kind != TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SCALAR);
    const BOOL use_mmv = (!use_small_batch && runtime->q8_0_pair_mmv_pipeline != nil);
    id<MTLComputePipelineState> scalar_pipeline = descriptor->fallback_pipeline != nil
        ? descriptor->fallback_pipeline
        : runtime->q8_0_pair_pipeline;
    id<MTLComputePipelineState> pipeline = use_small_batch
        ? small_batch_pipeline
        : (use_mmv
            ? runtime->q8_0_pair_mmv_pipeline
            : scalar_pipeline);
    if (pipeline == nil) return failure_code;
    const termite_metal_q8_0_linear_dispatch_kind actual_kind = use_small_batch
        ? TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SMALL_BATCH
        : (use_mmv
            ? TERMITE_METAL_Q8_0_LINEAR_DISPATCH_MMV
            : TERMITE_METAL_Q8_0_LINEAR_DISPATCH_SCALAR);
    termite_metal_record_q8_0_linear_dispatch(
        runtime,
        actual_kind,
        descriptor->rows,
        TERMITE_METAL_Q8_0_LINEAR_FAMILY_PAIR);
    [encoder setComputePipelineState:pipeline];
    [encoder setBuffer:descriptor->input_buffer offset:descriptor->input_offset atIndex:0];
    [encoder setBuffer:descriptor->weight_buffer offset:0 atIndex:1];
    [encoder setBuffer:descriptor->second_weight_buffer offset:0 atIndex:2];
    [encoder setBuffer:descriptor->output_buffer offset:descriptor->output_offset atIndex:3];
    [encoder setBuffer:descriptor->second_output_buffer offset:descriptor->second_output_offset atIndex:4];
    [encoder setBytes:&params length:sizeof(params) atIndex:5];
    if (use_small_batch) {
        [encoder dispatchThreadgroups:MTLSizeMake((descriptor->out_dim + 15u) / 16u, (descriptor->rows + small_batch_rows_per_tg - 1u) / small_batch_rows_per_tg, 1) threadsPerThreadgroup:MTLSizeMake(128, 1, 1)];
    } else if (use_mmv) {
        [encoder setThreadgroupMemoryLength:128u * sizeof(float) atIndex:0];
        [encoder dispatchThreadgroups:MTLSizeMake((descriptor->out_dim + 1u) / 2u, descriptor->rows, 1) threadsPerThreadgroup:MTLSizeMake(128, 1, 1)];
    } else {
        const size_t total = descriptor->rows * descriptor->out_dim;
        [encoder dispatchThreads:MTLSizeMake(total, 1, 1) threadsPerThreadgroup:MTLSizeMake(termite_metal_thread_width(pipeline, total), 1, 1)];
    }
    return 0;
}

