static int termite_metal_encode_paged_attention_slot_on_encoder(
    termite_metal_decode_runtime *runtime,
    id<MTLComputeCommandEncoder> encoder,
    size_t slot,
    uint32_t format,
    id<MTLBuffer> q_buffer,
    size_t q_offset,
    const uint32_t *block_table,
    size_t block_count,
    size_t page_size,
    size_t q_len,
    size_t kv_tokens,
    size_t num_heads,
    size_t num_kv_heads,
    size_t head_dim,
    size_t key_row_bytes,
    size_t base_key_row_bytes,
    size_t query_position_offset,
    size_t kv_position_offset,
    size_t sliding_window,
    float softcap,
    const float *sinks,
    size_t sink_count,
    id<MTLBuffer> output_buffer,
    size_t output_offset,
    int failure_code
) {
    if (runtime == NULL || encoder == nil || q_buffer == nil || block_table == NULL || output_buffer == nil) return failure_code;
    if (slot >= TERMITE_METAL_ATTENTION_SPAN_SLOT_CAPACITY) return failure_code;
    if (q_len == 0 || kv_tokens == 0 || num_heads == 0 || num_kv_heads == 0 || head_dim == 0 || page_size == 0 || block_count == 0) return failure_code;
    if (num_heads % num_kv_heads != 0) return failure_code;
    if (q_len > UINT32_MAX || kv_tokens > UINT32_MAX || num_heads > UINT32_MAX || num_kv_heads > UINT32_MAX || head_dim > UINT32_MAX) return failure_code;
    if (key_row_bytes > UINT32_MAX || base_key_row_bytes > UINT32_MAX || query_position_offset > UINT32_MAX || kv_position_offset > UINT32_MAX || sliding_window > UINT32_MAX || page_size > UINT32_MAX || block_count > UINT32_MAX) return failure_code;
    if (runtime->attention_paged_pipeline == nil) return failure_code;
    if (runtime->attention_span_encoded_key_buffers[slot] == nil || runtime->attention_span_v_buffers[slot] == nil) return failure_code;
    if (runtime->attention_span_slot_tokens[slot] < kv_tokens || runtime->attention_span_slot_key_row_bytes[slot] != key_row_bytes || runtime->attention_span_slot_position_offset[slot] != kv_position_offset) return failure_code;
    if (runtime->attention_span_slot_v_row_stride[slot] > UINT32_MAX) return failure_code;
    if (sinks != NULL && sink_count < num_heads) return failure_code;
    if (block_count > SIZE_MAX / sizeof(uint32_t)) return failure_code;
    const uint32_t v_element_bytes = (format == 3u) ? (uint32_t)sizeof(uint16_t) : (uint32_t)sizeof(float);
    switch (format) {
        case 0u:
        case 1u:
        case 2u:
        case 3u:
        case 4u:
            break;
        default:
            return failure_code;
    }

    termite_metal_paged_attention_params params = {
        .q_len = (uint32_t)q_len,
        .kv_tokens = (uint32_t)kv_tokens,
        .num_heads = (uint32_t)num_heads,
        .num_kv_heads = (uint32_t)num_kv_heads,
        .head_dim = (uint32_t)head_dim,
        .key_row_bytes = (uint32_t)key_row_bytes,
        .base_key_row_bytes = (uint32_t)base_key_row_bytes,
        .query_position_offset = (uint32_t)query_position_offset,
        .kv_position_offset = (uint32_t)kv_position_offset,
        .sliding_window = (uint32_t)sliding_window,
        .v_row_stride = (uint32_t)runtime->attention_span_slot_v_row_stride[slot],
        .page_size = (uint32_t)page_size,
        .block_count = (uint32_t)block_count,
        .format = format,
        .v_element_bytes = v_element_bytes,
        .has_sinks = sinks != NULL ? 1u : 0u,
        .softcap = softcap,
    };
    const float zero_sink = 0.0f;
    const size_t block_table_bytes = block_count * sizeof(uint32_t);
    const size_t sinks_bytes = sinks != NULL ? num_heads * sizeof(float) : sizeof(zero_sink);
    id<MTLBuffer> block_table_buffer = nil;
    id<MTLBuffer> sinks_buffer = nil;
    size_t q_bytes = 0;
    size_t output_bytes = 0;
    if (!termite_metal_size_mul3(q_len, num_heads, head_dim, &q_bytes) ||
        !termite_metal_size_mul(q_bytes, sizeof(float), &q_bytes) ||
        !termite_metal_size_mul3(q_len, num_heads, head_dim, &output_bytes) ||
        !termite_metal_size_mul(output_bytes, sizeof(float), &output_bytes))
    {
        return failure_code;
    }
    termite_metal_planned_encoder_range accesses[4];
    if (termite_metal_planned_range_make(q_buffer, q_offset, q_bytes, TERMITE_METAL_PLANNED_RANGE_READ, &accesses[0], failure_code) != 0 ||
        termite_metal_planned_range_make(runtime->attention_span_encoded_key_buffers[slot], 0, runtime->attention_span_encoded_key_buffers[slot].length, TERMITE_METAL_PLANNED_RANGE_READ, &accesses[1], failure_code) != 0 ||
        termite_metal_planned_range_make(runtime->attention_span_v_buffers[slot], 0, runtime->attention_span_v_buffers[slot].length, TERMITE_METAL_PLANNED_RANGE_READ, &accesses[2], failure_code) != 0 ||
        termite_metal_planned_range_make(output_buffer, output_offset, output_bytes, TERMITE_METAL_PLANNED_RANGE_WRITE, &accesses[3], failure_code) != 0 ||
        termite_metal_decode_runtime_prepare_planned_compute_accesses(runtime, accesses, 4, failure_code) != 0)
    {
        return failure_code;
    }

    [encoder setComputePipelineState:runtime->attention_paged_pipeline];
    [encoder setBuffer:q_buffer offset:q_offset atIndex:0];
    [encoder setBuffer:runtime->attention_span_encoded_key_buffers[slot] offset:0 atIndex:1];
    [encoder setBuffer:runtime->attention_span_v_buffers[slot] offset:0 atIndex:2];
    if (block_table_bytes <= 4096u) {
        [encoder setBytes:block_table length:block_table_bytes atIndex:3];
    } else {
        block_table_buffer = [runtime->device newBufferWithBytes:block_table length:block_table_bytes options:MTLResourceStorageModeShared];
        if (block_table_buffer == nil) return failure_code;
        [encoder setBuffer:block_table_buffer offset:0 atIndex:3];
    }
    if (sinks == NULL) {
        [encoder setBytes:&zero_sink length:sizeof(zero_sink) atIndex:4];
    } else if (sinks_bytes <= 4096u) {
        [encoder setBytes:sinks length:sinks_bytes atIndex:4];
    } else {
        sinks_buffer = [runtime->device newBufferWithBytes:sinks length:sinks_bytes options:MTLResourceStorageModeShared];
        if (sinks_buffer == nil) return failure_code;
        [encoder setBuffer:sinks_buffer offset:0 atIndex:4];
    }
    [encoder setBuffer:output_buffer offset:output_offset atIndex:5];
    [encoder setBytes:&params length:sizeof(params) atIndex:6];
    const size_t total = q_len * num_heads;
    [encoder dispatchThreads:MTLSizeMake(total, 1, 1) threadsPerThreadgroup:MTLSizeMake(termite_metal_thread_width(runtime->attention_paged_pipeline, total), 1, 1)];
    (void)block_table_buffer;
    (void)sinks_buffer;
    return 0;
}

