            pre_gate_rms_norm_slot,
            inv_scale_buffer,
            0,
            gate_view.weight_buffer,
            up_view.weight_buffer,
            ffn_gated_buffer,
            0,
            hidden_size,
            intermediate_size,
            activation_kind,
            failure_code
        );
    }
    if (rc == 0) {
        rc = termite_metal_encode_q8_0_linear_raw_on_encoder(
            runtime,
            encoder,
            ffn_gated_buffer,
            0,
            down_view.weight_buffer,
            ffn_projected_buffer,
            0,
            1,
            intermediate_size,
            hidden_size,
            failure_code
        );
    }
    if (rc == 0) {
        rc = termite_metal_encode_rms_norm_add_on_encoder(
            runtime,
            encoder,
            ffn_projected_buffer,
            0,
            post_down_rms_norm_slot,
            residual_buffer,
            residual_offset,
            ffn_output_buffer,
            ffn_output_offset,
            hidden_size,
            eps,
            failure_code
        );
    }
    if (rc == 0) {
        rc = termite_metal_encode_q8_0_activation_multiply_on_encoder(
            runtime,
            encoder,
            ffn_output_buffer,
            ffn_output_offset,
            ple_gate_view.weight_buffer,
            ple_buffer,
            ple_offset,
            ple_gated_buffer,
            0,
            1,
            hidden_size,
            ple_hidden_size,
            activation_kind,
            failure_code
        );
    }
    if (rc == 0) {
        rc = termite_metal_encode_q8_0_linear_raw_on_encoder(
            runtime,
            encoder,
            ple_gated_buffer,
            0,
            ple_proj_view.weight_buffer,
            ple_projected_buffer,
            0,
            1,
            ple_hidden_size,
            hidden_size,
            failure_code
        );
    }
    if (rc == 0) {
        rc = output_scale_present != 0
            ? termite_metal_encode_rms_norm_add_scale_on_encoder(
                runtime,
                encoder,
                ple_projected_buffer,
                0,
                ple_post_norm_slot,
                ffn_output_buffer,
                ffn_output_offset,
                output_buffer,
                output_offset,
                hidden_size,
                eps,
                output_scale,
                failure_code)
            : termite_metal_encode_rms_norm_add_on_encoder(
                runtime,
                encoder,
                ple_projected_buffer,
                0,
                ple_post_norm_slot,
                ffn_output_buffer,
                ffn_output_offset,
                output_buffer,
                output_offset,
                hidden_size,
                eps,
                failure_code);
    }
    const int end_rc = termite_metal_decode_runtime_end_planned_compute_scope(runtime);
    if (rc != 0) return rc;
    return end_rc == 0 ? 0 : failure_code;
}

static int termite_metal_encode_attention_ffn_ple_q8_0_planned_1x(
    termite_metal_decode_runtime *runtime,
    id<MTLCommandBuffer> command_buffer,
    id<MTLBuffer> q_buffer,
    size_t q_offset,
    id<MTLBuffer> k_buffer,
    size_t k_offset,
    id<MTLBuffer> v_buffer,
    size_t v_offset,
    id<MTLBuffer> attention_output_buffer,
    size_t kv_tokens,
    size_t num_heads,
    size_t num_kv_heads,
    size_t head_dim,
    size_t query_position_offset,
    size_t kv_position_offset,
    size_t sliding_window,
    size_t total_sequence_len,
    size_t attention_linear_slot,
    size_t attention_post_linear_rms_norm_slot,
    id<MTLBuffer> residual_buffer,
    size_t residual_offset,
    id<MTLBuffer> attn_added_buffer,
    id<MTLBuffer> ffn_output_buffer,
    size_t ffn_output_offset,
    size_t ffn_pre_gate_rms_norm_slot,
    size_t gate_ffn_linear_slot,
    size_t up_ffn_linear_slot,
    size_t down_ffn_linear_slot,
    size_t ffn_post_down_rms_norm_slot,
    id<MTLBuffer> ple_buffer,
    size_t ple_offset,
    size_t ple_gate_linear_slot,
    size_t ple_proj_linear_slot,
    size_t ple_post_norm_slot,
    id<MTLBuffer> output_buffer,
    size_t output_offset,
    size_t hidden_size,
    size_t attention_input_size,
    size_t intermediate_size,
    size_t ple_hidden_size,
    uint32_t activation_kind,
    float eps,
    int output_scale_present,
    float output_scale,
    termite_metal_planned_layer_contract planned_contract,
    bool use_paged_kv,
    size_t paged_slot,
    uint32_t paged_format,
    const uint32_t *paged_block_table,
    size_t paged_block_count,
    size_t paged_page_size,
    size_t paged_key_row_bytes,
    size_t paged_base_key_row_bytes,
    size_t paged_v_row_stride,
    size_t paged_suffix_tokens,
    int failure_code
) {
    const bool trace_q80_block = termite_metal_trace_q80_block();
#define TERMITE_Q80_PLANNED_FAIL(REASON) do { \
        if (trace_q80_block) { \
            fprintf(stderr, "metal-planned-q80-1x-fail reason=%s paged=%d suffix=%zu start=%zu ops=%zu\n", (REASON), use_paged_kv ? 1 : 0, paged_suffix_tokens, planned_contract.start_index, planned_contract.command_op_count); \
        } \
        return failure_code; \
    } while (0)
    if (runtime == NULL || command_buffer == nil || runtime->active_frame_cb != command_buffer) TERMITE_Q80_PLANNED_FAIL("runtime-or-frame");
    if (q_buffer == nil || attention_output_buffer == nil || residual_buffer == nil || attn_added_buffer == nil || ffn_output_buffer == nil || ple_buffer == nil || output_buffer == nil) TERMITE_Q80_PLANNED_FAIL("buffer");
    if (!use_paged_kv && (k_buffer == nil || v_buffer == nil)) TERMITE_Q80_PLANNED_FAIL("dense-kv-buffer");
    if (use_paged_kv && paged_suffix_tokens != 0 && (k_buffer == nil || v_buffer == nil)) TERMITE_Q80_PLANNED_FAIL("paged-suffix-buffer");
    if (use_paged_kv && (paged_block_table == NULL || paged_block_count == 0 || paged_page_size == 0 || paged_key_row_bytes == 0 || paged_base_key_row_bytes == 0 || paged_v_row_stride == 0)) TERMITE_Q80_PLANNED_FAIL("paged-descriptor");
    if (hidden_size == 0 || attention_input_size == 0 || intermediate_size == 0 || ple_hidden_size == 0) TERMITE_Q80_PLANNED_FAIL("zero-dim");
    if (hidden_size % 32u != 0 || attention_input_size % 32u != 0 || intermediate_size % 32u != 0 || ple_hidden_size % 32u != 0) TERMITE_Q80_PLANNED_FAIL("dim-alignment");
    if (attention_post_linear_rms_norm_slot == SIZE_MAX || ffn_pre_gate_rms_norm_slot == SIZE_MAX || ffn_post_down_rms_norm_slot == SIZE_MAX || ple_post_norm_slot == SIZE_MAX) TERMITE_Q80_PLANNED_FAIL("missing-rms-slot");
    if (runtime->attention_f32_pipeline == nil || runtime->rms_inv_scale_pipeline == nil || runtime->q8_0_pair_activation_rms_scale_mmv_pipeline == nil) TERMITE_Q80_PLANNED_FAIL("pipeline");

    termite_metal_quant_linear_slot_view attention_view;
    termite_metal_quant_linear_slot_view gate_view;
    termite_metal_quant_linear_slot_view up_view;
    termite_metal_quant_linear_slot_view down_view;
    termite_metal_quant_linear_slot_view ple_gate_view;
    termite_metal_quant_linear_slot_view ple_proj_view;
    if (termite_metal_decode_runtime_require_quant_linear_slot(runtime, TERMITE_METAL_QUANT_FORMAT_Q8_0, attention_linear_slot, attention_input_size, hidden_size, &attention_view) != 0) TERMITE_Q80_PLANNED_FAIL("attention-slot");
    if (termite_metal_decode_runtime_require_quant_linear_slot(runtime, TERMITE_METAL_QUANT_FORMAT_Q8_0, gate_ffn_linear_slot, hidden_size, intermediate_size, &gate_view) != 0) TERMITE_Q80_PLANNED_FAIL("gate-slot");
    if (termite_metal_decode_runtime_require_quant_linear_slot(runtime, TERMITE_METAL_QUANT_FORMAT_Q8_0, up_ffn_linear_slot, hidden_size, intermediate_size, &up_view) != 0) TERMITE_Q80_PLANNED_FAIL("up-slot");
    if (termite_metal_decode_runtime_require_quant_linear_slot(runtime, TERMITE_METAL_QUANT_FORMAT_Q8_0, down_ffn_linear_slot, intermediate_size, hidden_size, &down_view) != 0) TERMITE_Q80_PLANNED_FAIL("down-slot");
    if (termite_metal_decode_runtime_require_quant_linear_slot(runtime, TERMITE_METAL_QUANT_FORMAT_Q8_0, ple_gate_linear_slot, hidden_size, ple_hidden_size, &ple_gate_view) != 0) TERMITE_Q80_PLANNED_FAIL("ple-gate-slot");
    if (termite_metal_decode_runtime_require_quant_linear_slot(runtime, TERMITE_METAL_QUANT_FORMAT_Q8_0, ple_proj_linear_slot, ple_hidden_size, hidden_size, &ple_proj_view) != 0) TERMITE_Q80_PLANNED_FAIL("ple-proj-slot");
    if (attention_post_linear_rms_norm_slot >= TERMITE_METAL_RMS_NORM_SLOT_CAPACITY || ffn_pre_gate_rms_norm_slot >= TERMITE_METAL_RMS_NORM_SLOT_CAPACITY || ffn_post_down_rms_norm_slot >= TERMITE_METAL_RMS_NORM_SLOT_CAPACITY || ple_post_norm_slot >= TERMITE_METAL_RMS_NORM_SLOT_CAPACITY) TERMITE_Q80_PLANNED_FAIL("rms-slot-range");
    if (runtime->rms_norm_slot_prepared[attention_post_linear_rms_norm_slot] == 0 || runtime->rms_norm_hidden_sizes[attention_post_linear_rms_norm_slot] != hidden_size) TERMITE_Q80_PLANNED_FAIL("attention-rms-slot");
    if (runtime->rms_norm_slot_prepared[ffn_pre_gate_rms_norm_slot] == 0 || runtime->rms_norm_hidden_sizes[ffn_pre_gate_rms_norm_slot] != hidden_size) TERMITE_Q80_PLANNED_FAIL("ffn-pre-rms-slot");
    if (runtime->rms_norm_slot_prepared[ffn_post_down_rms_norm_slot] == 0 || runtime->rms_norm_hidden_sizes[ffn_post_down_rms_norm_slot] != hidden_size) TERMITE_Q80_PLANNED_FAIL("ffn-post-rms-slot");
    if (runtime->rms_norm_slot_prepared[ple_post_norm_slot] == 0 || runtime->rms_norm_hidden_sizes[ple_post_norm_slot] != hidden_size) TERMITE_Q80_PLANNED_FAIL("ple-rms-slot");

    const size_t hidden_bytes = hidden_size * sizeof(float);
    const size_t attention_bytes = attention_input_size * sizeof(float);
    const size_t intermediate_bytes = intermediate_size * sizeof(float);
    const size_t ple_bytes = ple_hidden_size * sizeof(float);
    const size_t hot_intermediate_bytes = intermediate_bytes > ple_bytes ? intermediate_bytes : ple_bytes;
    if (q_offset + attention_bytes > q_buffer.length || residual_offset + hidden_bytes > residual_buffer.length || ffn_output_offset + hidden_bytes > ffn_output_buffer.length || ple_offset + ple_bytes > ple_buffer.length || output_offset + hidden_bytes > output_buffer.length) TERMITE_Q80_PLANNED_FAIL("bounds");
    if (termite_metal_decode_runtime_ensure_hot_buffers(runtime, hidden_bytes, hot_intermediate_bytes) != 0) TERMITE_Q80_PLANNED_FAIL("hot-buffers");

    id<MTLBuffer> attention_projected_buffer = runtime->hot_hidden_buffers[3];
    id<MTLBuffer> inv_scale_buffer = runtime->hot_hidden_buffers[1];
    id<MTLBuffer> ffn_gated_buffer = runtime->hot_intermediate_buffers[2];
    id<MTLBuffer> ffn_projected_buffer = runtime->hot_hidden_buffers[0];
    id<MTLBuffer> ple_gated_buffer = runtime->hot_intermediate_buffers[3];
    id<MTLBuffer> ple_projected_buffer = runtime->hot_hidden_buffers[2];
    if (attention_projected_buffer == nil || inv_scale_buffer == nil || ffn_gated_buffer == nil || ffn_projected_buffer == nil || ple_gated_buffer == nil || ple_projected_buffer == nil) TERMITE_Q80_PLANNED_FAIL("hot-buffer-nil");

    const BOOL reusing_planned_encoder = (runtime->active_planned_compute_encoder != nil);
    if (!reusing_planned_encoder && termite_metal_decode_runtime_begin_planned_compute_scope(runtime, TERMITE_METAL_COMPUTE_SOURCE_LAYER, TERMITE_METAL_COMPUTE_REGION_LAYER) != 0) TERMITE_Q80_PLANNED_FAIL("begin-scope");
    id<MTLComputeCommandEncoder> encoder = runtime->active_planned_compute_encoder;
    if (encoder == nil) TERMITE_Q80_PLANNED_FAIL("encoder");
    if (planned_contract.command_ops != NULL) {
        int rc = 0;
        bool paged_kv_seed_encoded = false;
        if (trace_q80_block) {
            fprintf(
                stderr,
                "metal-planned-q80-1x-start paged=%d suffix=%zu start=%zu ops=%zu q=%zu kv=%zu page=%zu\n",
                use_paged_kv ? 1 : 0,
                paged_suffix_tokens,
                planned_contract.start_index,
                planned_contract.command_op_count,
                attention_input_size,
                kv_tokens,
                paged_page_size
            );
            const size_t trace_limit = planned_contract.command_op_count < 16u ? planned_contract.command_op_count : 16u;
            fprintf(stderr, "metal-planned-q80-1x-ops");
            for (size_t trace_index = planned_contract.start_index; trace_index < trace_limit; trace_index += 1) {
                const termite_metal_runtime_command_op trace_op = planned_contract.command_ops[trace_index];
                fprintf(
                    stderr,
                    " %zu:%u/b%u/q%u/o%u/f%u",
                    trace_index,
                    trace_op.kind,
                    trace_op.barrier_before,
                    trace_op.quant_dispatch,
                    trace_op.op,
                    trace_op.format
                );
            }
            fprintf(stderr, "\n");
        }
        for (size_t op_index = planned_contract.start_index;
             rc == 0 && op_index < planned_contract.command_op_count;
             op_index += 1)
        {
            const termite_metal_runtime_command_op op = planned_contract.command_ops[op_index];
            termite_metal_decode_runtime_record_planned_command_op(runtime, op);
            switch (op.kind) {
                case TERMITE_METAL_PLAN_OP_DECODE_KV_SEED:
                    if (use_paged_kv && paged_suffix_tokens != 0) {
                        if (paged_format == 2u) {
                            rc = termite_metal_encode_paged_f32_kv_seed_on_encoder(
                                runtime,
                                encoder,
                                paged_slot,
                                k_buffer,
                                k_offset,
                                v_buffer,
                                v_offset,
                                kv_tokens,
                                paged_suffix_tokens,
                                num_kv_heads,
                                head_dim,
                                paged_key_row_bytes,
                                paged_v_row_stride,
                                kv_position_offset,
                                paged_block_table,
                                paged_block_count,
	                                paged_page_size,
	                                failure_code);
	                            if (rc != 0) break;
	                        } else if (paged_format == 0u || paged_format == 1u || paged_format == 3u || paged_format == 4u) {
	                            rc = termite_metal_encode_paged_quantized_kv_seed_on_encoder(
                                runtime,
                                encoder,
                                paged_slot,
                                paged_format,
                                k_buffer,
                                k_offset,
                                v_buffer,
                                v_offset,
                                kv_tokens,
                                paged_suffix_tokens,
                                num_kv_heads,
                                head_dim,
                                paged_key_row_bytes,
                                paged_base_key_row_bytes,
                                paged_v_row_stride,
                                kv_position_offset,
                                paged_block_table,
                                paged_block_count,
	                                paged_page_size,
	                                failure_code);
	                            if (rc != 0) break;
	                        } else {
	                            if (termite_metal_decode_runtime_end_planned_compute_scope(runtime) != 0) {
	                                rc = failure_code;
                                break;
                            }
                            rc = termite_metal_decode_runtime_encode_attention_paged_update_from_f32_key_device_slot(
                                runtime,
                                command_buffer,
                                paged_slot,
                                paged_format,
                                (__bridge void *)k_buffer,
                                k_offset,
                                (__bridge void *)v_buffer,
                                v_offset,
                                kv_tokens,
                                paged_suffix_tokens,
                                num_kv_heads,
                                head_dim,
                                paged_key_row_bytes,
                                paged_base_key_row_bytes,
                                paged_v_row_stride,
                                kv_position_offset,
                                paged_block_table,
                                paged_block_count,
                                paged_page_size);
                            if (rc != 0) break;
                            if (termite_metal_decode_runtime_begin_planned_compute_scope(runtime, TERMITE_METAL_COMPUTE_SOURCE_LAYER, TERMITE_METAL_COMPUTE_REGION_LAYER) != 0) {
                                rc = failure_code;
                                break;
                            }
                            encoder = runtime->active_planned_compute_encoder;
                            if (encoder == nil) {
	                                rc = failure_code;
	                                break;
	                            }
	                        }
                        paged_kv_seed_encoded = true;
                    }
                    break;
                case TERMITE_METAL_PLAN_OP_DECODE_ATTENTION:
                    if (use_paged_kv) {
                        if (op.op != TERMITE_METAL_OPERATOR_UNKNOWN &&
                            op.op != TERMITE_METAL_OPERATOR_ATTENTION_PAGED &&
                            op.op != TERMITE_METAL_OPERATOR_ATTENTION_QUANTIZED_KV)
                        {
                            rc = failure_code;
                            break;
                        }
                        if (op.format != UINT8_MAX &&
                            op.format != TERMITE_METAL_GRAPH_ATTENTION_KV_FORMAT_F32 &&
                            op.format != TERMITE_METAL_GRAPH_ATTENTION_KV_FORMAT_POLAR4 &&
                            op.format != TERMITE_METAL_GRAPH_ATTENTION_KV_FORMAT_TURBO3 &&
                            op.format != TERMITE_METAL_GRAPH_ATTENTION_KV_FORMAT_QUANTIZED)
                        {
                            rc = failure_code;
                            break;
                        }
                        if (paged_suffix_tokens != 0 && !paged_kv_seed_encoded) {
                            if (paged_format == 2u) {
                                rc = termite_metal_encode_paged_f32_kv_seed_on_encoder(
                                    runtime,
                                    encoder,
                                    paged_slot,
                                    k_buffer,
                                    k_offset,
                                    v_buffer,
                                    v_offset,
                                    kv_tokens,
                                    paged_suffix_tokens,
                                    num_kv_heads,
                                    head_dim,
                                    paged_key_row_bytes,
                                    paged_v_row_stride,
                                    kv_position_offset,
                                    paged_block_table,
                                    paged_block_count,
	                                    paged_page_size,
	                                    failure_code);
	                                if (rc != 0) break;
	                            } else if (paged_format == 0u || paged_format == 1u || paged_format == 3u || paged_format == 4u) {
	                                rc = termite_metal_encode_paged_quantized_kv_seed_on_encoder(
                                    runtime,
                                    encoder,
                                    paged_slot,
                                    paged_format,
                                    k_buffer,
                                    k_offset,
                                    v_buffer,
                                    v_offset,
                                    kv_tokens,
                                    paged_suffix_tokens,
                                    num_kv_heads,
                                    head_dim,
                                    paged_key_row_bytes,
                                    paged_base_key_row_bytes,
                                    paged_v_row_stride,
                                    kv_position_offset,
                                    paged_block_table,
                                    paged_block_count,
	                                    paged_page_size,
	                                    failure_code);
	                                if (rc != 0) break;
	                            } else {
	                                if (termite_metal_decode_runtime_end_planned_compute_scope(runtime) != 0) {
	                                    rc = failure_code;
                                    break;
                                }
                                rc = termite_metal_decode_runtime_encode_attention_paged_update_from_f32_key_device_slot(
                                    runtime,
                                    command_buffer,
                                    paged_slot,
                                    paged_format,
                                    (__bridge void *)k_buffer,
                                    k_offset,
                                    (__bridge void *)v_buffer,
                                    v_offset,
                                    kv_tokens,
                                    paged_suffix_tokens,
                                    num_kv_heads,
                                    head_dim,
                                    paged_key_row_bytes,
                                    paged_base_key_row_bytes,
                                    paged_v_row_stride,
                                    kv_position_offset,
                                    paged_block_table,
                                    paged_block_count,
                                    paged_page_size);
                                if (rc != 0) break;
                                if (termite_metal_decode_runtime_begin_planned_compute_scope(runtime, TERMITE_METAL_COMPUTE_SOURCE_LAYER, TERMITE_METAL_COMPUTE_REGION_LAYER) != 0) {
                                    rc = failure_code;
                                    break;
                                }
                                encoder = runtime->active_planned_compute_encoder;
                                if (encoder == nil) {
	                                    rc = failure_code;
	                                    break;
	                                }
	                            }
                            paged_kv_seed_encoded = true;
                        }
                        rc = termite_metal_encode_paged_attention_slot_on_encoder(
                            runtime,
                            encoder,
                            paged_slot,
                            paged_format,
                            q_buffer,
                            q_offset,
                            paged_block_table,
                            paged_block_count,
                            paged_page_size,
                            1,
                            kv_tokens,
                            num_heads,
                            num_kv_heads,
                            head_dim,
                            paged_key_row_bytes,
                            paged_base_key_row_bytes,
                            query_position_offset,
                            kv_position_offset,
                            sliding_window,
                            0.0f,
                            NULL,
                            0,
                            attention_output_buffer,
                            0,
                            failure_code);
                    } else {
                        if (op.op != TERMITE_METAL_OPERATOR_UNKNOWN &&
                            op.op != TERMITE_METAL_OPERATOR_ATTENTION_FLASH)
                        {
                            rc = failure_code;
                            break;
                        }
                        if (!termite_metal_runtime_command_format_is_f32_attention(op.format)) {
                            rc = failure_code;
                            break;
                        }
                        rc = termite_metal_encode_attention_f32_on_encoder(
                            runtime,
                            encoder,
                            q_buffer,
                            q_offset,
                            k_buffer,
                            k_offset,
                            v_buffer,
                            v_offset,
                            attention_output_buffer,
                            0,
                            1,
                            kv_tokens,
                            num_heads,
                            num_kv_heads,
                            head_dim,
                            query_position_offset,
                            kv_position_offset,
                            sliding_window,
                            total_sequence_len,
                            failure_code);
                    }
                    break;
                case TERMITE_METAL_PLAN_OP_DECODE_ATTENTION_OUTPUT_LINEAR: {
                    if (!termite_metal_runtime_operator_is_quant_matmul(op.op)) {
                        rc = failure_code;
                        break;
                    }
                    if (!termite_metal_runtime_command_format_matches_quant(op.format, TERMITE_METAL_QUANT_FORMAT_Q8_0)) {
                        rc = failure_code;
                        break;
                    }
                    termite_metal_quant_matmul_descriptor descriptor = {
                        .slot = attention_linear_slot,
                        .format = TERMITE_METAL_QUANT_FORMAT_Q8_0,
                        .activation_dtype = TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32,
                        .input_dtype = termite_metal_quant_matmul_dtype_from_command(op.input_dtype),
                        .output_dtype = termite_metal_quant_matmul_dtype_from_command(op.output_dtype),
                        .epilogue = TERMITE_METAL_QUANT_MATMUL_EPILOGUE_NONE,
                        .fallback_pipeline = runtime->q8_0_pipeline,
                        .input_buffer = attention_output_buffer,
                        .weight_buffer = attention_view.weight_buffer,
                        .output_buffer = attention_projected_buffer,
                        .rows = 1,
                        .in_dim = attention_input_size,
                        .out_dim = hidden_size,
                        .values_per_block = 32u,
                        .bytes_per_block = 34u,
                        .q8_family = TERMITE_METAL_Q8_0_LINEAR_FAMILY_ATTENTION_OUTPUT,
                        .use_planned_dispatch = true,
                        .planned_dispatch = op.quant_dispatch,
                        .failure_code = failure_code,
                    };
                    rc = termite_metal_encode_quant_matmul_descriptor_on_encoder(runtime, encoder, &descriptor);
                    break;
