            .format = TERMITE_METAL_QUANT_FORMAT_Q8_0,
            .activation_dtype = TERMITE_METAL_QUANT_MATMUL_ACTIVATION_F32,
            .input_dtype = termite_metal_quant_matmul_dtype_from_command(termite_metal_planned_layer_cursor_input_dtype(&planned_cursor)),
            .output_dtype = termite_metal_quant_matmul_dtype_from_command(termite_metal_planned_layer_cursor_output_dtype(&planned_cursor)),
            .epilogue = TERMITE_METAL_QUANT_MATMUL_EPILOGUE_NONE,
            .fallback_pipeline = runtime->q8_0_pipeline,
            .input_buffer = ple_gated_buffer,
            .weight_buffer = ple_proj_view.weight_buffer,
            .output_buffer = ple_projected_buffer,
            .rows = 1,
            .in_dim = ple_hidden_size,
            .out_dim = hidden_size,
            .values_per_block = 32u,
            .bytes_per_block = 34u,
            .q8_family = TERMITE_METAL_Q8_0_LINEAR_FAMILY_PLE_PROJECTION,
            .use_planned_dispatch = true,
            .planned_dispatch = termite_metal_planned_layer_cursor_quant_dispatch(&planned_cursor),
            .failure_code = failure_code,
        };
        rc = termite_metal_encode_quant_matmul_descriptor_on_encoder(runtime, encoder, &descriptor);
    }
    if (rc == 0) rc = termite_metal_planned_layer_cursor_fallback_barrier_after_op(&planned_cursor);
    if (rc == 0) {
        rc = termite_metal_planned_layer_cursor_before_step(&planned_cursor, TERMITE_METAL_Q80_F32_KV_LAYER_STEP_KINDS, TERMITE_METAL_Q80_F32_KV_LAYER_STEP_COUNT, TERMITE_METAL_Q80_F32_KV_LAYER_STEP_PLE_POST_NORM_RESIDUAL);
    }
    if (rc == 0) {
        rc = output_scale_present != 0
            ? termite_metal_encode_rms_norm_add_scale_on_encoder(
                runtime,
                encoder,
                ple_projected_buffer,
                0,
                ple_post_norm_slot,
                ffn_output_buffer,
                ffn_output_offset,
                output_buffer,
                output_offset,
                hidden_size,
                eps,
                output_scale,
                failure_code)
            : termite_metal_encode_rms_norm_add_on_encoder(
                runtime,
                encoder,
                ple_projected_buffer,
                0,
                ple_post_norm_slot,
                ffn_output_buffer,
                ffn_output_offset,
                output_buffer,
                output_offset,
                hidden_size,
                eps,
                failure_code);
    }
    const int end_rc = termite_metal_decode_runtime_end_planned_compute_scope(runtime);
    if (rc != 0) return rc;
    return end_rc == 0 ? 0 : failure_code;
}

