static id<MTLLibrary> termite_metal_shared_library(id<MTLDevice> device, BOOL precise_math) {
    static id<MTLLibrary> shared_library = nil;
    static id<MTLLibrary> shared_precise_library = nil;
    if (precise_math) {
        if (shared_precise_library == nil) {
            shared_precise_library = termite_metal_make_library(device, YES);
            if (shared_precise_library == nil) {
                shared_precise_library = termite_metal_make_library(device, NO);
            }
        }
        return shared_precise_library;
    }
    if (shared_library == nil) {
        shared_library = termite_metal_make_library(device, NO);
    }
    return shared_library;
}

termite_metal_provider *termite_metal_provider_create(void) {
    @autoreleasepool {
        id<MTLDevice> device = termite_metal_shared_device();
        if (device == nil) return NULL;
        id<MTLCommandQueue> queue = [device newCommandQueue];
        if (queue == nil) return NULL;
        id<MTLLibrary> library = termite_metal_shared_library(device, NO);
        if (library == nil) return NULL;

        termite_metal_provider *provider = calloc(1, sizeof(termite_metal_provider));
        if (provider == NULL) return NULL;
        provider->device = device;
        provider->queue = queue;
        provider->q4_0_pipeline = termite_metal_make_pipeline(device, library, @"termite_q4_0_linear");
        provider->q4_1_pipeline = termite_metal_make_pipeline(device, library, @"termite_q4_1_linear");
        provider->q5_0_pipeline = termite_metal_make_pipeline(device, library, @"termite_q5_0_linear");
        provider->q5_1_pipeline = termite_metal_make_pipeline(device, library, @"termite_q5_1_linear");
        provider->q8_0_pipeline = termite_metal_make_pipeline(device, library, @"termite_q8_0_linear");
        provider->q8_1_pipeline = termite_metal_make_pipeline(device, library, @"termite_q8_1_linear");
        provider->q8_0_mmv_pipeline = termite_metal_make_pipeline(device, library, @"termite_q8_0_linear_mmv");
        provider->q8_0_small_batch_r2_pipeline = termite_metal_make_pipeline(device, library, @"termite_q8_0_linear_r2_ext");
        provider->q8_0_small_batch_r3_pipeline = termite_metal_make_pipeline(device, library, @"termite_q8_0_linear_r3_ext");
        provider->q8_0_small_batch_r4_pipeline = termite_metal_make_pipeline(device, library, @"termite_q8_0_linear_r4_ext");
