        }
        if (runtime->bias_activation_pipeline == nil || runtime->bias_add_layer_norm_pipeline == nil) {
            fprintf(stderr, "metal-runtime-create: pipeline=nil deberta_ffn\n");
            free(runtime);
            return NULL;
        }
        return runtime;
    }
}

void termite_metal_decode_runtime_destroy(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return;
    if (runtime->submitted_frame_cb != nil) {
        (void)termite_metal_decode_runtime_wait_frame(runtime);
    }
    if (runtime->active_frame_cb != nil) {
        if (termite_metal_decode_runtime_active_frame_empty(runtime)) {
            (void)termite_metal_decode_runtime_cancel_frame(runtime);
        } else if (termite_metal_decode_runtime_submit_frame(runtime) == 0) {
            (void)termite_metal_decode_runtime_wait_frame(runtime);
        }
    }
    termite_metal_decode_runtime_clear_frame_resources(&runtime->active_frame_retained_resources);
    termite_metal_decode_runtime_clear_frame_resources(&runtime->submitted_frame_retained_resources);
    runtime->embed_absolute_position_pipeline = nil;
