int termite_metal_decode_runtime_prepare_absolute_embeddings(
    termite_metal_decode_runtime *runtime,
    const float *token_embedding,
    size_t vocab_size,
    const float *position_embedding,
    size_t max_position_embeddings,
    size_t hidden_size
) {
    if (runtime == NULL || token_embedding == NULL || position_embedding == NULL) return -1;
    if (runtime->device == nil || runtime->queue == nil || runtime->library == nil) return -2;
    if (vocab_size == 0 || max_position_embeddings == 0 || hidden_size == 0) return -3;
    @autoreleasepool {
        const size_t token_bytes = vocab_size * hidden_size * sizeof(float);
        const size_t position_bytes = max_position_embeddings * hidden_size * sizeof(float);
        id<MTLBuffer> token_embedding_buffer = termite_metal_make_private_buffer_with_bytes(runtime->device, runtime->queue, token_embedding, token_bytes);
        id<MTLBuffer> position_embedding_buffer = termite_metal_make_private_buffer_with_bytes(runtime->device, runtime->queue, position_embedding, position_bytes);
        if (token_embedding_buffer == nil || position_embedding_buffer == nil) return -4;
        runtime->token_embedding_table_buffer = token_embedding_buffer;
        runtime->position_embedding_table_buffer = position_embedding_buffer;
        runtime->token_embedding_table_bytes = token_bytes;
        runtime->position_embedding_table_bytes = position_bytes;
        runtime->resident_vocab_size = vocab_size;
        runtime->resident_max_position_embeddings = max_position_embeddings;
        runtime->resident_hidden_size = hidden_size;
        return 0;
    }
}

static int termite_metal_decode_runtime_ensure_active_layer_projection_buffer(
    termite_metal_decode_runtime *runtime,
    size_t index,
    size_t bytes
) {
    if (runtime == NULL || index >= 6) return -1;
    if (bytes == 0) return 0;
    if (runtime->graph_plan_active != 0 && index < TERMITE_METAL_GRAPH_PLAN_SLOT_CAPACITY) {
        if (runtime->graph_plan_buffers[index] != nil &&
            runtime->graph_plan_capacities[index] >= bytes)
        {
            runtime->active_layer_projection_buffers[index] = runtime->graph_plan_buffers[index];
            runtime->active_layer_projection_capacities[index] = runtime->graph_plan_capacities[index];
            return 0;
        }
    }
    @autoreleasepool {
        if (bytes > runtime->active_layer_projection_capacities[index] ||
            runtime->active_layer_projection_buffers[index] == nil)
        {
            id<MTLBuffer> buffer = [runtime->device newBufferWithLength:bytes options:MTLResourceStorageModePrivate];
            if (buffer == nil) return -2;
            runtime->active_layer_projection_buffers[index] = buffer;
            runtime->active_layer_projection_capacities[index] = bytes;
        }
        return 0;
    }
}

int termite_metal_decode_runtime_begin_graph_plan(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return -1;
    for (size_t slot = 0; slot < TERMITE_METAL_GRAPH_PLAN_SLOT_CAPACITY; ++slot) {
        runtime->graph_plan_requested_bytes[slot] = 0;
    }
    runtime->graph_plan_active = 0;
    return 0;
}

int termite_metal_decode_runtime_reserve_graph_plan_slot(
    termite_metal_decode_runtime *runtime,
    size_t slot,
    size_t bytes
) {
    if (runtime == NULL || slot >= TERMITE_METAL_GRAPH_PLAN_SLOT_CAPACITY) return -1;
    if (bytes > runtime->graph_plan_requested_bytes[slot]) {
        runtime->graph_plan_requested_bytes[slot] = bytes;
    }
    return 0;
}

static size_t termite_metal_decode_runtime_graph_plan_allocation_bytes(size_t current_capacity, size_t requested_bytes) {
    if (requested_bytes == 0) return 0;
    size_t allocation_bytes = requested_bytes;
    if (current_capacity > 0) {
        if (current_capacity <= SIZE_MAX / 2u && current_capacity * 2u > allocation_bytes) {
            allocation_bytes = current_capacity * 2u;
        }
    } else if (requested_bytes <= SIZE_MAX / 2u) {
        allocation_bytes = requested_bytes * 2u;
    }
    return allocation_bytes;
}

int termite_metal_decode_runtime_commit_graph_plan(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL || runtime->device == nil) return -1;
    @autoreleasepool {
        const char *trace_graph_plan = getenv("TERMITE_METAL_TRACE_GRAPH_PLAN");
        const bool trace_enabled = trace_graph_plan != NULL && trace_graph_plan[0] != '\0' && strcmp(trace_graph_plan, "0") != 0;
        size_t trace_slots = 0;
        size_t trace_bytes = 0;
        size_t trace_allocations = 0;
        size_t trace_reuses = 0;
        for (size_t slot = 0; slot < TERMITE_METAL_GRAPH_PLAN_SLOT_CAPACITY; ++slot) {
            const size_t bytes = runtime->graph_plan_requested_bytes[slot];
            if (bytes == 0) continue;
            trace_slots += 1;
            trace_bytes += bytes;
            if (runtime->graph_plan_buffers[slot] != nil &&
                runtime->graph_plan_capacities[slot] >= bytes)
            {
                runtime->graph_plan_reuses += 1;
                trace_reuses += 1;
                continue;
            }
            const size_t allocation_bytes = termite_metal_decode_runtime_graph_plan_allocation_bytes(runtime->graph_plan_capacities[slot], bytes);
            id<MTLBuffer> buffer = [runtime->device newBufferWithLength:allocation_bytes options:MTLResourceStorageModePrivate];
            if (buffer == nil) return -2;
            runtime->graph_plan_buffers[slot] = buffer;
            runtime->graph_plan_capacities[slot] = allocation_bytes;
            runtime->graph_plan_allocations += 1;
            trace_allocations += 1;
        }
        runtime->graph_plan_active = 1;
        runtime->graph_plan_count += 1;
        if (trace_enabled) {
            fprintf(
                stderr,
                "metal_graph_plan_commit: count=%llu slots=%zu bytes=%zu allocations=%zu reuses=%zu\n",
                (unsigned long long)runtime->graph_plan_count,
                trace_slots,
                trace_bytes,
                trace_allocations,
                trace_reuses
            );
            if (strcmp(trace_graph_plan, "all") == 0) {
                fprintf(stderr, "metal_graph_plan_slots:");
                for (size_t slot = 0; slot < TERMITE_METAL_GRAPH_PLAN_SLOT_CAPACITY; ++slot) {
                    const size_t bytes = runtime->graph_plan_requested_bytes[slot];
                    if (bytes == 0) continue;
                    fprintf(stderr, " %zu=%zu", slot, bytes);
                }
        fprintf(stderr, "\n");
    }
}

        return 0;
    }
}

static bool termite_metal_trace_dense_linear_shapes_enabled(void) {
    const char *enabled = getenv("TERMITE_METAL_TRACE_DENSE_LINEAR_SHAPES");
    return enabled != NULL && enabled[0] != '\0' && strcmp(enabled, "0") != 0;
}

static const char *termite_metal_dense_linear_variant(
    bool use_bf16,
    bool use_shared_row_reduce,
    bool use_tiled32_m16,
    bool use_tiled32,
    bool use_tiled,
    bool use_reduce,
    bool activation_fused
) {
    if (use_bf16) {
        if (use_shared_row_reduce) return "bf16_shared_row_reduce";
        return use_reduce ? "bf16_multi_row_reduce" : "bf16_multi_row";
    }
    if (use_tiled32_m16) return activation_fused ? "f32_tiled32_m16_activation" : "f32_tiled32_m16";
    if (use_tiled32) return activation_fused ? "f32_tiled32_activation" : "f32_tiled32";
    if (use_tiled) return activation_fused ? "f32_tiled16_activation" : "f32_tiled16";
    return use_reduce ? "f32_row_reduce" : "f32_elementwise";
}

static void termite_metal_maybe_trace_dense_linear_dispatch(
    const char *site,
    size_t slot,
    size_t rows,
    size_t in_dim,
    size_t out_dim,
    const char *variant,
    bool active_frame,
    bool planned_encoder,
    bool packed_weight,
    bool activation_fused,
    bool mps
) {
    if (!termite_metal_trace_dense_linear_shapes_enabled()) return;
    fprintf(
        stderr,
        "metal_dense_linear_trace: site=%s slot=%zu rows=%zu in=%zu out=%zu variant=%s active_frame=%u planned_encoder=%u packed_weight=%u activation_fused=%u mps=%u\n",
        site,
        slot,
        rows,
        in_dim,
        out_dim,
        variant,
        active_frame ? 1u : 0u,
        planned_encoder ? 1u : 0u,
        packed_weight ? 1u : 0u,
        activation_fused ? 1u : 0u,
        mps ? 1u : 0u
    );
}

static bool termite_metal_decode_runtime_graph_slot_ready(
    termite_metal_decode_runtime *runtime,
    size_t slot,
    size_t bytes
) {
    if (runtime == NULL || slot >= TERMITE_METAL_GRAPH_PLAN_SLOT_CAPACITY) return false;
    if (bytes == 0) return true;
    return runtime->graph_plan_active != 0 &&
        runtime->graph_plan_buffers[slot] != nil &&
        runtime->graph_plan_capacities[slot] >= bytes;
}

static bool termite_metal_decode_runtime_graph_alias(
    termite_metal_decode_runtime *runtime,
    id<MTLBuffer> buffer
) {
    if (runtime == NULL || buffer == nil) return false;
    for (size_t slot = 0; slot < TERMITE_METAL_GRAPH_PLAN_SLOT_CAPACITY; ++slot) {
        if (runtime->graph_plan_buffers[slot] == buffer) return true;
    }
    return false;
}

static int termite_metal_decode_runtime_ensure_graph_plan_slot(
    termite_metal_decode_runtime *runtime,
    size_t slot,
    size_t bytes
) {
    if (runtime == NULL || slot >= TERMITE_METAL_GRAPH_PLAN_SLOT_CAPACITY) return -1;
    if (bytes == 0) return 0;
    if (termite_metal_decode_runtime_graph_slot_ready(runtime, slot, bytes)) return 0;
    if (runtime->graph_plan_active == 0) {
        if (termite_metal_decode_runtime_begin_graph_plan(runtime) != 0) return -2;
    }
    if (termite_metal_decode_runtime_reserve_graph_plan_slot(runtime, slot, bytes) != 0) return -3;
    if (termite_metal_decode_runtime_commit_graph_plan(runtime) != 0) return -4;
    return termite_metal_decode_runtime_graph_slot_ready(runtime, slot, bytes) ? 0 : -5;
}

static int termite_metal_decode_runtime_reserve_graph_plan_slots(
    termite_metal_decode_runtime *runtime,
    const size_t *slots,
    const size_t *bytes,
    size_t count
) {
    if (runtime == NULL || slots == NULL || bytes == NULL) return -1;
    bool all_ready = true;
    for (size_t i = 0; i < count; ++i) {
        if (slots[i] >= TERMITE_METAL_GRAPH_PLAN_SLOT_CAPACITY) return -2;
        if (bytes[i] == 0) continue;
        if (!termite_metal_decode_runtime_graph_slot_ready(runtime, slots[i], bytes[i])) {
            all_ready = false;
            break;
        }
    }
    if (all_ready) return 0;
    if (runtime->graph_plan_active == 0) {
        if (termite_metal_decode_runtime_begin_graph_plan(runtime) != 0) return -3;
    }
    for (size_t i = 0; i < count; ++i) {
        if (bytes[i] == 0) continue;
        if (termite_metal_decode_runtime_reserve_graph_plan_slot(runtime, slots[i], bytes[i]) != 0) return -4;
    }
    if (termite_metal_decode_runtime_commit_graph_plan(runtime) != 0) return -5;
    for (size_t i = 0; i < count; ++i) {
        if (!termite_metal_decode_runtime_graph_slot_ready(runtime, slots[i], bytes[i])) return -6;
    }
    return 0;
}

int termite_metal_decode_runtime_reserve_prefill_layer_scratch(
    termite_metal_decode_runtime *runtime,
    size_t rows,
    size_t num_heads,
    size_t num_kv_heads,
    size_t head_dim,
    size_t hidden_size,
    size_t intermediate_size,
    size_t tail_vocab_size
) {
    if (runtime == NULL) return -1;
    if (rows == 0 || num_heads == 0 || num_kv_heads == 0 || head_dim == 0) return -2;
    const size_t q_bytes = rows * num_heads * head_dim * sizeof(float);
    const size_t kv_bytes = rows * num_kv_heads * head_dim * sizeof(float);
    const size_t hidden_bytes = hidden_size > 0 ? rows * hidden_size * sizeof(float) : 0;
    const size_t direct_hidden_bytes = q_bytes > hidden_bytes ? q_bytes : hidden_bytes;
    const size_t hot_hidden_bytes = direct_hidden_bytes;
    const size_t intermediate_bytes = intermediate_size > 0 ? rows * intermediate_size * sizeof(float) : 0;
    const size_t tail_logits_bytes = tail_vocab_size * sizeof(float);
    size_t slots[21] = {
        0,
        1,
        2,
        3,
        4,
        5,
        TERMITE_METAL_GRAPH_PLAN_DIRECT_HIDDEN_SLOT_BASE + 0,
        TERMITE_METAL_GRAPH_PLAN_DIRECT_HIDDEN_SLOT_BASE + 1,
        TERMITE_METAL_GRAPH_PLAN_DIRECT_HIDDEN_SLOT_BASE + 2,
        TERMITE_METAL_GRAPH_PLAN_DIRECT_HIDDEN_SLOT_BASE + 3,
        TERMITE_METAL_GRAPH_PLAN_DIRECT_Q_SLOT,
        TERMITE_METAL_GRAPH_PLAN_SAMPLE_LOGITS_SLOT,
        TERMITE_METAL_GRAPH_PLAN_HOT_HIDDEN_SLOT_BASE + 0,
        TERMITE_METAL_GRAPH_PLAN_HOT_HIDDEN_SLOT_BASE + 1,
        TERMITE_METAL_GRAPH_PLAN_HOT_HIDDEN_SLOT_BASE + 2,
        TERMITE_METAL_GRAPH_PLAN_HOT_HIDDEN_SLOT_BASE + 3,
        TERMITE_METAL_GRAPH_PLAN_HOT_INTERMEDIATE_SLOT_BASE + 0,
        TERMITE_METAL_GRAPH_PLAN_HOT_INTERMEDIATE_SLOT_BASE + 1,
        TERMITE_METAL_GRAPH_PLAN_HOT_INTERMEDIATE_SLOT_BASE + 2,
        TERMITE_METAL_GRAPH_PLAN_HOT_INTERMEDIATE_SLOT_BASE + 3,
        TERMITE_METAL_GRAPH_PLAN_HOT_INTERMEDIATE_SLOT_BASE + 4,
    };
    size_t bytes[21] = {
        q_bytes,
        kv_bytes,
        kv_bytes,
        q_bytes,
        kv_bytes,
        kv_bytes,
        direct_hidden_bytes,
        direct_hidden_bytes,
        direct_hidden_bytes,
        direct_hidden_bytes,
        q_bytes,
        tail_logits_bytes,
        hot_hidden_bytes,
        hot_hidden_bytes,
        hot_hidden_bytes,
        hot_hidden_bytes,
        intermediate_bytes,
        intermediate_bytes,
        intermediate_bytes,
        intermediate_bytes,
        intermediate_bytes,
    };
    if (termite_metal_decode_runtime_reserve_graph_plan_slots(runtime, slots, bytes, 21) != 0) return -3;
    if (termite_metal_decode_runtime_ensure_active_layer_projection_buffer(runtime, 0, q_bytes) != 0) return -3;
    if (termite_metal_decode_runtime_ensure_active_layer_projection_buffer(runtime, 1, kv_bytes) != 0) return -4;
    if (termite_metal_decode_runtime_ensure_active_layer_projection_buffer(runtime, 2, kv_bytes) != 0) return -5;
    if (termite_metal_decode_runtime_ensure_active_layer_projection_buffer(runtime, 3, q_bytes) != 0) return -6;
    if (termite_metal_decode_runtime_ensure_active_layer_projection_buffer(runtime, 4, kv_bytes) != 0) return -7;
    if (termite_metal_decode_runtime_ensure_active_layer_projection_buffer(runtime, 5, kv_bytes) != 0) return -8;
    if (termite_metal_decode_runtime_ensure_direct_block_hidden_buffers(runtime, direct_hidden_bytes) != 0) return -10;
    if (termite_metal_decode_runtime_ensure_direct_block_q_buffer(runtime, q_bytes) != 0) return -11;
    if (hot_hidden_bytes > 0 || intermediate_bytes > 0) {
        if (termite_metal_decode_runtime_ensure_hot_buffers(runtime, hot_hidden_bytes, intermediate_bytes) != 0) return -12;
    }
    if (tail_logits_bytes > 0) {
        runtime->sample_logits_buffer = runtime->graph_plan_buffers[TERMITE_METAL_GRAPH_PLAN_SAMPLE_LOGITS_SLOT];
        runtime->sample_logits_capacity = runtime->graph_plan_capacities[TERMITE_METAL_GRAPH_PLAN_SAMPLE_LOGITS_SLOT];
    }
    return 0;
}

int termite_metal_decode_runtime_reserve_gated_ffn_scratch(
    termite_metal_decode_runtime *runtime,
    size_t rows,
    size_t hidden_size,
    size_t intermediate_size
) {
    if (runtime == NULL) return -1;
    if (rows == 0 || hidden_size == 0 || intermediate_size == 0) return -2;
    const size_t hidden_bytes = rows * hidden_size * sizeof(float);
    const size_t intermediate_bytes = rows * intermediate_size * sizeof(float);
    size_t slots[9] = {
        TERMITE_METAL_GRAPH_PLAN_HOT_HIDDEN_SLOT_BASE + 0,
        TERMITE_METAL_GRAPH_PLAN_HOT_HIDDEN_SLOT_BASE + 1,
        TERMITE_METAL_GRAPH_PLAN_HOT_HIDDEN_SLOT_BASE + 2,
        TERMITE_METAL_GRAPH_PLAN_HOT_HIDDEN_SLOT_BASE + 3,
        TERMITE_METAL_GRAPH_PLAN_HOT_INTERMEDIATE_SLOT_BASE + 0,
        TERMITE_METAL_GRAPH_PLAN_HOT_INTERMEDIATE_SLOT_BASE + 1,
        TERMITE_METAL_GRAPH_PLAN_HOT_INTERMEDIATE_SLOT_BASE + 2,
        TERMITE_METAL_GRAPH_PLAN_HOT_INTERMEDIATE_SLOT_BASE + 3,
        TERMITE_METAL_GRAPH_PLAN_HOT_INTERMEDIATE_SLOT_BASE + 4,
    };
    size_t bytes[9] = {
        hidden_bytes,
        hidden_bytes,
        hidden_bytes,
        hidden_bytes,
        intermediate_bytes,
        intermediate_bytes,
        intermediate_bytes,
        intermediate_bytes,
        intermediate_bytes,
    };
    if (termite_metal_decode_runtime_reserve_graph_plan_slots(runtime, slots, bytes, 9) != 0) return -3;
    if (termite_metal_decode_runtime_ensure_hot_buffers(runtime, hidden_bytes, intermediate_bytes) != 0) return -4;
    return 0;
}

int termite_metal_decode_runtime_embed_absolute_position(
    termite_metal_decode_runtime *runtime,
    size_t token_id,
    size_t position_id,
    size_t hidden_size,
    float *output
) {
