static int termite_metal_encode_head_rms_rope_on_encoder(
    termite_metal_decode_runtime *runtime,
    id<MTLComputeCommandEncoder> encoder,
    id<MTLBuffer> input_buffer,
    size_t input_offset,
    size_t norm_slot,
    size_t total_heads,
    size_t head_dim,
    size_t rope_dim,
    size_t position,
    float theta,
    float freq_scale,
    float eps,
    float value_scale,
    uint32_t consecutive_pairs,
    size_t heads_per_row,
    id<MTLBuffer> output_buffer,
    size_t output_offset,
    int failure_code
) {
    if (runtime == NULL || encoder == nil || input_buffer == nil || output_buffer == nil) return failure_code;
    if (runtime->head_rms_rope_pipeline == nil) return failure_code;
    if (norm_slot >= TERMITE_METAL_RMS_NORM_SLOT_CAPACITY || total_heads == 0 || head_dim == 0 || rope_dim == 0 || heads_per_row == 0) return failure_code;
    if (runtime->rms_norm_slot_prepared[norm_slot] == 0 || runtime->rms_norm_hidden_sizes[norm_slot] != head_dim) return failure_code;
    if (total_heads > UINT32_MAX || head_dim > UINT32_MAX || rope_dim > UINT32_MAX || position > UINT32_MAX || heads_per_row > UINT32_MAX) return failure_code;
    size_t elems = 0;
    size_t bytes = 0;
    if (!termite_metal_size_mul(total_heads, head_dim, &elems) ||
        !termite_metal_size_mul(elems, sizeof(float), &bytes))
    {
        return failure_code;
    }
    if (termite_metal_decode_runtime_prepare_planned_compute_norm_accesses(
            runtime,
            input_buffer,
            input_offset,
            bytes,
            runtime->rms_norm_weight_buffers[norm_slot],
            output_buffer,
            output_offset,
            bytes,
            failure_code) != 0)
    {
        return failure_code;
    }
    termite_metal_head_rms_rope_params params = {
        .total_heads = (uint32_t)total_heads,
        .head_dim = (uint32_t)head_dim,
        .rope_dim = (uint32_t)rope_dim,
        .position = (uint32_t)position,
        .theta = theta,
        .freq_scale = freq_scale,
        .eps = eps,
        .value_scale = value_scale,
        .consecutive_pairs = consecutive_pairs,
        .heads_per_row = (uint32_t)heads_per_row,
    };
    [encoder setComputePipelineState:runtime->head_rms_rope_pipeline];
    [encoder setBuffer:input_buffer offset:input_offset atIndex:0];
    [encoder setBuffer:runtime->rms_norm_weight_buffers[norm_slot] offset:0 atIndex:1];
    [encoder setBuffer:output_buffer offset:output_offset atIndex:2];
    [encoder setBytes:&params length:sizeof(params) atIndex:3];
    [encoder setThreadgroupMemoryLength:256u * sizeof(float) atIndex:0];
    [encoder dispatchThreadgroups:MTLSizeMake(total_heads, 1, 1) threadsPerThreadgroup:MTLSizeMake(256, 1, 1)];
    return 0;
}

