            input_buffer,
            input_offset,
            input_bytes,
            runtime->linear_weight_buffers[slot],
            runtime->linear_bias_buffers[slot],
            output_buffer,
            output_offset,
            output_bytes,
            failure_code) != 0) return failure_code;
