        if (thread_width > out_dim && out_dim > 0) thread_width = out_dim;
        [encoder dispatchThreads:MTLSizeMake(out_dim, 1, 1) threadsPerThreadgroup:MTLSizeMake(thread_width, 1, 1)];
    }
    return 0;
}

