static int termite_metal_decode_runtime_encode_sample_topk_from_logits_buffer(
    termite_metal_decode_runtime *runtime,
    id<MTLCommandBuffer> command_buffer,
    id<MTLBuffer> logits_buffer,
    size_t out_dim,
    float temperature,
    size_t top_k,
    float top_p,
    float min_p,
    float repetition_penalty,
    float frequency_penalty,
    float presence_penalty,
    const uint32_t *penalty_token_ids,
    const uint32_t *penalty_counts,
    size_t penalty_count,
    uint32_t seed
) {
    if (runtime == NULL || command_buffer == nil || logits_buffer == nil) return -1;
    if (runtime->sample_topk_partials_pipeline == nil || runtime->sample_topk_reduce_pipeline == nil) return -2;
    if (out_dim == 0 || out_dim > UINT32_MAX || top_k == 0 || top_k > 64 || penalty_count > UINT32_MAX) return -3;

    const size_t block_size = 512;
    const size_t actual_top_k = top_k < out_dim ? top_k : out_dim;
    const size_t block_count = (out_dim + block_size - 1) / block_size;
    const size_t candidate_count = block_count * actual_top_k;
    if (candidate_count == 0 || candidate_count > UINT32_MAX) return -3;
    const size_t partial_bytes = candidate_count * sizeof(float);
    if (termite_metal_decode_runtime_ensure_sample_topk_buffers(runtime, partial_bytes) != 0) return -4;
    const size_t probs_bytes = actual_top_k * sizeof(float);
    if (termite_metal_decode_runtime_ensure_sample_probs_buffer(runtime, probs_bytes) != 0) return -4;
    if (runtime->token_capacity < sizeof(uint32_t) || runtime->token_buffer == nil || runtime->token_buffer.storageMode != MTLStorageModeShared) {
        id<MTLBuffer> token = [runtime->device newBufferWithLength:sizeof(uint32_t) options:MTLResourceStorageModeShared];
        if (token == nil) return -4;
        runtime->token_buffer = token;
        runtime->token_capacity = sizeof(uint32_t);
    }

    termite_metal_sample_logits_params params = {
        .out_dim = (uint32_t)out_dim,
        .temperature = temperature,
        .top_k = (uint32_t)actual_top_k,
        .top_p = top_p,
        .min_p = min_p,
        .repetition_penalty = repetition_penalty,
        .frequency_penalty = frequency_penalty,
        .presence_penalty = presence_penalty,
        .penalty_count = (uint32_t)penalty_count,
        .seed = seed,
    };
    termite_metal_topk_reduce_params reduce_params = {
        .candidate_count = (uint32_t)candidate_count,
        .top_k = (uint32_t)actual_top_k,
        .top_p = top_p,
        .min_p = min_p,
        .seed = seed,
    };
    termite_metal_penalty_entry *entries = NULL;
    if (penalty_count > 0) {
        entries = calloc(penalty_count, sizeof(termite_metal_penalty_entry));
        if (entries == NULL) return -10;
        for (size_t i = 0; i < penalty_count; ++i) {
            entries[i].token_id = penalty_token_ids[i];
            entries[i].count = penalty_counts[i];
        }
    }

    id<MTLComputeCommandEncoder> partial_encoder = termite_metal_tracked_compute_command_encoder(command_buffer);
    if (partial_encoder == nil) {
        if (entries != NULL) free(entries);
        return -7;
    }
    [partial_encoder setComputePipelineState:runtime->sample_topk_partials_pipeline];
    [partial_encoder setBuffer:logits_buffer offset:0 atIndex:0];
    [partial_encoder setBuffer:runtime->sample_topk_values_buffer offset:0 atIndex:1];
    [partial_encoder setBuffer:runtime->sample_topk_ids_buffer offset:0 atIndex:2];
    [partial_encoder setBytes:&params length:sizeof(params) atIndex:3];
    if (entries != NULL) {
        [partial_encoder setBytes:entries length:penalty_count * sizeof(termite_metal_penalty_entry) atIndex:4];
    } else {
        termite_metal_penalty_entry empty_penalty = { 0, 0 };
        [partial_encoder setBytes:&empty_penalty length:sizeof(empty_penalty) atIndex:4];
    }
    [partial_encoder dispatchThreads:MTLSizeMake(block_count, 1, 1) threadsPerThreadgroup:MTLSizeMake(1, 1, 1)];
    [partial_encoder endEncoding];

    id<MTLComputeCommandEncoder> reduce_encoder = termite_metal_tracked_compute_command_encoder(command_buffer);
    if (reduce_encoder == nil) {
        if (entries != NULL) free(entries);
        return -7;
    }
    [reduce_encoder setComputePipelineState:runtime->sample_topk_reduce_pipeline];
    [reduce_encoder setBuffer:runtime->sample_topk_values_buffer offset:0 atIndex:0];
    [reduce_encoder setBuffer:runtime->sample_topk_ids_buffer offset:0 atIndex:1];
    [reduce_encoder setBuffer:runtime->scratch_buffer offset:0 atIndex:2];
    [reduce_encoder setBuffer:runtime->token_buffer offset:0 atIndex:3];
    [reduce_encoder setBytes:&reduce_params length:sizeof(reduce_params) atIndex:4];
    [reduce_encoder dispatchThreads:MTLSizeMake(1, 1, 1) threadsPerThreadgroup:MTLSizeMake(1, 1, 1)];
    [reduce_encoder endEncoding];
    if (entries != NULL) free(entries);
    return 0;
}

