static int termite_metal_decode_runtime_encode_replace_attention_span_from_f32_key_slot(
    termite_metal_decode_runtime *runtime,
    id<MTLCommandBuffer> command_buffer,
    size_t slot,
    uint32_t format,
    const float *k,
    const float *v,
    size_t kv_tokens,
    size_t num_kv_heads,
    size_t head_dim,
    size_t key_row_bytes,
    size_t base_key_row_bytes,
    size_t v_row_stride,
    size_t position_offset
) {
    if (runtime == NULL || command_buffer == nil || k == NULL || v == NULL) return -1;
    if (kv_tokens == 0 || num_kv_heads == 0 || head_dim == 0 || key_row_bytes == 0 || base_key_row_bytes == 0 || v_row_stride == 0) return -2;
    if (kv_tokens > UINT32_MAX || num_kv_heads > UINT32_MAX || head_dim > UINT32_MAX || key_row_bytes > UINT32_MAX || base_key_row_bytes > UINT32_MAX) return -3;
    if (slot >= TERMITE_METAL_ATTENTION_SPAN_SLOT_CAPACITY) return -4;
    size_t suffix_start = 0;
    if (runtime->attention_span_slot_tokens[slot] > 0 &&
        runtime->attention_span_slot_tokens[slot] <= kv_tokens &&
        runtime->attention_span_slot_key_row_bytes[slot] == key_row_bytes &&
        runtime->attention_span_slot_v_row_stride[slot] == v_row_stride &&
        runtime->attention_span_slot_position_offset[slot] == position_offset)
    {
        suffix_start = runtime->attention_span_slot_tokens[slot];
        if (suffix_start == kv_tokens) return 0;
    }
    const size_t suffix_tokens = kv_tokens - suffix_start;
    const size_t encoded_bytes = kv_tokens * key_row_bytes;
    const size_t suffix_k_values = suffix_tokens * num_kv_heads * head_dim;
    const size_t k_bytes = suffix_k_values * sizeof(float);
    const size_t v_bytes = kv_tokens * v_row_stride * sizeof(float);
    const size_t suffix_v_bytes = suffix_tokens * v_row_stride * sizeof(float);
    if (termite_metal_decode_runtime_ensure_attention_span_slot_buffers(runtime, slot, encoded_bytes, v_bytes) != 0) return -5;

    id<MTLComputePipelineState> pipeline = nil;
    switch (format) {
        case 0u: pipeline = runtime->encode_polar4_key_pipeline; break;
        case 1u: pipeline = runtime->encode_turbo3_key_pipeline; break;
        default: return -7;
    }
    if (pipeline == nil) return -8;

    const float *k_suffix = k + suffix_start * num_kv_heads * head_dim;
    const float *v_suffix = v + suffix_start * v_row_stride;
    id<MTLBuffer> k_buffer = [runtime->device newBufferWithBytesNoCopy:(void *)k_suffix length:k_bytes options:MTLResourceStorageModeShared deallocator:nil];
    if (k_buffer == nil) k_buffer = [runtime->device newBufferWithBytes:k_suffix length:k_bytes options:MTLResourceStorageModeShared];
    id<MTLBuffer> v_staging = [runtime->device newBufferWithBytes:v_suffix length:suffix_v_bytes options:MTLResourceStorageModeShared];
    if (k_buffer == nil || v_staging == nil) return -9;

    termite_metal_encode_key_params params = {
        .rows = (uint32_t)suffix_tokens,
        .num_kv_heads = (uint32_t)num_kv_heads,
        .head_dim = (uint32_t)head_dim,
        .key_row_bytes = (uint32_t)key_row_bytes,
        .base_key_row_bytes = (uint32_t)base_key_row_bytes,
    };
    id<MTLBuffer> params_buffer = [runtime->device newBufferWithBytes:&params length:sizeof(params) options:MTLResourceStorageModeShared];
    if (params_buffer == nil) return -10;

    id<MTLComputeCommandEncoder> encoder = termite_metal_tracked_compute_command_encoder(command_buffer);
    if (encoder == nil) return -11;
    [encoder setComputePipelineState:pipeline];
    [encoder setBuffer:k_buffer offset:0 atIndex:0];
    [encoder setBuffer:runtime->attention_span_encoded_key_buffers[slot] offset:(suffix_start * key_row_bytes) atIndex:1];
    [encoder setBuffer:params_buffer offset:0 atIndex:2];
    const size_t residual_bytes = (num_kv_heads * 32u + 7u) / 8u;
    const size_t work_items = format == 0u ? suffix_tokens * base_key_row_bytes : suffix_tokens * (base_key_row_bytes + residual_bytes);
    [encoder dispatchThreads:MTLSizeMake(work_items, 1, 1) threadsPerThreadgroup:MTLSizeMake(termite_metal_thread_width(pipeline, work_items), 1, 1)];
    [encoder endEncoding];

    termite_metal_record_active_frame_blit_source(command_buffer, TERMITE_METAL_BLIT_SOURCE_ATTENTION_SPAN);
    id<MTLBlitCommandEncoder> blit = termite_metal_tracked_blit_command_encoder(command_buffer);
    if (blit == nil) return -12;
    [blit copyFromBuffer:v_staging sourceOffset:0 toBuffer:runtime->attention_span_v_buffers[slot] destinationOffset:(suffix_start * v_row_stride * sizeof(float)) size:suffix_v_bytes];
    [blit endEncoding];

    runtime->attention_span_slot_tokens[slot] = kv_tokens;
    runtime->attention_span_slot_key_row_bytes[slot] = key_row_bytes;
    runtime->attention_span_slot_v_row_stride[slot] = v_row_stride;
    runtime->attention_span_slot_position_offset[slot] = position_offset;
    if (slot == 0) {
        runtime->attention_span_encoded_key_buffer = runtime->attention_span_encoded_key_buffers[slot];
        runtime->attention_span_v_buffer = runtime->attention_span_v_buffers[slot];
        runtime->attention_span_encoded_key_capacity = runtime->attention_span_encoded_key_capacities[slot];
        runtime->attention_span_v_capacity = runtime->attention_span_v_capacities[slot];
        runtime->attention_span_tokens = kv_tokens;
        runtime->attention_span_key_row_bytes = key_row_bytes;
        runtime->attention_span_v_row_stride = v_row_stride;
        runtime->attention_span_position_offset = position_offset;
    }
    return 0;
}

static int termite_metal_decode_runtime_encode_replace_attention_span_from_f32_key_device_slot(
    termite_metal_decode_runtime *runtime,
    id<MTLCommandBuffer> command_buffer,
    size_t slot,
    uint32_t format,
    void *k_handle,
    size_t k_offset,
    void *v_handle,
    size_t v_offset,
    size_t kv_tokens,
    size_t num_kv_heads,
    size_t head_dim,
    size_t key_row_bytes,
    size_t base_key_row_bytes,
    size_t v_row_stride,
    size_t position_offset
) {
    if (runtime == NULL || command_buffer == nil || k_handle == NULL || v_handle == NULL) return -1;
    if (kv_tokens == 0 || num_kv_heads == 0 || head_dim == 0 || key_row_bytes == 0 || base_key_row_bytes == 0 || v_row_stride == 0) return -2;
    if (kv_tokens > UINT32_MAX || num_kv_heads > UINT32_MAX || head_dim > UINT32_MAX || key_row_bytes > UINT32_MAX || base_key_row_bytes > UINT32_MAX) return -3;
    if (slot >= TERMITE_METAL_ATTENTION_SPAN_SLOT_CAPACITY) return -4;
    size_t suffix_start = 0;
    if (runtime->attention_span_slot_tokens[slot] > 0 &&
        runtime->attention_span_slot_tokens[slot] <= kv_tokens &&
        runtime->attention_span_slot_key_row_bytes[slot] == key_row_bytes &&
        runtime->attention_span_slot_v_row_stride[slot] == v_row_stride &&
        runtime->attention_span_slot_position_offset[slot] == position_offset)
    {
        suffix_start = runtime->attention_span_slot_tokens[slot];
        if (suffix_start == kv_tokens) return 0;
    }
    const size_t suffix_tokens = kv_tokens - suffix_start;
    const size_t encoded_bytes = kv_tokens * key_row_bytes;
    const size_t v_bytes = kv_tokens * v_row_stride * sizeof(float);
    const size_t suffix_v_bytes = suffix_tokens * v_row_stride * sizeof(float);
    if (termite_metal_decode_runtime_ensure_attention_span_slot_buffers(runtime, slot, encoded_bytes, v_bytes) != 0) return -5;

    id<MTLBuffer> k_buffer = (__bridge id<MTLBuffer>)k_handle;
    id<MTLBuffer> v_buffer = (__bridge id<MTLBuffer>)v_handle;
    if (k_buffer == nil || v_buffer == nil) return -9;

    if (format == 2u) {
        uint32_t contiguous_block_table[1] = { 0u };
        BOOL encoder_owned = YES;
        id<MTLComputeCommandEncoder> encoder = termite_metal_scoped_compute_encoder_for(runtime, command_buffer, TERMITE_METAL_COMPUTE_SOURCE_ATTENTION, &encoder_owned);
        if (encoder == nil) return -12;
        const int rc = termite_metal_encode_paged_f32_kv_seed_on_encoder(
            runtime,
            encoder,
            slot,
            k_buffer,
            k_offset,
            v_buffer,
            v_offset,
            kv_tokens,
            suffix_tokens,
            num_kv_heads,
            head_dim,
            key_row_bytes,
            v_row_stride,
            position_offset,
            contiguous_block_table,
            1,
            kv_tokens,
            -12);
        termite_metal_end_scoped_compute_encoder(encoder, encoder_owned);
        if (rc != 0) return rc;
    } else if (format == 4u) {
        // int8 per-head path — keys are quantized into a (scale_f32 + int8[head_dim])
        // layout per head via threadgroup tree reduction; values are raw f32
        // (same as polar4/turbo3 layout so existing attention/gather paths
        // continue to work unchanged).
        id<MTLComputePipelineState> pipeline = runtime->encode_int8_per_head_pipeline;
        if (pipeline == nil) return -8;
        const size_t values_per_row = num_kv_heads * head_dim;
        // Threadgroup size = next power of 2 >= head_dim, capped at 256.
        size_t tg_size = 1u;
        while (tg_size < head_dim && tg_size < 256u) tg_size <<= 1u;
        if (tg_size < head_dim) return -13;
        termite_metal_encode_key_params params = {
            .rows = (uint32_t)suffix_tokens,
            .num_kv_heads = (uint32_t)num_kv_heads,
            .head_dim = (uint32_t)head_dim,
            .key_row_bytes = (uint32_t)key_row_bytes,
            .base_key_row_bytes = (uint32_t)base_key_row_bytes,
        };
        id<MTLBuffer> params_buffer = [runtime->device newBufferWithBytes:&params length:sizeof(params) options:MTLResourceStorageModeShared];
        if (params_buffer == nil) return -10;

        id<MTLComputeCommandEncoder> k_encoder = termite_metal_tracked_compute_command_encoder(command_buffer);
        if (k_encoder == nil) return -11;
        [k_encoder setComputePipelineState:pipeline];
        [k_encoder setBuffer:k_buffer offset:k_offset atIndex:0];
        [k_encoder setBuffer:runtime->attention_span_encoded_key_buffers[slot] offset:(suffix_start * key_row_bytes) atIndex:1];
        [k_encoder setBuffer:params_buffer offset:0 atIndex:2];
        [k_encoder dispatchThreads:MTLSizeMake(tg_size, suffix_tokens * num_kv_heads, 1)
              threadsPerThreadgroup:MTLSizeMake(tg_size, 1, 1)];
        [k_encoder endEncoding];

        // Values: raw f32 blit matching the polar4/turbo3 path.
        termite_metal_record_active_frame_blit_source(command_buffer, TERMITE_METAL_BLIT_SOURCE_ATTENTION_SPAN);
        id<MTLBlitCommandEncoder> blit = termite_metal_tracked_blit_command_encoder(command_buffer);
        if (blit == nil) return -12;
        [blit copyFromBuffer:v_buffer
                sourceOffset:v_offset
                    toBuffer:runtime->attention_span_v_buffers[slot]
           destinationOffset:(suffix_start * v_row_stride * sizeof(float))
                        size:suffix_v_bytes];
        [blit endEncoding];
    } else if (format == 3u) {
        // f16 path — dispatch the f32→half converter twice (once for keys,
        // once for values). Slot buffers are sized for `key_row_bytes` and
        // `v_row_stride * sizeof(half)` respectively; caller is responsible
        // for passing key_row_bytes = num_kv_heads*head_dim*sizeof(half).
        id<MTLComputePipelineState> pipeline = runtime->encode_f16_convert_pipeline;
        if (pipeline == nil) return -8;
        const size_t values_per_row = num_kv_heads * head_dim;
        termite_metal_encode_key_params params = {
            .rows = (uint32_t)suffix_tokens,
            .num_kv_heads = (uint32_t)num_kv_heads,
            .head_dim = (uint32_t)head_dim,
            .key_row_bytes = (uint32_t)key_row_bytes,
            .base_key_row_bytes = (uint32_t)base_key_row_bytes,
        };
        id<MTLBuffer> params_buffer = [runtime->device newBufferWithBytes:&params length:sizeof(params) options:MTLResourceStorageModeShared];
        if (params_buffer == nil) return -10;
        const size_t work_items = suffix_tokens * values_per_row;
        const size_t tg_width = termite_metal_thread_width(pipeline, work_items);

        id<MTLComputeCommandEncoder> k_encoder = termite_metal_tracked_compute_command_encoder(command_buffer);
        if (k_encoder == nil) return -11;
        [k_encoder setComputePipelineState:pipeline];
        [k_encoder setBuffer:k_buffer offset:k_offset atIndex:0];
        [k_encoder setBuffer:runtime->attention_span_encoded_key_buffers[slot] offset:(suffix_start * key_row_bytes) atIndex:1];
        [k_encoder setBuffer:params_buffer offset:0 atIndex:2];
        [k_encoder dispatchThreads:MTLSizeMake(work_items, 1, 1) threadsPerThreadgroup:MTLSizeMake(tg_width, 1, 1)];
        [k_encoder endEncoding];

        // Values: slot holds v_row_stride halfs per row. Suffix write offset
        // is in *half* units, i.e. v_row_stride * 2 bytes per row.
        id<MTLComputeCommandEncoder> v_encoder = termite_metal_tracked_compute_command_encoder(command_buffer);
        if (v_encoder == nil) return -11;
        [v_encoder setComputePipelineState:pipeline];
        [v_encoder setBuffer:v_buffer offset:v_offset atIndex:0];
        [v_encoder setBuffer:runtime->attention_span_v_buffers[slot] offset:(suffix_start * v_row_stride * sizeof(uint16_t)) atIndex:1];
        [v_encoder setBuffer:params_buffer offset:0 atIndex:2];
        [v_encoder dispatchThreads:MTLSizeMake(work_items, 1, 1) threadsPerThreadgroup:MTLSizeMake(tg_width, 1, 1)];
        [v_encoder endEncoding];
    } else {
        id<MTLComputePipelineState> pipeline = nil;
        switch (format) {
            case 0u: pipeline = runtime->encode_polar4_key_pipeline; break;
            case 1u: pipeline = runtime->encode_turbo3_key_pipeline; break;
            default: return -7;
        }
        if (pipeline == nil) return -8;

        termite_metal_encode_key_params params = {
            .rows = (uint32_t)suffix_tokens,
            .num_kv_heads = (uint32_t)num_kv_heads,
            .head_dim = (uint32_t)head_dim,
            .key_row_bytes = (uint32_t)key_row_bytes,
            .base_key_row_bytes = (uint32_t)base_key_row_bytes,
        };
        id<MTLBuffer> params_buffer = [runtime->device newBufferWithBytes:&params length:sizeof(params) options:MTLResourceStorageModeShared];
        if (params_buffer == nil) return -10;

        id<MTLComputeCommandEncoder> encoder = termite_metal_tracked_compute_command_encoder(command_buffer);
        if (encoder == nil) return -11;
        [encoder setComputePipelineState:pipeline];
        [encoder setBuffer:k_buffer offset:k_offset atIndex:0];
        [encoder setBuffer:runtime->attention_span_encoded_key_buffers[slot] offset:(suffix_start * key_row_bytes) atIndex:1];
        [encoder setBuffer:params_buffer offset:0 atIndex:2];
        const size_t residual_bytes = (num_kv_heads * 32u + 7u) / 8u;
        const size_t work_items = format == 0u ? suffix_tokens * base_key_row_bytes : suffix_tokens * (base_key_row_bytes + residual_bytes);
        [encoder dispatchThreads:MTLSizeMake(work_items, 1, 1) threadsPerThreadgroup:MTLSizeMake(termite_metal_thread_width(pipeline, work_items), 1, 1)];
        [encoder endEncoding];

        termite_metal_record_active_frame_blit_source(command_buffer, TERMITE_METAL_BLIT_SOURCE_ATTENTION_SPAN);
        id<MTLBlitCommandEncoder> blit = termite_metal_tracked_blit_command_encoder(command_buffer);
        if (blit == nil) return -12;
        [blit copyFromBuffer:v_buffer sourceOffset:v_offset toBuffer:runtime->attention_span_v_buffers[slot] destinationOffset:(suffix_start * v_row_stride * sizeof(float)) size:suffix_v_bytes];
        [blit endEncoding];
    }

    runtime->attention_span_slot_tokens[slot] = kv_tokens;
    runtime->attention_span_slot_key_row_bytes[slot] = key_row_bytes;
    runtime->attention_span_slot_v_row_stride[slot] = v_row_stride;
    runtime->attention_span_slot_position_offset[slot] = position_offset;
    if (slot == 0) {
        runtime->attention_span_encoded_key_buffer = runtime->attention_span_encoded_key_buffers[slot];
        runtime->attention_span_v_buffer = runtime->attention_span_v_buffers[slot];
        runtime->attention_span_encoded_key_capacity = runtime->attention_span_encoded_key_capacities[slot];
        runtime->attention_span_v_capacity = runtime->attention_span_v_capacities[slot];
        runtime->attention_span_tokens = kv_tokens;
        runtime->attention_span_key_row_bytes = key_row_bytes;
        runtime->attention_span_v_row_stride = v_row_stride;
        runtime->attention_span_position_offset = position_offset;
    }
    return 0;
}

