        if (command_buffer == nil) return -3;
        const int rc = termite_metal_decode_runtime_encode_paged_attention_slot(
            runtime,
            command_buffer,
            slot,
            format,
            q_buffer,
            q_offset,
            block_table,
            block_count,
            page_size,
            q_len,
            kv_tokens,
            num_heads,
            num_kv_heads,
            head_dim,
            key_row_bytes,
            base_key_row_bytes,
            query_position_offset,
            kv_position_offset,
            sliding_window,
            softcap,
            sinks,
            sink_count,
            output_buffer,
            output_offset
        );
        if (rc != 0) return rc;
        if (frame_active) return 0;
        [command_buffer commit];
        [command_buffer waitUntilCompleted];
        return command_buffer.status == MTLCommandBufferStatusCompleted ? 0 : -4;
    }
}

static int termite_metal_decode_runtime_encode_rms_norm_quantized_linear_slot(
    termite_metal_decode_runtime *runtime,
    id<MTLCommandBuffer> command_buffer,
    size_t norm_slot,
    const float *input,
    size_t hidden_size,
    float eps,
    size_t linear_slot,
    id<MTLComputePipelineState> linear_pipeline,
    id<MTLBuffer> linear_weight_buffer,
    size_t out_dim,
    size_t row_blocks,
    float *output
