    if (runtime == NULL || command_buffer == nil || input == NULL || output == NULL) return -1;
    if (runtime->rms_norm_pipeline == nil || linear_pipeline == nil || linear_weight_buffer == nil) return -2;
    if (hidden_size == 0 || hidden_size > UINT32_MAX || out_dim == 0 || out_dim > UINT32_MAX) return -3;
    if (termite_metal_decode_runtime_ensure_hot_buffers(runtime, hidden_size * sizeof(float), 0) != 0) return -4;
    @autoreleasepool {
        const size_t input_bytes = hidden_size * sizeof(float);
