    id<MTLBuffer> q_buffer,
    size_t q_offset,
    size_t kv_tokens,
    size_t num_heads,
    size_t num_kv_heads,
    size_t head_dim,
    size_t key_row_bytes,
    size_t base_key_row_bytes,
    size_t query_position,
    size_t kv_position_offset,
    size_t sliding_window,
    id<MTLBuffer> output_buffer,
    size_t output_offset
) {
