    if (kv_tokens == 0 || num_heads == 0 || num_kv_heads == 0 || head_dim == 0) return -2;
    if (num_heads > UINT32_MAX || num_kv_heads > UINT32_MAX || head_dim > UINT32_MAX || kv_tokens > UINT32_MAX) return -3;
    if (key_row_bytes > UINT32_MAX || base_key_row_bytes > UINT32_MAX || query_position > UINT32_MAX || kv_position_offset > UINT32_MAX || sliding_window > UINT32_MAX) return -4;
    if (slot >= TERMITE_METAL_ATTENTION_SPAN_SLOT_CAPACITY) return -5;
    if (runtime->attention_span_encoded_key_buffers[slot] == nil || runtime->attention_span_v_buffers[slot] == nil) return -6;
