    id<MTLComputePipelineState> pipeline = nil;
    switch (format) {
        case 0u: pipeline = runtime->polar4_attention_span_pipeline; break;
        case 1u: pipeline = runtime->turbo3_attention_span_pipeline; break;
        default: return -8;
    }
    if (pipeline == nil) return -9;
    termite_metal_attention_span_params params = {
        .kv_tokens = (uint32_t)kv_tokens,
        .num_heads = (uint32_t)num_heads,
        .num_kv_heads = (uint32_t)num_kv_heads,
        .head_dim = (uint32_t)head_dim,
        .key_row_bytes = (uint32_t)key_row_bytes,
        .base_key_row_bytes = (uint32_t)base_key_row_bytes,
        .query_position = (uint32_t)query_position,
        .kv_position_offset = (uint32_t)kv_position_offset,
        .sliding_window = (uint32_t)sliding_window,
        .v_row_stride = (uint32_t)runtime->attention_span_slot_v_row_stride[slot],
    };
    id<MTLBuffer> params_buffer = [runtime->device newBufferWithBytes:&params length:sizeof(params) options:MTLResourceStorageModeShared];
    if (params_buffer == nil) return -10;
    id<MTLComputeCommandEncoder> encoder = termite_metal_tracked_compute_command_encoder(command_buffer);
    if (encoder == nil) return -11;
    [encoder setComputePipelineState:pipeline];
    [encoder setBuffer:q_buffer offset:q_offset atIndex:0];
    [encoder setBuffer:runtime->attention_span_encoded_key_buffers[slot] offset:0 atIndex:1];
    [encoder setBuffer:runtime->attention_span_v_buffers[slot] offset:0 atIndex:2];
    [encoder setBuffer:output_buffer offset:output_offset atIndex:3];
    [encoder setBuffer:params_buffer offset:0 atIndex:4];
    [encoder dispatchThreads:MTLSizeMake(num_heads, 1, 1) threadsPerThreadgroup:MTLSizeMake(termite_metal_thread_width(pipeline, num_heads), 1, 1)];
    [encoder endEncoding];
    return 0;
}

static int termite_metal_apply_optional_norm(
    termite_metal_decode_runtime *runtime,
    size_t layer_norm_slot,
    size_t rms_norm_slot,
    const float *input,
    size_t hidden_size,
    float eps,
    float *output
) {
    if (layer_norm_slot != SIZE_MAX) {
        return termite_metal_decode_runtime_apply_layer_norm(
            runtime,
            layer_norm_slot,
            input,
            1,
            hidden_size,
            eps,
            output
        );
    }
    if (rms_norm_slot != SIZE_MAX) {
        return termite_metal_decode_runtime_apply_rms_norm(
            runtime,
            rms_norm_slot,
            input,
            hidden_size,
            eps,
            output
        );
    }
    if (input != output) {
        memcpy(output, input, hidden_size * sizeof(float));
    }
    return 0;
}

static NSUInteger termite_metal_thread_width(id<MTLComputePipelineState> pipeline, size_t dim) {
    NSUInteger thread_width = pipeline.maxTotalThreadsPerThreadgroup;
    if (thread_width == 0) thread_width = 64;
    if (dim > 0 && thread_width > dim) thread_width = dim;
    return thread_width;
}

static NSUInteger termite_metal_threadgroup_memory_16(NSUInteger bytes) {
    return (bytes + 15u) & ~(NSUInteger)15u;
}

static int termite_metal_decode_runtime_encode_attention_block_prefix(
