            [encoder setBuffer:params_buffer offset:0 atIndex:3];
            [encoder dispatchThreads:MTLSizeMake(hidden_size, 1, 1) threadsPerThreadgroup:MTLSizeMake(termite_metal_thread_width(runtime->add_pipeline, hidden_size), 1, 1)];
            [encoder endEncoding];
        }

