            [encoder setBuffer:ffn_input_buffer offset:ffn_input_offset atIndex:2];
            [encoder setBuffer:params_buffer offset:0 atIndex:3];
            [encoder dispatchThreads:MTLSizeMake(1, 1, 1) threadsPerThreadgroup:MTLSizeMake(1, 1, 1)];
            [encoder endEncoding];
        } else {
