int termite_metal_decode_runtime_apply_attention_dense_block(
    termite_metal_decode_runtime *runtime,
    uint32_t format,
    const float *q,
    const uint8_t *encoded_key,
    const float *v,
    size_t kv_tokens,
    size_t num_heads,
    size_t num_kv_heads,
    size_t head_dim,
    size_t key_row_bytes,
    size_t v_row_stride,
    size_t base_key_row_bytes,
    size_t query_position,
    size_t kv_position_offset,
    size_t sliding_window,
    size_t attention_linear_slot,
    size_t attention_pre_linear_rms_norm_slot,
    size_t attention_post_linear_rms_norm_slot,
    const float *residual,
    size_t attention_input_size,
    size_t hidden_size,
    float eps,
    size_t ffn_layer_norm_slot,
    size_t ffn_rms_norm_slot,
    size_t first_ffn_linear_slot,
    size_t second_ffn_linear_slot,
    size_t intermediate_size,
    uint32_t activation_kind,
    float *output
) {
    if (runtime == NULL || q == NULL || encoded_key == NULL || v == NULL || residual == NULL || output == NULL) return -1;
    @autoreleasepool {
        const size_t q_bytes = num_heads * head_dim * sizeof(float);
        const size_t hidden_bytes = hidden_size * sizeof(float);
        if (termite_metal_decode_runtime_ensure_direct_block_hidden_buffers(runtime, hidden_bytes) != 0) return -2;
        if (termite_metal_decode_runtime_ensure_direct_block_shared_buffer(runtime, 0, q_bytes) != 0) return -2;
        if (termite_metal_decode_runtime_ensure_direct_block_shared_buffer(runtime, 1, hidden_bytes) != 0) return -2;
        if (termite_metal_decode_runtime_ensure_direct_block_shared_buffer(runtime, 2, hidden_bytes) != 0) return -2;
        id<MTLBuffer> q_buffer = runtime->direct_block_shared_buffers[0];
        id<MTLBuffer> residual_buffer = runtime->direct_block_shared_buffers[1];
        id<MTLBuffer> attention_output_buffer = runtime->direct_block_hidden_buffers[0];
        id<MTLBuffer> attn_added_buffer = runtime->direct_block_hidden_buffers[1];
        id<MTLBuffer> ffn_input_buffer = runtime->direct_block_hidden_buffers[2];
        id<MTLBuffer> output_buffer = runtime->direct_block_shared_buffers[2];
        if (q_buffer == nil || residual_buffer == nil || attention_output_buffer == nil || attn_added_buffer == nil || ffn_input_buffer == nil || output_buffer == nil) return -2;
        memcpy(q_buffer.contents, q, q_bytes);
        memcpy(residual_buffer.contents, residual, hidden_bytes);
        id<MTLCommandBuffer> command_buffer = termite_metal_new_command_buffer(runtime->queue, __func__);
        if (command_buffer == nil) return -3;
        int rc = termite_metal_decode_runtime_encode_replace_attention_span(
            runtime,
            command_buffer,
            encoded_key,
            v,
            kv_tokens,
            key_row_bytes,
            v_row_stride,
            kv_position_offset
        );
        if (rc == 0) {
            rc = termite_metal_decode_runtime_encode_attention_span(
                runtime,
                command_buffer,
                format,
                q_buffer,
                0,
                kv_tokens,
                num_heads,
                num_kv_heads,
                head_dim,
                key_row_bytes,
                base_key_row_bytes,
                query_position,
                kv_position_offset,
                sliding_window,
                attention_output_buffer,
                0
            );
        }
        if (rc == 0) {
            rc = termite_metal_decode_runtime_encode_attention_block_prefix(
                runtime,
                command_buffer,
                attention_output_buffer,
                0,
                attention_pre_linear_rms_norm_slot,
                attention_linear_slot,
                attention_post_linear_rms_norm_slot,
                residual_buffer,
                0,
                attention_input_size,
                hidden_size,
                eps,
                ffn_layer_norm_slot,
                ffn_rms_norm_slot,
                attn_added_buffer,
                0,
                ffn_input_buffer,
                0
            );
        }
        if (rc == 0) {
            rc = termite_metal_decode_runtime_encode_dense_ffn_residual(
                runtime,
                command_buffer,
                first_ffn_linear_slot,
                second_ffn_linear_slot,
                ffn_input_buffer,
                attn_added_buffer,
                hidden_size,
                intermediate_size,
                activation_kind,
                output_buffer
            );
        }
        if (rc == 0) {
            [command_buffer commit];
            [command_buffer waitUntilCompleted];
            rc = command_buffer.status == MTLCommandBufferStatusCompleted ? 0 : -4;
            if (rc == 0) memcpy(output, output_buffer.contents, hidden_bytes);
        }
        return rc;
    }
}

