int termite_metal_decode_runtime_apply_attention_gated_block_q_slot(
    termite_metal_decode_runtime *runtime,
    uint32_t format,
    const float *attention_input,
    size_t q_linear_slot,
    const float *k,
    const float *v,
    size_t kv_tokens,
    size_t num_heads,
    size_t num_kv_heads,
    size_t head_dim,
    size_t key_row_bytes,
    size_t v_row_stride,
    size_t base_key_row_bytes,
    size_t query_position,
    size_t kv_position_offset,
    size_t sliding_window,
    size_t attention_linear_slot,
    size_t attention_pre_linear_rms_norm_slot,
    size_t attention_post_linear_rms_norm_slot,
    const float *residual,
    size_t hidden_size,
    size_t attention_input_size,
    float eps,
    size_t ffn_layer_norm_slot,
    size_t ffn_rms_norm_slot,
    size_t ffn_post_gate_rms_norm_slot,
    size_t gate_ffn_linear_slot,
    size_t up_ffn_linear_slot,
    size_t down_ffn_linear_slot,
    size_t intermediate_size,
    uint32_t activation_kind,
    size_t layer_index,
