    termite_metal_attention_gated_block_timing *timing
) {
    if (runtime == NULL || attention_input == NULL || k == NULL || v == NULL || residual == NULL || output == NULL) return -1;
    if (layer_index >= TERMITE_METAL_ATTENTION_SPAN_SLOT_CAPACITY) return -2;
    if (timing != NULL) memset(timing, 0, sizeof(*timing));
    if (q_linear_slot >= TERMITE_METAL_LINEAR_SLOT_CAPACITY) return -2;
    if (runtime->linear_pipeline == nil || runtime->linear_reduce_pipeline == nil) return -3;
    if (runtime->linear_slot_prepared[q_linear_slot] == 0) return -4;
    if (runtime->linear_in_dims[q_linear_slot] != hidden_size || runtime->linear_out_dims[q_linear_slot] != attention_input_size) return -5;
    if (hidden_size > UINT32_MAX || attention_input_size > UINT32_MAX) return -6;
    @autoreleasepool {
        const size_t input_bytes = hidden_size * sizeof(float);
        const size_t q_bytes = attention_input_size * sizeof(float);
        const size_t hidden_bytes = hidden_size * sizeof(float);
        if (termite_metal_decode_runtime_ensure_direct_block_hidden_buffers(runtime, hidden_bytes) != 0) return -7;
        if (termite_metal_decode_runtime_ensure_direct_block_q_buffer(runtime, q_bytes) != 0) return -8;
        if (termite_metal_decode_runtime_ensure_direct_block_shared_buffer(runtime, 0, input_bytes) != 0) return -9;
        if (termite_metal_decode_runtime_ensure_direct_block_shared_buffer(runtime, 1, hidden_bytes) != 0) return -9;
        if (termite_metal_decode_runtime_ensure_direct_block_shared_buffer(runtime, 2, hidden_bytes) != 0) return -9;
        id<MTLBuffer> input_buffer = runtime->direct_block_shared_buffers[0];
        id<MTLBuffer> residual_buffer = runtime->direct_block_shared_buffers[1];
        id<MTLBuffer> q_buffer = runtime->direct_block_q_buffer;
        id<MTLBuffer> attention_output_buffer = runtime->direct_block_hidden_buffers[0];
        id<MTLBuffer> attn_added_buffer = runtime->direct_block_hidden_buffers[1];
        id<MTLBuffer> ffn_input_buffer = runtime->direct_block_hidden_buffers[2];
        id<MTLBuffer> output_buffer = runtime->direct_block_shared_buffers[2];
        if (input_buffer == nil || residual_buffer == nil || q_buffer == nil || attention_output_buffer == nil || attn_added_buffer == nil || ffn_input_buffer == nil || output_buffer == nil) return -9;
        memcpy(input_buffer.contents, attention_input, input_bytes);
        memcpy(residual_buffer.contents, residual, hidden_bytes);

        termite_metal_apply_linear_params q_params = {
            .in_dim = (uint32_t)hidden_size,
            .out_dim = (uint32_t)attention_input_size,
        };

        id<MTLCommandBuffer> command_buffer = termite_metal_new_command_buffer(runtime->queue, __func__);
        if (command_buffer == nil) return -10;

        uint64_t stage_started_at = termite_metal_clock_monotonic_nanos();
        id<MTLComputeCommandEncoder> q_encoder = termite_metal_tracked_compute_command_encoder(command_buffer);
        if (q_encoder == nil) return -11;
        const BOOL use_q_reduce = attention_input_size >= 128;
        [q_encoder setComputePipelineState:(use_q_reduce ? runtime->linear_reduce_pipeline : runtime->linear_pipeline)];
        [q_encoder setBuffer:input_buffer offset:0 atIndex:0];
        [q_encoder setBuffer:runtime->linear_weight_buffers[q_linear_slot] offset:0 atIndex:1];
        [q_encoder setBuffer:runtime->linear_bias_buffers[q_linear_slot] offset:0 atIndex:2];
        [q_encoder setBuffer:q_buffer offset:0 atIndex:3];
        [q_encoder setBytes:&q_params length:sizeof(q_params) atIndex:4];
        if (use_q_reduce) {
            [q_encoder dispatchThreads:MTLSizeMake(attention_input_size * 32u, 1, 1) threadsPerThreadgroup:MTLSizeMake(32, 1, 1)];
        } else {
            NSUInteger q_thread_width = runtime->linear_pipeline.maxTotalThreadsPerThreadgroup;
            if (q_thread_width == 0) q_thread_width = 64;
            if (q_thread_width > attention_input_size && attention_input_size > 0) q_thread_width = attention_input_size;
            [q_encoder dispatchThreads:MTLSizeMake(attention_input_size, 1, 1) threadsPerThreadgroup:MTLSizeMake(q_thread_width, 1, 1)];
        }
        [q_encoder endEncoding];
        if (timing != NULL) timing->attention_span_nanos += termite_metal_clock_monotonic_nanos() - stage_started_at;

        stage_started_at = termite_metal_clock_monotonic_nanos();
        int rc = termite_metal_decode_runtime_encode_replace_attention_span_from_f32_key_slot(
            runtime,
            command_buffer,
            layer_index,
            format,
            k,
            v,
            kv_tokens,
            num_kv_heads,
            head_dim,
            key_row_bytes,
            base_key_row_bytes,
            v_row_stride,
            kv_position_offset
        );
        if (rc != 0 && timing != NULL) {
            timing->failure_stage = 1;
            timing->failure_code = rc;
        }
        if (timing != NULL) timing->replace_span_nanos += termite_metal_clock_monotonic_nanos() - stage_started_at;
        if (rc == 0) {
            stage_started_at = termite_metal_clock_monotonic_nanos();
            rc = termite_metal_decode_runtime_encode_attention_span_slot(
                runtime,
                command_buffer,
                layer_index,
                format,
                q_buffer,
                0,
                kv_tokens,
                num_heads,
                num_kv_heads,
                head_dim,
                key_row_bytes,
                base_key_row_bytes,
                query_position,
                kv_position_offset,
                sliding_window,
                attention_output_buffer,
                0
            );
            if (rc != 0 && timing != NULL) {
                timing->failure_stage = 2;
                timing->failure_code = rc;
            }
            if (timing != NULL) timing->attention_span_nanos += termite_metal_clock_monotonic_nanos() - stage_started_at;
        }
        if (rc == 0) {
            stage_started_at = termite_metal_clock_monotonic_nanos();
            rc = termite_metal_decode_runtime_encode_attention_block_prefix(
                runtime,
                command_buffer,
                attention_output_buffer,
                0,
                attention_pre_linear_rms_norm_slot,
                attention_linear_slot,
                attention_post_linear_rms_norm_slot,
                residual_buffer,
                0,
                attention_input_size,
                hidden_size,
                eps,
                ffn_layer_norm_slot,
                ffn_rms_norm_slot,
                attn_added_buffer,
                0,
                ffn_input_buffer,
                0
            );
            if (rc != 0 && timing != NULL) {
                timing->failure_stage = 3;
                timing->failure_code = rc;
            }
            if (timing != NULL) timing->attention_prefix_nanos += termite_metal_clock_monotonic_nanos() - stage_started_at;
        }
        if (rc == 0) {
            stage_started_at = termite_metal_clock_monotonic_nanos();
            rc = termite_metal_decode_runtime_encode_gated_ffn_residual(
                runtime,
                command_buffer,
                gate_ffn_linear_slot,
                up_ffn_linear_slot,
                down_ffn_linear_slot,
                ffn_post_gate_rms_norm_slot,
                ffn_input_buffer,
                0,
                attn_added_buffer,
                0,
                hidden_size,
                intermediate_size,
                activation_kind,
                output_buffer,
                0
            );
            if (rc != 0 && timing != NULL) {
                timing->failure_stage = 4;
                timing->failure_code = rc;
            }
            if (timing != NULL) timing->gated_ffn_residual_nanos += termite_metal_clock_monotonic_nanos() - stage_started_at;
        }
        if (rc == 0) {
            stage_started_at = termite_metal_clock_monotonic_nanos();
            [command_buffer commit];
            [command_buffer waitUntilCompleted];
            if (timing != NULL) timing->command_wait_nanos += termite_metal_clock_monotonic_nanos() - stage_started_at;
            rc = command_buffer.status == MTLCommandBufferStatusCompleted ? 0 : -12;
            if (rc == 0) {
                if (termite_metal_debug_direct_block_finite(layer_index)) {
                    termite_metal_debug_dump_buffer_finite(runtime, "direct-q", layer_index, q_buffer, 0, attention_input_size);
                    termite_metal_debug_dump_buffer_finite(runtime, "direct-attention", layer_index, attention_output_buffer, 0, attention_input_size);
                    termite_metal_debug_dump_buffer_finite(runtime, "direct-attn-added", layer_index, attn_added_buffer, 0, hidden_size);
                    termite_metal_debug_dump_buffer_finite(runtime, "direct-ffn-input", layer_index, ffn_input_buffer, 0, hidden_size);
                    termite_metal_debug_dump_buffer_finite(runtime, "direct-output", layer_index, output_buffer, 0, hidden_size);
                }
