    const uint32_t *block_table,
    size_t block_count,
    size_t page_size,
    size_t paged_key_row_bytes,
    size_t paged_base_key_row_bytes,
    size_t paged_v_row_stride,
    size_t suffix_tokens
) {
    if (runtime == NULL || input_handle == NULL || residual_handle == NULL || output_handle == NULL) return -1;
    if (rows == 0 || hidden_size == 0 || attention_input_size == 0 || kv_tokens == 0) return -2;
    if (runtime->active_frame_cb == nil) return -3;
    if (q_format != TERMITE_METAL_QUANT_FORMAT_Q8_0) return -4;
    if (!shares_kv && (k_format != TERMITE_METAL_QUANT_FORMAT_Q8_0 || v_format != TERMITE_METAL_QUANT_FORMAT_Q8_0)) return -5;
    if (suffix_tokens != 0 && suffix_tokens != rows) return -6;

    void *q_ready_handle = NULL;
    void *k_ready_handle = NULL;
    void *v_ready_handle = NULL;
    int rc = termite_metal_decode_runtime_apply_prefill_quantized_setup_device(
        runtime,
        shares_kv,
        q_format,
        k_format,
        v_format,
        q_slot,
        k_slot,
        v_slot,
        input_handle,
        input_offset,
        rows,
        hidden_size,
        attention_input_size,
        shares_kv ? 0 : kv_dim,
        q_norm_slot,
        shares_kv ? 0 : k_norm_slot,
        value_norm_present,
        value_norm_weight_handle,
        value_norm_weight_offset,
        num_heads,
        num_kv_heads,
        head_dim,
        rope_dim,
        position,
        theta,
        freq_scale,
        eps,
        query_value_scale,
        consecutive_pairs,
        setup_contract,
        1,
        &q_ready_handle,
        &k_ready_handle,
        &v_ready_handle
    );
    if (rc != 0) {
        if (timing != NULL) {
            timing->failure_stage = 1;
            timing->failure_code = rc;
        }
        return rc;
    }
    if (q_ready_handle == NULL) {
        if (runtime->active_planned_compute_encoder != nil) (void)termite_metal_decode_runtime_end_planned_compute_scope(runtime);
        if (timing != NULL) {
            timing->failure_stage = 1;
            timing->failure_code = -7;
        }
        return -7;
    }
    if (!shares_kv && (k_ready_handle == NULL || v_ready_handle == NULL)) {
        if (runtime->active_planned_compute_encoder != nil) (void)termite_metal_decode_runtime_end_planned_compute_scope(runtime);
        if (timing != NULL) {
            timing->failure_stage = 1;
            timing->failure_code = -8;
        }
        return -8;
    }

    rc = termite_metal_decode_runtime_apply_attention_f32_gated_block_q8_0_device_kv_device(
        runtime,
        q_ready_handle,
        0,
        shares_kv ? NULL : k_ready_handle,
        0,
        shares_kv ? NULL : v_ready_handle,
        0,
        rows,
        kv_tokens,
        num_heads,
        num_kv_heads,
        head_dim,
        query_position_offset,
        kv_position_offset,
        sliding_window,
        total_sequence_len,
        attention_linear_slot,
        attention_pre_linear_rms_norm_slot,
        attention_post_linear_rms_norm_slot,
        residual_handle,
        residual_offset,
        attention_input_size,
        hidden_size,
        eps,
        ffn_layer_norm_slot,
        ffn_rms_norm_slot,
        ffn_post_gate_rms_norm_slot,
        ffn_post_down_rms_norm_slot,
        gate_ffn_linear_slot,
        up_ffn_linear_slot,
        down_ffn_linear_slot,
        intermediate_size,
        activation_kind,
        layer_index,
        ple_handle,
        ple_offset,
        ple_gate_linear_slot,
        ple_proj_linear_slot,
        ple_post_norm_slot,
        ple_hidden_size,
        output_scale_present,
        output_scale,
        output_handle,
        output_offset,
        block_contract,
        timing,
        paged_slot,
        paged_format,
        block_table,
        block_count,
        page_size,
        paged_key_row_bytes,
        paged_base_key_row_bytes,
        paged_v_row_stride,
        suffix_tokens
    );
    if (rc != 0 && runtime->active_planned_compute_encoder != nil) {
        (void)termite_metal_decode_runtime_end_planned_compute_scope(runtime);
    }
    return rc;
}

int termite_metal_decode_runtime_ready(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return 0;
    return (runtime->device != nil && runtime->queue != nil && runtime->library != nil) ? 1 : 0;
}

int termite_metal_decode_runtime_reset_state(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return -1;
    runtime->attention_span_tokens = 0;
    runtime->attention_span_key_row_bytes = 0;
    runtime->attention_span_v_row_stride = 0;
    runtime->attention_span_position_offset = 0;
    // Attention-span slots back MetalKvStorage's persistent per-sequence KV
    // cache. Runtime resets clear transient graph/frame state only; sequence
    // release owns persistent KV slot invalidation.
    for (size_t slot = 0; slot < TERMITE_METAL_SCRATCH_POOL_CAPACITY; ++slot) {
        runtime->scratch_pool_in_use[slot] = 0;
        runtime->scratch_pool_pending_frame_release[slot] = 0;
    }
    for (size_t slot = 0; slot < TERMITE_METAL_GRAPH_PLAN_SLOT_CAPACITY; ++slot) {
        runtime->graph_plan_requested_bytes[slot] = 0;
    }
    runtime->graph_plan_active = 0;
    // Phase 4 — abandon any in-flight frame. If a frame was active (not
    // yet submitted) its encoded work is simply dropped. If it was
    // submitted but not waited on, we still release our reference;
    // Metal will complete it in the background.
    runtime->active_frame_cb = nil;
    runtime->submitted_frame_cb = nil;
    runtime->active_planned_compute_encoder = nil;
    termite_metal_decode_runtime_reset_planned_compute_ranges(runtime);
    runtime->active_frame_compute_encoder_count = 0;
    runtime->active_frame_blit_encoder_count = 0;
    runtime->active_frame_planned_compute_scope_count = 0;
    runtime->active_frame_planned_barrier_count = 0;
    runtime->submitted_frame_compute_encoder_count = 0;
    runtime->submitted_frame_blit_encoder_count = 0;
    runtime->submitted_frame_planned_compute_scope_count = 0;
    runtime->submitted_frame_planned_barrier_count = 0;
    runtime->active_planned_compute_source = TERMITE_METAL_COMPUTE_SOURCE_OTHER;
    runtime->active_planned_compute_region = TERMITE_METAL_COMPUTE_REGION_OTHER;
    memset(runtime->active_frame_compute_source_counts, 0, sizeof(runtime->active_frame_compute_source_counts));
    memset(runtime->submitted_frame_compute_source_counts, 0, sizeof(runtime->submitted_frame_compute_source_counts));
    memset(runtime->active_frame_compute_region_counts, 0, sizeof(runtime->active_frame_compute_region_counts));
    memset(runtime->submitted_frame_compute_region_counts, 0, sizeof(runtime->submitted_frame_compute_region_counts));
    memset(runtime->active_frame_compute_region_source_counts, 0, sizeof(runtime->active_frame_compute_region_source_counts));
    memset(runtime->submitted_frame_compute_region_source_counts, 0, sizeof(runtime->submitted_frame_compute_region_source_counts));
    memset(runtime->active_frame_planned_command_op_kind_counts, 0, sizeof(runtime->active_frame_planned_command_op_kind_counts));
    memset(runtime->submitted_frame_planned_command_op_kind_counts, 0, sizeof(runtime->submitted_frame_planned_command_op_kind_counts));
    memset(runtime->active_frame_planned_command_operator_counts, 0, sizeof(runtime->active_frame_planned_command_operator_counts));
    memset(runtime->submitted_frame_planned_command_operator_counts, 0, sizeof(runtime->submitted_frame_planned_command_operator_counts));
    memset(runtime->active_frame_planned_command_quant_dispatch_counts, 0, sizeof(runtime->active_frame_planned_command_quant_dispatch_counts));
    memset(runtime->submitted_frame_planned_command_quant_dispatch_counts, 0, sizeof(runtime->submitted_frame_planned_command_quant_dispatch_counts));
    memset(runtime->active_frame_blit_source_counts, 0, sizeof(runtime->active_frame_blit_source_counts));
    memset(runtime->submitted_frame_blit_source_counts, 0, sizeof(runtime->submitted_frame_blit_source_counts));
    if (termite_metal_active_encoder_runtime == runtime) {
        termite_metal_active_encoder_runtime = NULL;
    }
    termite_metal_decode_runtime_clear_frame_resources(&runtime->active_frame_retained_resources);
    termite_metal_decode_runtime_clear_frame_resources(&runtime->submitted_frame_retained_resources);
    runtime->frame_cb_count = 0;
    return 0;
}

// Phase 4 — frame API. See struct declaration for semantics. When a
// frame is active, internal `encode_*` helpers and public
// `apply_*_device` entrypoints that opt in will encode into the active
// CB and skip the per-call commit/wait. This collapses the ~96
// command-buffer submissions per Gemma token (3 CBs × 32 layers) down
// to a single CB per layer (first pass) or per token (final pass).
static void termite_metal_decode_runtime_clear_frame_resources(CFMutableArrayRef *resources) {
    if (resources == NULL || *resources == NULL) return;
    CFRelease(*resources);
    *resources = NULL;
}

static void termite_metal_decode_runtime_finish_frame_scratch_releases(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return;
    for (size_t slot = 0; slot < TERMITE_METAL_SCRATCH_POOL_CAPACITY; ++slot) {
        if (runtime->scratch_pool_pending_frame_release[slot] == 0) continue;
        runtime->scratch_pool_pending_frame_release[slot] = 0;
        runtime->scratch_pool_in_use[slot] = 0;
    }
}

static bool termite_metal_decode_runtime_active_frame_empty(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL || runtime->active_frame_cb == nil) return false;
    return runtime->active_frame_compute_encoder_count == 0 &&
        runtime->active_frame_blit_encoder_count == 0 &&
        runtime->active_frame_planned_compute_scope_count == 0 &&
        runtime->active_frame_planned_barrier_count == 0 &&
        runtime->active_frame_planned_command_op_count == 0 &&
        runtime->active_planned_compute_encoder == nil;
}

static int termite_metal_decode_runtime_retain_frame_resource(termite_metal_decode_runtime *runtime, id resource) {
    if (runtime == NULL || resource == nil) return -1;
    CFMutableArrayRef *resources = NULL;
    if (runtime->active_frame_cb != nil) {
        resources = &runtime->active_frame_retained_resources;
    } else if (runtime->submitted_frame_cb != nil) {
        resources = &runtime->submitted_frame_retained_resources;
    } else {
        return 0;
    }
    if (*resources == NULL) {
        *resources = CFArrayCreateMutable(kCFAllocatorDefault, 0, &kCFTypeArrayCallBacks);
        if (*resources == NULL) return -2;
    }
    CFArrayAppendValue(*resources, (__bridge const void *)resource);
    return 0;
}

int termite_metal_decode_runtime_retain_active_frame_buffer(termite_metal_decode_runtime *runtime, void *handle) {
    if (runtime == NULL || handle == NULL) return -1;
    if (runtime->active_frame_cb == nil) return 0;
    id<MTLBuffer> buffer = (__bridge id<MTLBuffer>)handle;
    if (buffer == nil) return -2;
    return termite_metal_decode_runtime_retain_frame_resource(runtime, buffer);
}

int termite_metal_decode_runtime_begin_frame(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return -1;
    if (runtime->queue == nil) return -2;
    if (runtime->active_frame_cb != nil) return -3;
    if (runtime->submitted_frame_cb != nil) return -4;
    termite_metal_decode_runtime_finish_frame_scratch_releases(runtime);
    @autoreleasepool {
        id<MTLCommandBuffer> cb = termite_metal_new_command_buffer(runtime->queue, __func__);
        if (cb == nil) return -5;
        cb.label = @"termite_metal_decode_runtime_frame";
        runtime->active_frame_cb = cb;
        runtime->active_frame_compute_encoder_count = 0;
        runtime->active_frame_blit_encoder_count = 0;
        runtime->active_frame_planned_compute_scope_count = 0;
        runtime->active_frame_planned_barrier_count = 0;
        runtime->active_frame_planned_command_op_count = 0;
        runtime->active_frame_host_staging_offset = 0;
        runtime->active_frame_host_staging_retained_buffer = nil;
        runtime->active_planned_compute_encoder = nil;
        termite_metal_decode_runtime_reset_planned_compute_ranges(runtime);
        runtime->active_planned_compute_scope_closed_for_encoder_transition = false;
        runtime->active_planned_compute_source = TERMITE_METAL_COMPUTE_SOURCE_OTHER;
        runtime->active_planned_compute_region = TERMITE_METAL_COMPUTE_REGION_OTHER;
        runtime->active_compute_region = TERMITE_METAL_COMPUTE_REGION_OTHER;
        memset(runtime->active_frame_compute_source_counts, 0, sizeof(runtime->active_frame_compute_source_counts));
        memset(runtime->active_frame_compute_region_counts, 0, sizeof(runtime->active_frame_compute_region_counts));
        memset(runtime->active_frame_compute_region_source_counts, 0, sizeof(runtime->active_frame_compute_region_source_counts));
        memset(runtime->active_frame_planned_command_op_kind_counts, 0, sizeof(runtime->active_frame_planned_command_op_kind_counts));
        memset(runtime->active_frame_planned_command_operator_counts, 0, sizeof(runtime->active_frame_planned_command_operator_counts));
        memset(runtime->active_frame_planned_command_quant_dispatch_counts, 0, sizeof(runtime->active_frame_planned_command_quant_dispatch_counts));
        memset(runtime->active_frame_blit_source_counts, 0, sizeof(runtime->active_frame_blit_source_counts));
        termite_metal_active_encoder_runtime = runtime;
        if (termite_metal_trace_frame_lifecycle_enabled()) {
            fprintf(stderr, "metal_frame_lifecycle: begin\n");
        }
        return 0;
    }
}

int termite_metal_decode_runtime_submit_frame(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return -1;
    if (runtime->active_frame_cb == nil) return -2;
    if (runtime->submitted_frame_cb != nil) return -3;
    id<MTLCommandBuffer> cb = runtime->active_frame_cb;
    if (runtime->active_planned_compute_encoder != nil) {
        termite_metal_decode_runtime_close_planned_compute_encoder_for_transition(runtime);
    }
    if (termite_metal_trace_frame_lifecycle_enabled()) {
        fprintf(
            stderr,
            "metal_frame_lifecycle: submit compute=%llu blit=%llu planned_scopes=%llu planned_barriers=%llu\n",
            (unsigned long long)runtime->active_frame_compute_encoder_count,
            (unsigned long long)runtime->active_frame_blit_encoder_count,
            (unsigned long long)runtime->active_frame_planned_compute_scope_count,
            (unsigned long long)runtime->active_frame_planned_barrier_count
        );
    }
    runtime->last_frame_gpu_nanos = 0;
    [cb commit];
    runtime->submitted_frame_cb = cb;
    runtime->active_frame_cb = nil;
    runtime->submitted_frame_compute_encoder_count = runtime->active_frame_compute_encoder_count;
    runtime->submitted_frame_blit_encoder_count = runtime->active_frame_blit_encoder_count;
    runtime->submitted_frame_planned_compute_scope_count = runtime->active_frame_planned_compute_scope_count;
    runtime->submitted_frame_planned_barrier_count = runtime->active_frame_planned_barrier_count;
    runtime->submitted_frame_mps_dense_linear_count = runtime->active_frame_mps_dense_linear_count;
    runtime->submitted_frame_planned_command_op_count = runtime->active_frame_planned_command_op_count;
    memcpy(runtime->submitted_frame_compute_source_counts, runtime->active_frame_compute_source_counts, sizeof(runtime->submitted_frame_compute_source_counts));
    memcpy(runtime->submitted_frame_compute_region_counts, runtime->active_frame_compute_region_counts, sizeof(runtime->submitted_frame_compute_region_counts));
    memcpy(runtime->submitted_frame_compute_region_source_counts, runtime->active_frame_compute_region_source_counts, sizeof(runtime->submitted_frame_compute_region_source_counts));
    memcpy(runtime->submitted_frame_planned_command_op_kind_counts, runtime->active_frame_planned_command_op_kind_counts, sizeof(runtime->submitted_frame_planned_command_op_kind_counts));
    memcpy(runtime->submitted_frame_planned_command_operator_counts, runtime->active_frame_planned_command_operator_counts, sizeof(runtime->submitted_frame_planned_command_operator_counts));
    memcpy(runtime->submitted_frame_planned_command_quant_dispatch_counts, runtime->active_frame_planned_command_quant_dispatch_counts, sizeof(runtime->submitted_frame_planned_command_quant_dispatch_counts));
    memcpy(runtime->submitted_frame_blit_source_counts, runtime->active_frame_blit_source_counts, sizeof(runtime->submitted_frame_blit_source_counts));
    runtime->active_frame_compute_encoder_count = 0;
    runtime->active_frame_blit_encoder_count = 0;
    runtime->active_frame_planned_compute_scope_count = 0;
    runtime->active_frame_planned_barrier_count = 0;
    runtime->active_frame_mps_dense_linear_count = 0;
    runtime->active_frame_planned_command_op_count = 0;
    runtime->active_planned_compute_encoder = nil;
    termite_metal_decode_runtime_reset_planned_compute_ranges(runtime);
    runtime->active_planned_compute_scope_closed_for_encoder_transition = false;
    runtime->active_planned_compute_source = TERMITE_METAL_COMPUTE_SOURCE_OTHER;
    runtime->active_planned_compute_region = TERMITE_METAL_COMPUTE_REGION_OTHER;
    runtime->active_compute_region = TERMITE_METAL_COMPUTE_REGION_OTHER;
    memset(runtime->active_frame_compute_source_counts, 0, sizeof(runtime->active_frame_compute_source_counts));
    memset(runtime->active_frame_compute_region_counts, 0, sizeof(runtime->active_frame_compute_region_counts));
    memset(runtime->active_frame_compute_region_source_counts, 0, sizeof(runtime->active_frame_compute_region_source_counts));
    memset(runtime->active_frame_planned_command_op_kind_counts, 0, sizeof(runtime->active_frame_planned_command_op_kind_counts));
    memset(runtime->active_frame_planned_command_operator_counts, 0, sizeof(runtime->active_frame_planned_command_operator_counts));
    memset(runtime->active_frame_planned_command_quant_dispatch_counts, 0, sizeof(runtime->active_frame_planned_command_quant_dispatch_counts));
    memset(runtime->active_frame_blit_source_counts, 0, sizeof(runtime->active_frame_blit_source_counts));
    if (termite_metal_active_encoder_runtime == runtime) {
        termite_metal_active_encoder_runtime = NULL;
    }
    runtime->submitted_frame_retained_resources = runtime->active_frame_retained_resources;
    runtime->active_frame_retained_resources = NULL;
    runtime->frame_cb_count += 1;
    return 0;
}

int termite_metal_decode_runtime_cancel_frame(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return -1;
    if (runtime->active_frame_cb == nil) return -2;
    if (termite_metal_trace_frame_lifecycle_enabled()) {
        fprintf(
            stderr,
            "metal_frame_lifecycle: cancel compute=%llu blit=%llu planned_scopes=%llu planned_barriers=%llu\n",
            (unsigned long long)runtime->active_frame_compute_encoder_count,
            (unsigned long long)runtime->active_frame_blit_encoder_count,
            (unsigned long long)runtime->active_frame_planned_compute_scope_count,
            (unsigned long long)runtime->active_frame_planned_barrier_count
        );
    }
    if (runtime->active_planned_compute_encoder != nil) {
        [runtime->active_planned_compute_encoder endEncoding];
        runtime->active_planned_compute_encoder = nil;
    }
    termite_metal_decode_runtime_reset_planned_compute_ranges(runtime);
    runtime->active_planned_compute_scope_closed_for_encoder_transition = false;
    runtime->active_frame_cb = nil;
    runtime->active_frame_compute_encoder_count = 0;
    runtime->active_frame_blit_encoder_count = 0;
    runtime->active_frame_planned_compute_scope_count = 0;
    runtime->active_frame_planned_barrier_count = 0;
    runtime->active_frame_mps_dense_linear_count = 0;
    runtime->active_frame_planned_command_op_count = 0;
    runtime->active_frame_host_staging_offset = 0;
    runtime->active_frame_host_staging_retained_buffer = nil;
    runtime->active_planned_compute_source = TERMITE_METAL_COMPUTE_SOURCE_OTHER;
    runtime->active_planned_compute_region = TERMITE_METAL_COMPUTE_REGION_OTHER;
    runtime->active_compute_region = TERMITE_METAL_COMPUTE_REGION_OTHER;
    memset(runtime->active_frame_compute_source_counts, 0, sizeof(runtime->active_frame_compute_source_counts));
    memset(runtime->active_frame_compute_region_counts, 0, sizeof(runtime->active_frame_compute_region_counts));
    memset(runtime->active_frame_compute_region_source_counts, 0, sizeof(runtime->active_frame_compute_region_source_counts));
    memset(runtime->active_frame_planned_command_op_kind_counts, 0, sizeof(runtime->active_frame_planned_command_op_kind_counts));
    memset(runtime->active_frame_planned_command_operator_counts, 0, sizeof(runtime->active_frame_planned_command_operator_counts));
    memset(runtime->active_frame_planned_command_quant_dispatch_counts, 0, sizeof(runtime->active_frame_planned_command_quant_dispatch_counts));
    memset(runtime->active_frame_blit_source_counts, 0, sizeof(runtime->active_frame_blit_source_counts));
    if (termite_metal_active_encoder_runtime == runtime) {
        termite_metal_active_encoder_runtime = NULL;
    }
    termite_metal_decode_runtime_clear_frame_resources(&runtime->active_frame_retained_resources);
    termite_metal_decode_runtime_finish_frame_scratch_releases(runtime);
    return 0;
}

int termite_metal_decode_runtime_wait_frame(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return -1;
    id<MTLCommandBuffer> cb = runtime->submitted_frame_cb;
    if (cb == nil) return -2;
    [cb waitUntilCompleted];
    int status_code = (cb.status == MTLCommandBufferStatusCompleted) ? 0 : -3;
    runtime->last_frame_gpu_nanos = status_code == 0 ? termite_metal_command_buffer_gpu_elapsed_nanos(cb) : 0;
    runtime->last_frame_compute_encoder_count = runtime->submitted_frame_compute_encoder_count;
    runtime->last_frame_blit_encoder_count = runtime->submitted_frame_blit_encoder_count;
    runtime->last_frame_planned_compute_scope_count = runtime->submitted_frame_planned_compute_scope_count;
    runtime->last_frame_planned_barrier_count = runtime->submitted_frame_planned_barrier_count;
    runtime->last_frame_mps_dense_linear_count = runtime->submitted_frame_mps_dense_linear_count;
    runtime->last_frame_planned_command_op_count = runtime->submitted_frame_planned_command_op_count;
    memcpy(runtime->last_frame_compute_source_counts, runtime->submitted_frame_compute_source_counts, sizeof(runtime->last_frame_compute_source_counts));
    memcpy(runtime->last_frame_compute_region_counts, runtime->submitted_frame_compute_region_counts, sizeof(runtime->last_frame_compute_region_counts));
    memcpy(runtime->last_frame_compute_region_source_counts, runtime->submitted_frame_compute_region_source_counts, sizeof(runtime->last_frame_compute_region_source_counts));
    memcpy(runtime->last_frame_planned_command_op_kind_counts, runtime->submitted_frame_planned_command_op_kind_counts, sizeof(runtime->last_frame_planned_command_op_kind_counts));
    memcpy(runtime->last_frame_planned_command_operator_counts, runtime->submitted_frame_planned_command_operator_counts, sizeof(runtime->last_frame_planned_command_operator_counts));
    memcpy(runtime->last_frame_planned_command_quant_dispatch_counts, runtime->submitted_frame_planned_command_quant_dispatch_counts, sizeof(runtime->last_frame_planned_command_quant_dispatch_counts));
    memcpy(runtime->last_frame_blit_source_counts, runtime->submitted_frame_blit_source_counts, sizeof(runtime->last_frame_blit_source_counts));
    termite_metal_maybe_trace_last_frame(runtime);
    runtime->submitted_frame_compute_encoder_count = 0;
    runtime->submitted_frame_blit_encoder_count = 0;
    runtime->submitted_frame_planned_compute_scope_count = 0;
    runtime->submitted_frame_planned_barrier_count = 0;
    runtime->submitted_frame_mps_dense_linear_count = 0;
    runtime->submitted_frame_planned_command_op_count = 0;
    memset(runtime->submitted_frame_compute_source_counts, 0, sizeof(runtime->submitted_frame_compute_source_counts));
    memset(runtime->submitted_frame_compute_region_counts, 0, sizeof(runtime->submitted_frame_compute_region_counts));
    memset(runtime->submitted_frame_compute_region_source_counts, 0, sizeof(runtime->submitted_frame_compute_region_source_counts));
    memset(runtime->submitted_frame_planned_command_op_kind_counts, 0, sizeof(runtime->submitted_frame_planned_command_op_kind_counts));
    memset(runtime->submitted_frame_planned_command_operator_counts, 0, sizeof(runtime->submitted_frame_planned_command_operator_counts));
    memset(runtime->submitted_frame_planned_command_quant_dispatch_counts, 0, sizeof(runtime->submitted_frame_planned_command_quant_dispatch_counts));
    memset(runtime->submitted_frame_blit_source_counts, 0, sizeof(runtime->submitted_frame_blit_source_counts));
    if (status_code != 0) {
        termite_metal_log_command_buffer_failure(cb, __func__);
    }
    runtime->submitted_frame_cb = nil;
    termite_metal_decode_runtime_clear_frame_resources(&runtime->submitted_frame_retained_resources);
    runtime->active_frame_host_staging_offset = 0;
    runtime->active_frame_host_staging_retained_buffer = nil;
    termite_metal_decode_runtime_finish_frame_scratch_releases(runtime);
    return status_code;
}

int termite_metal_decode_runtime_flush_active_frame(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return -1;
    const bool had_active_frame = (runtime->active_frame_cb != nil);
    if (termite_metal_trace_frame_lifecycle_enabled()) {
        fprintf(
            stderr,
            "metal_frame_lifecycle: flush had_active=%d submitted=%d compute=%llu blit=%llu planned_scopes=%llu planned_barriers=%llu\n",
            had_active_frame ? 1 : 0,
            runtime->submitted_frame_cb != nil ? 1 : 0,
            (unsigned long long)runtime->active_frame_compute_encoder_count,
            (unsigned long long)runtime->active_frame_blit_encoder_count,
            (unsigned long long)runtime->active_frame_planned_compute_scope_count,
            (unsigned long long)runtime->active_frame_planned_barrier_count
        );
    }
    if (runtime->submitted_frame_cb != nil) {
        int wait_rc = termite_metal_decode_runtime_wait_frame(runtime);
        if (wait_rc != 0) return wait_rc;
    }
    if (!had_active_frame) return 0;
    if (termite_metal_decode_runtime_active_frame_empty(runtime)) {
        int cancel_rc = termite_metal_decode_runtime_cancel_frame(runtime);
        if (cancel_rc != 0) return cancel_rc;
        return termite_metal_decode_runtime_begin_frame(runtime);
    }
    int submit_rc = termite_metal_decode_runtime_submit_frame(runtime);
    if (submit_rc != 0) return submit_rc;
    int wait_rc = termite_metal_decode_runtime_wait_frame(runtime);
    if (wait_rc != 0) return wait_rc;
    return termite_metal_decode_runtime_begin_frame(runtime);
}

int termite_metal_decode_runtime_active_frame_has_work(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL || runtime->active_frame_cb == nil) return 0;
    return termite_metal_decode_runtime_active_frame_empty(runtime) ? 0 : 1;
}

int termite_metal_decode_runtime_has_active_frame(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return 0;
    return runtime->active_frame_cb != nil ? 1 : 0;
}

int termite_metal_decode_runtime_push_compute_region(termite_metal_decode_runtime *runtime, size_t region, size_t *previous_out) {
    if (runtime == NULL || previous_out == NULL) return -1;
    if (region >= TERMITE_METAL_COMPUTE_REGION_COUNTER_COUNT) return -2;
    *previous_out = termite_metal_enter_compute_region(runtime, region);
    return 0;
}

int termite_metal_decode_runtime_pop_compute_region(termite_metal_decode_runtime *runtime, size_t previous) {
    if (runtime == NULL) return -1;
    termite_metal_restore_compute_region(runtime, previous);
    return 0;
}

uint64_t termite_metal_decode_runtime_frame_cb_count(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return 0;
    return runtime->frame_cb_count;
}

uint64_t termite_metal_decode_runtime_last_frame_gpu_nanos(termite_metal_decode_runtime *runtime) {
    if (runtime == NULL) return 0;
    return runtime->last_frame_gpu_nanos;
}

int termite_metal_decode_runtime_memory_snapshot(
    termite_metal_decode_runtime *runtime,
    termite_metal_decode_runtime_memory_stats *snapshot
) {
    if (snapshot == NULL) return -1;
    memset(snapshot, 0, sizeof(*snapshot));
    if (runtime == NULL) return -2;

    termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->token_embedding_table_buffer, &snapshot->embedding_bytes);
    termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->position_embedding_table_buffer, &snapshot->embedding_bytes);
    for (size_t slot = 0; slot < TERMITE_METAL_GENERIC_EMBEDDING_CACHE_CAPACITY; ++slot) {
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->generic_embedding_cache[slot].buffer, &snapshot->embedding_bytes);
    }

    for (size_t slot = 0; slot < TERMITE_METAL_LAYER_NORM_SLOT_CAPACITY; ++slot) {
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->layer_norm_weight_buffers[slot], &snapshot->norm_bytes);
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->layer_norm_bias_buffers[slot], &snapshot->norm_bytes);
    }
    for (size_t slot = 0; slot < TERMITE_METAL_RMS_NORM_SLOT_CAPACITY; ++slot) {
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->rms_norm_weight_buffers[slot], &snapshot->norm_bytes);
    }

    for (size_t slot = 0; slot < TERMITE_METAL_LINEAR_SLOT_CAPACITY; ++slot) {
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->linear_weight_buffers[slot], &snapshot->dense_linear_bytes);
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->linear_bias_buffers[slot], &snapshot->dense_linear_bytes);
        if (runtime->linear_weight_buffers[slot] != nil) {
            snapshot->dense_linear_buffer_count += 1;
            const uint64_t bytes = (uint64_t)runtime->linear_weight_buffers[slot].length;
            snapshot->dense_linear_weight_bytes += bytes;
            if (runtime->linear_weight_dtypes[slot] == TERMITE_METAL_DENSE_LINEAR_DTYPE_BF16) {
                snapshot->dense_linear_bf16_weight_bytes += bytes;
                snapshot->dense_linear_bf16_slots += 1;
            } else {
                snapshot->dense_linear_f32_weight_bytes += bytes;
                snapshot->dense_linear_f32_slots += 1;
            }
            if (bytes > snapshot->dense_linear_largest_bytes) {
                snapshot->dense_linear_largest_slot = (uint64_t)slot;
                snapshot->dense_linear_largest_bytes = bytes;
                snapshot->dense_linear_largest_in_dim = (uint64_t)runtime->linear_in_dims[slot];
                snapshot->dense_linear_largest_out_dim = (uint64_t)runtime->linear_out_dims[slot];
            }
        }
        if (runtime->linear_bias_buffers[slot] != nil) {
            snapshot->dense_linear_buffer_count += 1;
        }
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->dense_qkv_packed_weight_buffers[slot], &snapshot->dense_linear_bytes);
        if (runtime->dense_qkv_packed_weight_buffers[slot] != nil) {
            snapshot->dense_linear_buffer_count += 1;
        }
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->dense_pair_packed_weight_buffers[slot], &snapshot->dense_linear_bytes);
        if (runtime->dense_pair_packed_weight_buffers[slot] != nil) {
            snapshot->dense_linear_buffer_count += 1;
        }
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->quant_linear_weight_buffers[slot], &snapshot->quant_linear_bytes);
    }

    if (!termite_metal_decode_runtime_graph_alias(runtime, runtime->scratch_buffer)) {
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->scratch_buffer, &snapshot->scratch_bytes);
    }
    termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->host_staging_buffer, &snapshot->scratch_bytes);
    termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->active_frame_host_staging_buffer, &snapshot->scratch_bytes);
    termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->token_buffer, &snapshot->scratch_bytes);
    if (!termite_metal_decode_runtime_graph_alias(runtime, runtime->sample_logits_buffer)) {
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->sample_logits_buffer, &snapshot->scratch_bytes);
    }
    if (!termite_metal_decode_runtime_graph_alias(runtime, runtime->sample_topk_values_buffer)) {
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->sample_topk_values_buffer, &snapshot->scratch_bytes);
    }
    if (!termite_metal_decode_runtime_graph_alias(runtime, runtime->sample_topk_ids_buffer)) {
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->sample_topk_ids_buffer, &snapshot->scratch_bytes);
    }
    for (size_t i = 0; i < 4; ++i) {
        if (!termite_metal_decode_runtime_graph_alias(runtime, runtime->hot_hidden_buffers[i])) {
            termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->hot_hidden_buffers[i], &snapshot->scratch_bytes);
        }
    }
    for (size_t i = 0; i < 5; ++i) {
        if (!termite_metal_decode_runtime_graph_alias(runtime, runtime->hot_intermediate_buffers[i])) {
            termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->hot_intermediate_buffers[i], &snapshot->scratch_bytes);
        }
    }
    for (size_t i = 0; i < TERMITE_METAL_DIRECT_BLOCK_HIDDEN_BUFFER_COUNT; ++i) {
        if (!termite_metal_decode_runtime_graph_alias(runtime, runtime->direct_block_hidden_buffers[i])) {
            termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->direct_block_hidden_buffers[i], &snapshot->scratch_bytes);
        }
    }
    for (size_t i = 0; i < TERMITE_METAL_DIRECT_BLOCK_SHARED_BUFFER_COUNT; ++i) {
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->direct_block_shared_buffers[i], &snapshot->scratch_bytes);
    }
    if (!termite_metal_decode_runtime_graph_alias(runtime, runtime->direct_block_q_buffer)) {
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->direct_block_q_buffer, &snapshot->scratch_bytes);
    }
    for (size_t i = 0; i < 6; ++i) {
        if (!termite_metal_decode_runtime_graph_alias(runtime, runtime->active_layer_projection_buffers[i])) {
            termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->active_layer_projection_buffers[i], &snapshot->scratch_bytes);
        }
    }
    termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->i2s_qinput_buffer, &snapshot->scratch_bytes);
    termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->i2s_scale_buffer, &snapshot->scratch_bytes);
    for (size_t slot = 0; slot < TERMITE_METAL_GRAPH_PLAN_SLOT_CAPACITY; ++slot) {
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->graph_plan_buffers[slot], &snapshot->scratch_bytes);
        if (runtime->graph_plan_buffers[slot] != nil) {
            snapshot->graph_plan_slots += 1;
            snapshot->graph_plan_bytes += (uint64_t)runtime->graph_plan_buffers[slot].length;
        }
    }
    for (size_t slot = 0; slot < TERMITE_METAL_SCRATCH_POOL_CAPACITY; ++slot) {
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->scratch_pool_buffers[slot], &snapshot->scratch_bytes);
        if (runtime->scratch_pool_buffers[slot] != nil) {
            snapshot->scratch_pool_slots += 1;
            snapshot->scratch_pool_bytes += (uint64_t)runtime->scratch_pool_buffers[slot].length;
        }
        if (runtime->scratch_pool_in_use[slot] != 0) snapshot->scratch_pool_in_use_slots += 1;
        if (runtime->scratch_pool_pending_frame_release[slot] != 0) snapshot->scratch_pool_pending_slots += 1;
    }

    if (!termite_metal_decode_runtime_graph_alias(runtime, runtime->attention_span_encoded_key_buffer)) {
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->attention_span_encoded_key_buffer, &snapshot->attention_span_bytes);
    }
    if (!termite_metal_decode_runtime_graph_alias(runtime, runtime->attention_span_v_buffer)) {
        termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->attention_span_v_buffer, &snapshot->attention_span_bytes);
    }
    for (size_t slot = 0; slot < TERMITE_METAL_ATTENTION_SPAN_SLOT_CAPACITY; ++slot) {
        if (!termite_metal_decode_runtime_graph_alias(runtime, runtime->attention_span_encoded_key_buffers[slot])) {
            termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->attention_span_encoded_key_buffers[slot], &snapshot->attention_span_bytes);
        }
        if (!termite_metal_decode_runtime_graph_alias(runtime, runtime->attention_span_v_buffers[slot])) {
            termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->attention_span_v_buffers[slot], &snapshot->attention_span_bytes);
        }
    }

    termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->hidden_state_front, &snapshot->hidden_state_bytes);
    termite_metal_decode_runtime_memory_add_buffer(snapshot, runtime->hidden_state_back, &snapshot->hidden_state_bytes);
    termite_metal_decode_runtime_memory_add_resources(snapshot, runtime->active_frame_retained_resources, &snapshot->frame_retained_bytes);
    termite_metal_decode_runtime_memory_add_resources(snapshot, runtime->submitted_frame_retained_resources, &snapshot->frame_retained_bytes);
    snapshot->graph_plan_active = runtime->graph_plan_active;
    snapshot->graph_plan_count = runtime->graph_plan_count;
    snapshot->graph_plan_allocations = runtime->graph_plan_allocations;
    snapshot->graph_plan_reuses = runtime->graph_plan_reuses;
    snapshot->mps_dense_linear_standalone_calls = runtime->mps_dense_linear_standalone_calls;
    snapshot->mps_dense_linear_active_frame_calls = runtime->mps_dense_linear_active_frame_calls;
    snapshot->mps_dense_linear_standalone_wait_nanos = runtime->mps_dense_linear_standalone_wait_nanos;
    snapshot->mps_dense_linear_standalone_gpu_nanos = runtime->mps_dense_linear_standalone_gpu_nanos;
    snapshot->last_frame_mps_dense_linear_count = runtime->last_frame_mps_dense_linear_count;
    snapshot->deberta_ffn_fused_calls = runtime->deberta_ffn_fused_calls;
    snapshot->deberta_ffn_fused_mps_matmuls = runtime->deberta_ffn_fused_mps_matmuls;
    snapshot->deberta_ffn_fused_fallbacks = runtime->deberta_ffn_fused_fallbacks;
    snapshot->mpsgraph_ffn_calls = runtime->mpsgraph_ffn_calls;
    snapshot->mpsgraph_ffn_fallbacks = runtime->mpsgraph_ffn_fallbacks;
    snapshot->mpsgraph_ffn_compiles = runtime->mpsgraph_ffn_compiles;
    snapshot->mpsgraph_ffn_cache_hits = runtime->mpsgraph_ffn_cache_hits;
    snapshot->compute_encoder_count = runtime->compute_encoder_count;
    snapshot->blit_encoder_count = runtime->blit_encoder_count;
    snapshot->last_frame_compute_encoder_count = runtime->last_frame_compute_encoder_count;
    snapshot->last_frame_blit_encoder_count = runtime->last_frame_blit_encoder_count;
    snapshot->last_frame_planned_compute_scope_count = runtime->last_frame_planned_compute_scope_count;
    snapshot->last_frame_planned_barrier_count = runtime->last_frame_planned_barrier_count;
    snapshot->last_frame_compute_quant_linear_count = runtime->last_frame_compute_source_counts[TERMITE_METAL_COMPUTE_SOURCE_QUANT_LINEAR];
    snapshot->last_frame_compute_quant_qkv_count = runtime->last_frame_compute_source_counts[TERMITE_METAL_COMPUTE_SOURCE_QUANT_QKV];
    snapshot->last_frame_compute_quant_pair_act_count = runtime->last_frame_compute_source_counts[TERMITE_METAL_COMPUTE_SOURCE_QUANT_PAIR_ACT];
    snapshot->last_frame_compute_attention_count = runtime->last_frame_compute_source_counts[TERMITE_METAL_COMPUTE_SOURCE_ATTENTION];
    snapshot->last_frame_compute_rms_norm_count = runtime->last_frame_compute_source_counts[TERMITE_METAL_COMPUTE_SOURCE_RMS_NORM];
    snapshot->last_frame_compute_head_rope_count = runtime->last_frame_compute_source_counts[TERMITE_METAL_COMPUTE_SOURCE_HEAD_ROPE];
