    snapshot->last_frame_compute_region_attention_project_count = runtime->last_frame_compute_region_counts[TERMITE_METAL_COMPUTE_REGION_ATTENTION_PROJECT];
    snapshot->last_frame_compute_region_ffn_norm_count = runtime->last_frame_compute_region_counts[TERMITE_METAL_COMPUTE_REGION_FFN_NORM];
