    snapshot->q8_0_pair_activation_rms_scale_mmv_f16_output = runtime->q8_0_pair_activation_rms_scale_mmv_f16_output;
    snapshot->q8_0_linear_mmv_f16_input = runtime->q8_0_linear_mmv_f16_input;
    memcpy(
