int termite_metal_buffer_slice_last_dim_2d(
    termite_metal_decode_runtime *runtime,
    void *src_handle,
    size_t src_offset,
    size_t rows,
    size_t cols,
    size_t start,
    size_t out_cols,
    void *dst_handle,
    size_t dst_offset
) {
    if (runtime == NULL || runtime->queue == nil || src_handle == NULL || dst_handle == NULL) return -1;
    if (rows == 0 || cols == 0 || out_cols == 0 || start > cols || out_cols > cols - start) return -2;
    if (rows > UINT32_MAX || cols > UINT32_MAX || start > UINT32_MAX || out_cols > UINT32_MAX) return -2;
    @autoreleasepool {
        id<MTLBuffer> src = (__bridge id<MTLBuffer>)src_handle;
        id<MTLBuffer> dst = (__bridge id<MTLBuffer>)dst_handle;
        const size_t elem_size = sizeof(float);
        const size_t row_bytes = out_cols * elem_size;
        const size_t src_required = src_offset + ((rows - 1) * cols + start + out_cols) * elem_size;
        const size_t dst_required = dst_offset + rows * out_cols * elem_size;
        if (src_required > src.length || dst_required > dst.length) return -3;
        if (runtime->slice_last_dim_f32_2d_pipeline != nil) {
            termite_metal_slice_last_dim_f32_2d_params params = {
                .rows = (uint32_t)rows,
                .cols = (uint32_t)cols,
                .start = (uint32_t)start,
                .out_cols = (uint32_t)out_cols,
            };
            const size_t total = rows * out_cols;
            id<MTLComputeCommandEncoder> planned_encoder = runtime->active_planned_compute_encoder;
            if (planned_encoder != nil) {
                if (src_required < src_offset || dst_required < dst_offset) return -3;
                if (termite_metal_decode_runtime_prepare_planned_compute_unary_accesses(
                        runtime,
                        src,
                        src_offset,
                        src_required - src_offset,
                        dst,
                        dst_offset,
                        dst_required - dst_offset,
                        -3) != 0)
                {
                    return -3;
                }
                [planned_encoder setComputePipelineState:runtime->slice_last_dim_f32_2d_pipeline];
                [planned_encoder setBuffer:src offset:src_offset atIndex:0];
                [planned_encoder setBuffer:dst offset:dst_offset atIndex:1];
                [planned_encoder setBytes:&params length:sizeof(params) atIndex:2];
                [planned_encoder dispatchThreads:MTLSizeMake(total, 1, 1)
                           threadsPerThreadgroup:MTLSizeMake(termite_metal_thread_width(runtime->slice_last_dim_f32_2d_pipeline, total), 1, 1)];
                return 0;
            }
            bool frame_owned = true;
            id<MTLCommandBuffer> command_buffer = termite_metal_decode_runtime_command_buffer(runtime, __func__, &frame_owned);
            if (command_buffer == nil) return -4;
            id<MTLComputeCommandEncoder> encoder = termite_metal_tracked_compute_command_encoder_for(command_buffer, TERMITE_METAL_COMPUTE_SOURCE_OTHER);
            if (encoder == nil) return -5;
            [encoder setComputePipelineState:runtime->slice_last_dim_f32_2d_pipeline];
            [encoder setBuffer:src offset:src_offset atIndex:0];
            [encoder setBuffer:dst offset:dst_offset atIndex:1];
            [encoder setBytes:&params length:sizeof(params) atIndex:2];
            [encoder dispatchThreads:MTLSizeMake(total, 1, 1)
               threadsPerThreadgroup:MTLSizeMake(termite_metal_thread_width(runtime->slice_last_dim_f32_2d_pipeline, total), 1, 1)];
            [encoder endEncoding];
            return termite_metal_decode_runtime_finish_command_buffer(command_buffer, frame_owned, -6);
        }
        bool frame_owned = true;
        id<MTLCommandBuffer> command_buffer = termite_metal_decode_runtime_command_buffer(runtime, __func__, &frame_owned);
        if (command_buffer == nil) return -4;
        termite_metal_record_active_frame_blit_source(command_buffer, TERMITE_METAL_BLIT_SOURCE_BUFFER_SLICE);
        if (!frame_owned && termite_metal_trace_frame_blits_enabled()) {
            fprintf(stderr, "metal_frame_blit: kind=slice_last_dim rows=%zu cols=%zu start=%zu out_cols=%zu row_bytes=%zu\n", rows, cols, start, out_cols, row_bytes);
        }
        id<MTLBlitCommandEncoder> blit = termite_metal_tracked_blit_command_encoder(command_buffer);
        if (blit == nil) return -5;
        if ([blit respondsToSelector:@selector(setLabel:)]) {
            blit.label = @"buffer-slice-last-dim-2d";
        }
        for (size_t row = 0; row < rows; ++row) {
            const size_t src_row_offset = src_offset + (row * cols + start) * elem_size;
            const size_t dst_row_offset = dst_offset + row * out_cols * elem_size;
            [blit copyFromBuffer:src sourceOffset:src_row_offset toBuffer:dst destinationOffset:dst_row_offset size:row_bytes];
        }
        [blit endEncoding];
        return termite_metal_decode_runtime_finish_command_buffer(command_buffer, frame_owned, -6);
    }
}

int termite_metal_decode_runtime_reserve_hidden_state(
    termite_metal_decode_runtime *runtime,
    size_t max_prefill_rows,
    size_t hidden_size
) {
    if (runtime == NULL || runtime->device == nil) return -1;
    if (max_prefill_rows == 0 || hidden_size == 0) return -2;
    const size_t required_bytes = max_prefill_rows * hidden_size * sizeof(float);
    @autoreleasepool {
        if (required_bytes > runtime->hidden_state_capacity) {
            id<MTLBuffer> front = [runtime->device newBufferWithLength:required_bytes options:MTLResourceStorageModePrivate];
            if (front == nil) return -3;
            id<MTLBuffer> back = [runtime->device newBufferWithLength:required_bytes options:MTLResourceStorageModePrivate];
            if (back == nil) return -4;
            runtime->hidden_state_front = front;
            runtime->hidden_state_back = back;
            runtime->hidden_state_capacity = required_bytes;
        }
        runtime->hidden_state_max_rows = max_prefill_rows;
        runtime->hidden_state_hidden_size = hidden_size;
        return 0;
    }
}

void *termite_metal_decode_runtime_hidden_state_buffer(
    termite_metal_decode_runtime *runtime,
    int which
) {
    if (runtime == NULL) return NULL;
    id<MTLBuffer> buffer = (which == 0) ? runtime->hidden_state_front : runtime->hidden_state_back;
    if (buffer == nil) return NULL;
    return (__bridge_retained void *)buffer;
}

size_t termite_metal_decode_runtime_hidden_state_capacity(
    termite_metal_decode_runtime *runtime
) {
    if (runtime == NULL) return 0;
    return runtime->hidden_state_capacity;
}

size_t termite_metal_decode_runtime_hidden_state_max_rows(
    termite_metal_decode_runtime *runtime
) {
    if (runtime == NULL) return 0;
    return runtime->hidden_state_max_rows;
}

void *termite_metal_decode_runtime_acquire_scratch(
    termite_metal_decode_runtime *runtime,
    size_t bytes
) {
    if (runtime == NULL || runtime->device == nil || bytes == 0) return NULL;
    @autoreleasepool {
        // Prefer an idle slot that already has enough capacity — no allocation.
        for (size_t slot = 0; slot < TERMITE_METAL_SCRATCH_POOL_CAPACITY; ++slot) {
            if (runtime->scratch_pool_in_use[slot] == 0 &&
                runtime->scratch_pool_pending_frame_release[slot] == 0 &&
                runtime->scratch_pool_buffers[slot] != nil &&
                runtime->scratch_pool_capacities[slot] >= bytes) {
                runtime->scratch_pool_in_use[slot] = 1;
                return (__bridge_retained void *)runtime->scratch_pool_buffers[slot];
            }
        }
        // Fallback: find the first idle slot and (re)allocate it to fit.
        for (size_t slot = 0; slot < TERMITE_METAL_SCRATCH_POOL_CAPACITY; ++slot) {
            if (runtime->scratch_pool_in_use[slot] == 0 && runtime->scratch_pool_pending_frame_release[slot] == 0) {
                id<MTLBuffer> buffer = [runtime->device newBufferWithLength:bytes options:MTLResourceStorageModePrivate];
                if (buffer == nil) return NULL;
                runtime->scratch_pool_buffers[slot] = buffer;
                runtime->scratch_pool_capacities[slot] = bytes;
                runtime->scratch_pool_in_use[slot] = 1;
                return (__bridge_retained void *)buffer;
            }
        }
        // Pool exhausted — caller can fall back to `termite_metal_buffer_alloc`.
        return NULL;
    }
}

void termite_metal_decode_runtime_release_scratch(
    termite_metal_decode_runtime *runtime,
    void *handle
) {
    if (handle == NULL) return;
    // Consume the caller's +1 retain from acquire; the slot's own strong
    // reference in `scratch_pool_buffers[slot]` keeps the buffer alive across
    // frames so the next acquire can reuse the allocation.
    id<MTLBuffer> buffer = (__bridge_transfer id<MTLBuffer>)handle;
    if (runtime == NULL) {
        (void)buffer;
        return;
    }
    for (size_t slot = 0; slot < TERMITE_METAL_SCRATCH_POOL_CAPACITY; ++slot) {
        if (runtime->scratch_pool_buffers[slot] == buffer) {
            if (runtime->active_frame_cb != nil || runtime->submitted_frame_cb != nil) {
                runtime->scratch_pool_pending_frame_release[slot] = 1;
                runtime->scratch_pool_in_use[slot] = 1;
            } else {
                runtime->scratch_pool_pending_frame_release[slot] = 0;
                runtime->scratch_pool_in_use[slot] = 0;
            }
            break;
        }
    }
    (void)buffer;
}

int termite_metal_decode_runtime_prepare_decoder_only_greedy(
    termite_metal_decode_runtime *runtime,
    size_t hidden_size,
    size_t intermediate_size,
    size_t num_layers,
    size_t num_heads,
    size_t num_kv_heads,
    size_t head_dim,
    size_t vocab_size,
    size_t kv_tokens
) {
    if (runtime == NULL) return -1;
    if (hidden_size == 0 || intermediate_size == 0 || num_layers == 0 || num_heads == 0 || num_kv_heads == 0 || head_dim == 0 || vocab_size == 0) return -2;

    const size_t hidden_bytes = hidden_size * sizeof(float);
    const size_t q_bytes = num_heads * head_dim * sizeof(float);
    const size_t kv_bytes = num_kv_heads * head_dim * sizeof(float);
    const size_t attn_bytes = num_heads * head_dim * sizeof(float);
    const size_t mlp_bytes = intermediate_size * sizeof(float) * 2u;
    const size_t layer_scratch = hidden_bytes * 2u + q_bytes + kv_bytes * 2u + attn_bytes + mlp_bytes;
    const size_t kv_span_meta = kv_tokens * sizeof(uint32_t);
    const size_t scratch_bytes = layer_scratch + hidden_bytes + kv_span_meta + 4096u;

    return termite_metal_decode_runtime_reserve(runtime, scratch_bytes, sizeof(uint32_t));
}

static int termite_metal_dispatch(termite_metal_provider *provider, id<MTLComputePipelineState> pipeline, const float *input, size_t rows, size_t in_dim, size_t row_blocks, const uint8_t *weight_raw, size_t weight_bytes, size_t out_dim, float *output) {
    if (provider == NULL || pipeline == nil || input == NULL || weight_raw == NULL || output == NULL) return -1;
    @autoreleasepool {
        const size_t input_bytes = rows * in_dim * sizeof(float);
        const size_t output_bytes = rows * out_dim * sizeof(float);
        id<MTLBuffer> input_buffer = [provider->device newBufferWithBytesNoCopy:(void *)input length:input_bytes options:MTLResourceStorageModeShared deallocator:nil];
        if (input_buffer == nil) input_buffer = [provider->device newBufferWithBytes:input length:input_bytes options:MTLResourceStorageModeShared];
        id<MTLBuffer> weight_buffer = [provider->device newBufferWithBytesNoCopy:(void *)weight_raw length:weight_bytes options:MTLResourceStorageModeShared deallocator:nil];
        if (weight_buffer == nil) weight_buffer = [provider->device newBufferWithBytes:weight_raw length:weight_bytes options:MTLResourceStorageModeShared];
        id<MTLBuffer> output_buffer = [provider->device newBufferWithBytesNoCopy:output length:output_bytes options:MTLResourceStorageModeShared deallocator:nil];
        if (output_buffer == nil) output_buffer = [provider->device newBufferWithBytes:output length:output_bytes options:MTLResourceStorageModeShared];
        if (input_buffer == nil || weight_buffer == nil || output_buffer == nil) return -3;
        termite_metal_linear_params params = { .rows = (uint32_t)rows, .in_dim = (uint32_t)in_dim, .out_dim = (uint32_t)out_dim, .row_blocks = (uint32_t)row_blocks };
        id<MTLBuffer> params_buffer = [provider->device newBufferWithBytes:&params length:sizeof(params) options:MTLResourceStorageModeShared];
        if (params_buffer == nil) return -4;
        id<MTLCommandBuffer> command_buffer = termite_metal_new_command_buffer(provider->queue, __func__);
        if (command_buffer == nil) return -5;
        id<MTLComputeCommandEncoder> encoder = termite_metal_tracked_compute_command_encoder(command_buffer);
        if (encoder == nil) return -6;
        [encoder setComputePipelineState:pipeline];
        [encoder setBuffer:input_buffer offset:0 atIndex:0];
        [encoder setBuffer:weight_buffer offset:0 atIndex:1];
        [encoder setBuffer:output_buffer offset:0 atIndex:2];
        [encoder setBuffer:params_buffer offset:0 atIndex:3];
        const NSUInteger total = rows * out_dim;
        MTLSize grid_size = MTLSizeMake(total, 1, 1);
        NSUInteger thread_width = pipeline.maxTotalThreadsPerThreadgroup;
        if (thread_width == 0) thread_width = 64;
        if (thread_width > total && total > 0) thread_width = total;
        MTLSize group_size = MTLSizeMake(thread_width, 1, 1);
        [encoder dispatchThreads:grid_size threadsPerThreadgroup:group_size];
        [encoder endEncoding];
        [command_buffer commit];
        [command_buffer waitUntilCompleted];
        return command_buffer.status == MTLCommandBufferStatusCompleted ? 0 : -7;
    }
}

static int termite_metal_dispatch_pair(termite_metal_provider *provider, id<MTLComputePipelineState> pipeline, const float *input, size_t rows, size_t in_dim, size_t row_blocks, const uint8_t *weight_a_raw, size_t weight_a_bytes, const uint8_t *weight_b_raw, size_t weight_b_bytes, size_t out_dim, float *output_a, float *output_b) {
    if (provider == NULL || pipeline == nil || input == NULL || weight_a_raw == NULL || weight_b_raw == NULL || output_a == NULL || output_b == NULL) return -1;
    @autoreleasepool {
